INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 61, 'kids', 1, 'Where did David ask God to lead him when his heart was overwhelmed?', 'To a high rock', 'To a river', 'To a cave', 'To a mountain', 'a', 'David prayed, "Lead me to the rock that is higher than I" (Psalm 61:2).'),
('Psalms', 61, 'kids', 2, 'What did David want to do in God''s tabernacle forever?', 'Sing songs', 'Abide there', 'Offer sacrifices', 'Read scrolls', 'b', 'David said, "I will abide in thy tabernacle for ever" (Psalm 61:4).'),
('Psalms', 61, 'kids', 3, 'What did David say he would do daily in the psalm?', 'Pray alone', 'Perform his vows', 'Fast and weep', 'Sleep in peace', 'b', 'David said, "So will I sing praise unto thy name for ever, that I may daily perform my vows" (Psalm 61:8).'),
('Psalms', 61, 'teens', 1, 'From where did David cry unto God in Psalm 61?', 'From the temple', 'From the end of the earth', 'From the wilderness', 'From the city of David', 'b', 'David cried, "From the end of the earth will I cry unto thee, when my heart is overwhelmed" (Psalm 61:2).'),
('Psalms', 61, 'teens', 2, 'What two things did David say God had been to him?', 'A refuge and a tower', 'A shield and a sword', 'A lamp and a path', 'A rock and a river', 'a', 'David said God had been "a shelter for me, and a strong tower from the enemy" (Psalm 61:3).'),
('Psalms', 61, 'teens', 3, 'What did David say he trusted in regarding the king in Psalm 61?', 'That the king would conquer all enemies', 'That God would prolong the king''s life', 'That the king would build a great temple', 'That the king would defeat David''s enemies', 'b', 'David prayed that God would prolong the king''s life and that "his years as many generations" (Psalm 61:6).'),
('Psalms', 61, 'teens', 4, 'What two things did David ask to be sent to preserve the king?', 'Angels and fire', 'Mercy and truth', 'Wisdom and strength', 'Rain and sunshine', 'b', 'David prayed, "O prepare mercy and truth, which may preserve him" (Psalm 61:7).'),
('Psalms', 61, 'teens', 5, 'What musical term heads Psalm 61, indicating it was to be used with what instrument?', 'A harp', 'A neginah (stringed instrument)', 'A flute', 'Cymbals', 'b', 'Psalm 61 is headed "To the chief Musician upon Neginah" — a stringed instrument (Psalm 61 superscription).'),
('Psalms', 61, 'adults', 1, 'What Hebrew word rendered "overwhelmed" in Psalm 61:2 conveys the sense of fainting or being covered over?', 'Atap', 'Ataph', 'Nephesh', 'Shachah', 'b', 'The word "ataph" (overwhelmed) in Psalm 61:2 means to be faint, covered, or feeble — David feels utterly spent.'),
('Psalms', 61, 'adults', 2, 'What does David''s phrase "the rock that is higher than I" theologially convey?', 'God is taller than mountains', 'God''s salvation is beyond David''s own ability to reach it', 'David wanted to climb a literal rock', 'God''s throne is above all creation', 'b', 'The phrase "lead me to the rock that is higher than I" (Psalm 61:2) expresses that God''s help transcends human ability.'),
('Psalms', 61, 'adults', 3, 'What does David''s desire to "abide in thy tabernacle for ever" (Psalm 61:4) reflect about his deepest longing?', 'A wish for priestly office', 'An unbroken dwelling in God''s presence as the highest good', 'A desire to live in Jerusalem', 'A vow to never leave the city', 'b', 'David''s longing to abide in God''s tabernacle forever (Psalm 61:4) reflects that God''s presence is his supreme joy.'),
('Psalms', 61, 'adults', 4, 'The phrase "under the shadow of thy wings" in Psalm 61:4 is a recurring OT image. What does it primarily symbolize?', 'God''s power in battle', 'Divine protection and sheltering care', 'The wings of cherubim on the ark', 'The eagle imagery of Deuteronomy', 'b', 'The shadow of God''s wings (Psalm 61:4) is a tender image of divine shelter and protection, used also in Psalm 17:8 and 91:4.'),
('Psalms', 61, 'adults', 5, 'How does Psalm 61:6-7 function as a Messianic or royal prayer?', 'It prophesies the birth of a king in Bethlehem', 'It intercedes for the ideal king whose reign is perpetual, ultimately fulfilled in Christ', 'It describes David''s own coronation', 'It predicts the return of Solomon', 'b', 'The prayer for the king''s endless life and mercy (Psalm 61:6-7) points beyond any earthly king to the eternal reign of Christ.'),
('Psalms', 61, 'adults', 6, 'What vow does David make at the close of Psalm 61?', 'To offer a thousand burnt offerings', 'To daily perform his vows and sing praise to God''s name forever', 'To never leave Jerusalem', 'To build a house for God', 'b', 'David concludes, "So will I sing praise unto thy name for ever, that I may daily perform my vows" (Psalm 61:8).'),
('Psalms', 61, 'adults', 7, 'What attribute of God is emphasized by the pairing of "mercy and truth" in Psalm 61:7?', 'God''s power and holiness', 'God''s covenant faithfulness and reliable love', 'God''s omniscience and justice', 'God''s creativity and wisdom', 'b', 'Mercy (hesed — covenant love) and truth (emet — faithfulness) together describe God''s reliable covenant character (Psalm 61:7).'),
('Psalms', 61, 'adults', 8, 'What does the heading "upon Neginah" suggest about the original liturgical use of Psalm 61?', 'It was sung a cappella', 'It was performed with a single stringed instrument, likely the lute or lyre', 'It was a whispered prayer', 'It was chanted by a choir', 'b', 'Neginah refers to a stringed instrument; the psalm was composed for musical accompaniment in Israel''s worship (Psalm 61 superscription).');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 62, 'kids', 1, 'What did David say his soul did toward God in Psalm 62?', 'It sang loudly', 'It waited silently', 'It ran quickly', 'It cried out', 'b', 'David said, "My soul waiteth upon God: from him cometh my salvation" (Psalm 62:1).'),
('Psalms', 62, 'kids', 2, 'What did David call God in Psalm 62 — his rock and his what?', 'His sword', 'His salvation', 'His king', 'His shepherd', 'b', 'David called God "my rock and my salvation" (Psalm 62:2).'),
('Psalms', 62, 'kids', 3, 'Who does Psalm 62 say power belongs to?', 'The king', 'God', 'The army', 'The angels', 'b', 'David declared, "Power belongeth unto God" (Psalm 62:11).'),
('Psalms', 62, 'teens', 1, 'How does David describe trusting in men of low and high degree in Psalm 62?', 'They are trustworthy if chosen by God', 'They are altogether vanity and lighter than a breath', 'They are good helpers in times of need', 'They can be trusted if they are righteous', 'b', 'David wrote that men of low and high degree are "altogether vanity... lighter than vanity" (Psalm 62:9).'),
('Psalms', 62, 'teens', 2, 'What did David say not to trust in, specifically mentioning robbery?', 'Weapons and armies', 'Oppression and robbery — and riches that increase', 'The wisdom of counsellors', 'The strength of kings', 'b', 'David warned, "Trust not in oppression, and become not vain in robbery: if riches increase, set not your heart upon them" (Psalm 62:10).'),
('Psalms', 62, 'teens', 3, 'How many times does the phrase "only" (or "only he") appear as a refrain in Psalm 62, emphasizing exclusive trust in God?', 'Once', 'Three times', 'Five times', 'Seven times', 'b', 'The word "only" (Hebrew: ak) appears as a refrain in Psalm 62:1, 2, 4, 5, 6 — about three key refrains stressing sole dependence on God.'),
('Psalms', 62, 'teens', 4, 'To what does David compare his enemies'' assault on him in Psalm 62:3?', 'A flood sweeping him away', 'A leaning wall and a tottering fence', 'A lion ready to devour', 'A fire burning around him', 'b', 'David asks, "How long will ye imagine mischief against a man? ye shall be slain all of you: as a bowing wall shall ye be, and as a tottering fence" (Psalm 62:3).'),
('Psalms', 62, 'teens', 5, 'What two things does David say God renders to every man in Psalm 62:12?', 'Life and death', 'Mercy and salvation according to his work', 'Wisdom and power', 'Riches and honour', 'b', 'David wrote, "Also unto thee, O Lord, belongeth mercy: for thou renderest to every man according to his work" (Psalm 62:12).'),
('Psalms', 62, 'adults', 1, 'What Hebrew term is translated "truly" or "only" (ak) and serves as the structural refrain of Psalm 62, appearing in verses 1, 2, 4, 5, and 6?', 'Selah', 'Ak', 'Higgaion', 'Maskil', 'b', 'The particle ak (only/surely/truly) anchors each stanza of Psalm 62, directing the reader''s sole trust to God.'),
('Psalms', 62, 'adults', 2, 'What does "my soul waiteth upon God" (Psalm 62:1) — the Hebrew "dummiyyah" — literally mean?', 'Active petition', 'Silent rest or stillness before God', 'Loud praise', 'Patient endurance in suffering', 'b', 'Dummiyyah means silence or stillness; "my soul waiteth in silence upon God" (Psalm 62:1) speaks of calm, wordless trust.'),
('Psalms', 62, 'adults', 3, 'What does David''s metaphor of God as a "rock" and "fortress" (Psalm 62:2, 6-7) emphasize?', 'God''s physical size', 'God''s immovable stability and protection in contrast to flimsy human support', 'The temple''s stone construction', 'The mountains of Israel', 'b', 'The rock and fortress imagery (Psalm 62:2, 6-7) contrasts God''s absolute stability with the vanity of human help.'),
('Psalms', 62, 'adults', 4, 'How does Psalm 62:9 use a balance/scale image to make its point about humanity?', 'It says the righteous outweigh the wicked', 'It says all men laid in a balance are lighter than vanity', 'It says God weighs human hearts', 'It says riches weigh down the soul', 'b', 'Psalm 62:9 says men of low and high degree "laid in the balance...are altogether lighter than vanity."'),
('Psalms', 62, 'adults', 5, 'What do the two attributes named in Psalm 62:11-12 — "power" and "mercy" — reveal about God''s character?', 'That God is both distant and near', 'That God''s omnipotence is exercised through covenant love, not arbitrary force', 'That God rewards the powerful with mercy', 'That power and mercy compete in God', 'b', 'Psalm 62:11-12 pairs God''s power with mercy, showing his might is always governed by his covenant love.'),
('Psalms', 62, 'adults', 6, 'What does "God hath spoken once; twice have I heard this" (Psalm 62:11) illustrate as a literary device?', 'God spoke audibly twice to David', 'A numerical graduation device (x, x+1) emphasizing the certainty of what was said', 'David had two prophetic dreams', 'God repeats himself for emphasis only', 'b', 'The "once...twice" formula (Psalm 62:11) is a Hebrew literary device (cf. Proverbs 6:16) stressing the absolute certainty of the truth.'),
('Psalms', 62, 'adults', 7, 'What does David mean by "pour out your heart before him" (Psalm 62:8)?', 'Make a blood offering', 'Express every burden, emotion, and need openly to God in prayer', 'Weep publicly in the temple', 'Confess sins to the priest', 'b', 'Pouring out the heart before God (Psalm 62:8) is an image of complete, uninhibited self-disclosure in prayer (cf. 1 Samuel 1:15).'),
('Psalms', 62, 'adults', 8, 'How does Jeduthun''s name in the heading of Psalm 62 connect to Israel''s worship structure?', 'Jeduthun was a king of Israel', 'Jeduthun was one of David''s three chief musicians appointed for temple worship', 'Jeduthun was a scribe who collected psalms', 'Jeduthun was a prophet who interpreted psalms', 'b', 'Jeduthun (1 Chronicles 16:41-42) was one of David''s three chief worship leaders; Psalm 62 was committed to his care for Israel''s liturgy.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 63, 'kids', 1, 'Where was David when he wrote Psalm 63?', 'In a palace', 'In the wilderness of Judah', 'By a river', 'In a cave by the sea', 'b', 'The superscription reads, "A Psalm of David, when he was in the wilderness of Judah" (Psalm 63 superscription).'),
('Psalms', 63, 'kids', 2, 'What did David say his soul did for God like a thirsty body?', 'Thirsted for him', 'Slept peacefully', 'Danced for joy', 'Sang all night', 'a', 'David said, "My soul thirsteth for thee, my flesh longeth for thee in a dry and thirsty land" (Psalm 63:1).'),
('Psalms', 63, 'kids', 3, 'What did David say he would do while lying on his bed at night?', 'Count the stars', 'Remember God and meditate on him', 'Pray for his enemies', 'Sing out loud', 'b', 'David said, "When I remember thee upon my bed, and meditate on thee in the night watches" (Psalm 63:6).'),
('Psalms', 63, 'teens', 1, 'What does David say is better than life in Psalm 63:3?', 'God''s presence in the temple', 'God''s lovingkindness', 'A righteous kingdom', 'The joy of praise', 'b', 'David declared, "Because thy lovingkindness is better than life, my lips shall praise thee" (Psalm 63:3).'),
('Psalms', 63, 'teens', 2, 'How does David describe his praise — what posture does he mention?', 'Bowing low to the ground', 'Lifting up his hands in God''s name', 'Dancing in a circle', 'Kneeling at the altar', 'b', 'David wrote, "Thus will I bless thee while I live: I will lift up my hands in thy name" (Psalm 63:4).'),
('Psalms', 63, 'teens', 3, 'What image does David use to describe his soul''s satisfaction in God?', 'A spring of living water', 'Marrow and fatness', 'Honey from the comb', 'Bread from heaven', 'b', 'David said, "My soul shall be satisfied as with marrow and fatness; and my mouth shall praise thee with joyful lips" (Psalm 63:5).'),
('Psalms', 63, 'teens', 4, 'What does David say about those who seek his soul to destroy it?', 'They will be forgiven', 'They will go into the lower parts of the earth and fall by the sword', 'They will be scattered like chaff', 'They will be turned back in shame', 'b', 'David said his enemies "shall go into the lower parts of the earth... they shall fall by the sword" (Psalm 63:9-10).'),
('Psalms', 63, 'teens', 5, 'What does David call himself in Psalm 63:1 — using what divine title for God?', 'My Shepherd', 'O God, thou art my God', 'My King and my God', 'My Rock and Fortress', 'b', 'David opens with "O God, thou art my God; early will I seek thee" (Psalm 63:1).'),
('Psalms', 63, 'adults', 1, 'What does the Hebrew word "shachar" (translated "early will I seek thee" in Psalm 63:1) literally convey?', 'Seeking at noon', 'Diligently seeking at dawn, implying earnest and urgent pursuit', 'Searching in darkness', 'Seeking with the whole congregation', 'b', 'Shachar means to seek at dawn or diligently; "early will I seek thee" (Psalm 63:1) conveys urgent, first-priority devotion.'),
('Psalms', 63, 'adults', 2, 'What is the theological weight of David''s assertion that lovingkindness is "better than life" (Psalm 63:3)?', 'David preferred death to life without God', 'God''s covenant love (hesed) surpasses physical existence as the highest good', 'Life in the wilderness was miserable', 'David was suicidal and longed for heaven', 'b', 'To declare lovingkindness better than life (Psalm 63:3) places God''s hesed above the most precious earthly possession — life itself.'),
('Psalms', 63, 'adults', 3, 'The phrase "in the shadow of thy wings" (Psalm 63:7) echoes what broader OT theological theme?', 'The wings of seraphim in Isaiah', 'God''s maternal sheltering of his people (cf. Deuteronomy 32:11; Ruth 2:12; Psalm 91:4)', 'The eagle as a symbol of Israel''s military power', 'The wings of the cherubim on the mercy seat', 'b', 'The shadow of God''s wings (Psalm 63:7) is a recurring image of tender divine protection, rooted in Deuteronomy 32:11 and Boaz''s blessing in Ruth 2:12.'),
('Psalms', 63, 'adults', 4, 'How does David''s night meditation (Psalm 63:6) reflect ancient Near Eastern spiritual practice?', 'Night was considered the time of evil spirits', 'The night watches were times of prayer and contemplation in Israel''s worship calendar', 'David could not sleep due to enemies', 'Night was set aside for fasting not prayer', 'b', 'Night watches were established periods of prayer and guard (cf. Psalm 119:148); David''s night meditation (Psalm 63:6) shows his constant communion with God.'),
('Psalms', 63, 'adults', 5, 'What does David''s description of his soul clinging to God — "my soul followeth hard after thee" (Psalm 63:8) — convey in Hebrew (dabaq)?', 'A passive waiting for God', 'An intense, tenacious cleaving to God like a marriage bond (cf. Genesis 2:24)', 'A desperate search in confusion', 'A ritual act of sacrifice', 'b', 'Dabaq (cleave/cling) in Psalm 63:8 is the same word used in Genesis 2:24 for a husband cleaving to his wife — total covenant attachment.'),
('Psalms', 63, 'adults', 6, 'What does the fate of David''s enemies — their mouths stopped (Psalm 63:11) — contrast with in the psalm''s structure?', 'The silence of the wilderness', 'David''s own lips praising and swearing by God, contrasted with lying mouths stopped', 'The silence of night meditation', 'The king''s wordless reign', 'b', 'The stopped mouths of liars (Psalm 63:11) contrast pointedly with David''s praising lips (Psalm 63:3, 5) — praise silences wickedness.'),
('Psalms', 63, 'adults', 7, 'What military or royal context likely underlies Psalm 63''s composition in the wilderness?', 'David''s flight from Saul in the Judean desert', 'David''s flight from Absalom''s rebellion when he crossed the wilderness east of Jerusalem', 'David''s forty years of wandering', 'David''s campaign against the Philistines', 'b', 'The superscription and David''s reference to "the king" (Psalm 63:11) suggest this was written during Absalom''s rebellion, when David fled across the Judean wilderness.'),
('Psalms', 63, 'adults', 8, 'Psalm 63:3 has been called one of the boldest statements in the Psalter. What makes it theologically radical?', 'It claims God is visible in the wilderness', 'It elevates divine love above physical life, reversing the natural hierarchy of values', 'It denies the value of temple worship', 'It asserts that martyrdom is the highest good', 'b', 'By placing lovingkindness above life itself (Psalm 63:3), David subordinates the most prized earthly good to God''s covenantal love — a radical reordering of values.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 64, 'kids', 1, 'What did David ask God to preserve him from in Psalm 64?', 'Rain and storms', 'Fear of the enemy', 'Wild animals', 'Disease and sickness', 'b', 'David prayed, "Preserve my life from fear of the enemy" (Psalm 64:1).'),
('Psalms', 64, 'kids', 2, 'What did David say God would shoot at the wicked?', 'A stone', 'An arrow', 'A bolt of lightning', 'A spear', 'b', 'David declared, "God shall shoot at them with an arrow; suddenly shall they be wounded" (Psalm 64:7).'),
('Psalms', 64, 'kids', 3, 'What would all men do when they saw God''s judgment on the wicked?', 'They would be afraid and declare God''s work', 'They would run away', 'They would laugh', 'They would weep', 'a', 'David said all men "shall fear, and shall declare the work of God; for they shall wisely consider of his doing" (Psalm 64:9).'),
('Psalms', 64, 'teens', 1, 'How does David describe the secret plotting of the wicked in Psalm 64?', 'They plot openly in the city gates', 'They shoot in secret at the blameless man with bitter words as arrows', 'They gather armies against the righteous', 'They bribe judges against the innocent', 'b', 'David said they "shoot in secret at the perfect: suddenly do they shoot at him, and fear not" (Psalm 64:4).'),
('Psalms', 64, 'teens', 2, 'What do the wicked say about their evil plots in Psalm 64:5?', 'God will judge us', 'Who shall see them?', 'We will not be caught', 'No man can stop us', 'b', 'The wicked encouraged themselves and said, "Who shall see them?" (Psalm 64:5).'),
('Psalms', 64, 'teens', 3, 'What body part of the wicked does David say will cause their downfall?', 'Their hands', 'Their tongue', 'Their feet', 'Their eyes', 'b', 'David said, "So they shall make their own tongue to fall upon themselves" (Psalm 64:8).'),
('Psalms', 64, 'teens', 4, 'What does David say the righteous will do in response to God''s judgment in Psalm 64:10?', 'They will rejoice in the LORD and trust in him', 'They will weep for the wicked', 'They will build altars of thanksgiving', 'They will tell all nations', 'a', 'David wrote, "The righteous shall be glad in the LORD, and shall trust in him; and all the upright in heart shall glory" (Psalm 64:10).'),
('Psalms', 64, 'teens', 5, 'What does David compare the enemy''s sharp and bitter words to in Psalm 64:3?', 'A sharp sword and bitter poison', 'Their tongue like a sword and their words like arrows', 'A bitter root and a sharp thorn', 'A whip and a spear', 'b', 'David said the enemies "whet their tongue like a sword, and bend their bows to shoot their arrows, even bitter words" (Psalm 64:3).'),
('Psalms', 64, 'adults', 1, 'What literary device dominates Psalm 64, and how does it create a reversal between the wicked and the righteous?', 'Chiasm — the structure mirrors itself perfectly', 'Poetic justice — the weapons (arrows/words) the wicked use against David are turned against them by God', 'Acrostic — each verse begins with a Hebrew letter', 'Anaphora — the same opening phrase repeats', 'b', 'The poetic justice of Psalm 64 is that God shoots the wicked with an arrow (64:7), reversing their secret shooting of arrows (bitter words) at the righteous (64:3-4).'),
('Psalms', 64, 'adults', 2, 'What does David''s request to be hidden from the "secret counsel of the wicked" (Psalm 64:2) imply about the threat he faces?', 'Open warfare by known enemies', 'An organized conspiracy of hidden enemies plotting his destruction', 'A foreign invasion', 'A legal dispute before judges', 'b', 'The "secret counsel" and "insurrection of workers of iniquity" (Psalm 64:2) describe a covert conspiracy — likely David''s political enemies.'),
('Psalms', 64, 'adults', 3, 'What is the theological principle illustrated when "their own tongue" causes the wicked to fall (Psalm 64:8)?', 'Sin is always found out by witnesses', 'God uses the very instruments of wickedness as instruments of judgment — self-defeating sin', 'Speech is the most powerful human weapon', 'God punishes the wicked by silencing them', 'b', 'When their own tongue falls upon themselves (Psalm 64:8), the psalm illustrates how sin carries within itself the seeds of its own destruction.'),
('Psalms', 64, 'adults', 4, 'What does the phrase "they commune of laying snares privily" (Psalm 64:5) reveal about the psychology of the wicked?', 'They are cowards who fear open confrontation', 'They encourage one another in secret scheming, mistakenly believing they are hidden from God', 'They work alone and do not collaborate', 'They are ignorant of moral law', 'b', 'Psalm 64:5 exposes the self-deception of the wicked: they commune secretly and ask "who shall see them?" — forgetting God''s omniscience.'),
('Psalms', 64, 'adults', 5, 'What does "they search out iniquities; they accomplish a diligent search" (Psalm 64:6) emphasize?', 'The wicked are thorough investigators', 'The wicked apply painstaking effort and ingenuity to sin — wickedness is their industry', 'God searches out the iniquities of the wicked', 'The righteous investigate wrongdoing', 'b', 'Psalm 64:6 ironically credits the wicked with great diligence — "they accomplish a diligent search" — showing that sin is a deliberate, effortful enterprise.'),
('Psalms', 64, 'adults', 6, 'How does "suddenly shall they be wounded" (Psalm 64:7) contrast with the plotting tempo earlier in the psalm?', 'It shows God is slow to anger', 'The wicked''s careful, prolonged scheming is answered by God''s instantaneous decisive judgment', 'The wicked wound suddenly so God wounds slowly', 'It shows judgment comes in stages', 'b', 'The wicked plot carefully and patiently (Psalm 64:2-6), but God''s arrow strikes suddenly (Psalm 64:7) — divine judgment comes without warning at the appointed moment.'),
('Psalms', 64, 'adults', 7, 'What is the communal effect described in Psalm 64:9 when all men see God''s judgment?', 'National mourning for the wicked', 'A universal fear of God and declaration of his works — a witness to the nations', 'A political revolution', 'A revival only among the righteous', 'b', 'When all men fear and declare God''s work (Psalm 64:9), God''s judgment on the wicked becomes a universal testimony to his power and justice.'),
('Psalms', 64, 'adults', 8, 'What does Psalm 64''s movement from personal lament to universal praise (verse 10) model for believers?', 'That prayers are always answered quickly', 'That individual trust in God''s justice leads to corporate rejoicing — personal faith has communal dimensions', 'That the righteous must wait passively', 'That praise replaces the need for prayer', 'b', 'Psalm 64 moves from David''s personal plea (64:1-2) to universal praise (64:9-10), modeling how faith in God''s justice becomes shared worship.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 65, 'kids', 1, 'What did the psalmist say God crowns the year with in Psalm 65?', 'Rain and floods', 'His goodness', 'Gold and silver', 'Flowers and fruit', 'b', 'The psalmist declared, "Thou crownest the year with thy goodness" (Psalm 65:11).'),
('Psalms', 65, 'kids', 2, 'Where does God dwell and receive praise according to Psalm 65:1?', 'In the wilderness', 'In Zion', 'In the heavens', 'In the sea', 'b', 'The psalmist says, "Praise waiteth for thee, O God, in Sion" (Psalm 65:1).'),
('Psalms', 65, 'kids', 3, 'What did God do to the seas and waves to show his power in Psalm 65?', 'He dried them up', 'He stilled the noise of them', 'He turned them to rivers', 'He raised them to the mountains', 'b', 'The psalmist said God "stilleth the noise of the seas, the noise of their waves" (Psalm 65:7).'),
('Psalms', 65, 'teens', 1, 'What does Psalm 65:2 say that allows all flesh to come to God?', 'His great power', 'He hears prayer', 'His righteousness', 'His mercy alone', 'b', 'The psalmist said, "O thou that hearest prayer, unto thee shall all flesh come" (Psalm 65:2).'),
('Psalms', 65, 'teens', 2, 'What does God do with the transgressions of his people according to Psalm 65:3?', 'He records them all', 'He purges them away', 'He punishes them severely', 'He remembers them no more', 'b', 'The psalmist wrote, "As for our transgressions, thou shalt purge them away" (Psalm 65:3).'),
('Psalms', 65, 'teens', 3, 'What blessing is given to the one whom God chooses and causes to approach him in Psalm 65:4?', 'Long life and many children', 'Satisfaction with the goodness of God''s house and holy temple', 'Wealth and honour', 'Victory over all enemies', 'b', 'The psalmist wrote, "Blessed is the man whom thou choosest... that he may dwell in thy courts: we shall be satisfied with the goodness of thy house" (Psalm 65:4).'),
('Psalms', 65, 'teens', 4, 'What does Psalm 65 say God does to establish the mountains, showing his great power?', 'He speaks and they appear', 'He is girded with strength and sets fast the mountains', 'He lifts them from the sea', 'He causes them to tremble and bow', 'b', 'The psalmist declared, "Which by his strength setteth fast the mountains; being girded with power" (Psalm 65:6).'),
('Psalms', 65, 'teens', 5, 'How does Psalm 65 describe the tracks of God''s chariot — what drops from them?', 'Manna and dew', 'Fatness', 'Fire and lightning', 'Rain and grain', 'b', 'The psalmist wrote, "Thy paths drop fatness" (Psalm 65:11), describing God''s providential abundance.'),
('Psalms', 65, 'adults', 1, 'What does "praise waiteth for thee" (Psalm 65:1) mean in the Hebrew, where the verb is related to "silence" (dumiyyah)?', 'Praise is offered in loud song', 'Praise is quietly expectant — a still, reverent waiting before God that is itself a form of worship', 'Praise has been postponed until later', 'Praise is offered only by the priests', 'b', 'The Hebrew dumiyyah suggests silent, expectant praise (Psalm 65:1) — adoration that is calm and awestruck before God''s greatness.'),
('Psalms', 65, 'adults', 2, 'What is the theological significance of "unto thee shall all flesh come" (Psalm 65:2) in the context of this psalm?', 'It predicts the physical resurrection of all people', 'It indicates that God''s hearing of prayer is universally available — no nation is excluded from approaching him', 'It refers only to Israel''s pilgrimage feasts', 'It means all flesh will be judged', 'b', 'The universal scope of "all flesh" (Psalm 65:2) anticipates the Gentile inclusion in the NT — all peoples may approach God through prayer.'),
('Psalms', 65, 'adults', 3, 'How does Psalm 65:3 balance human sinfulness with divine grace?', 'It denies that the people have sinned', 'It acknowledges that iniquities prevail against us, yet God purges transgressions — grace overwhelms sin', 'It teaches that sin is unavoidable and unpunishable', 'It promises that obedient people will never sin', 'b', 'Psalm 65:3 is honest: "iniquities prevail against me," yet God purges them — a frank acknowledgment of human sin met by divine atoning grace.'),
('Psalms', 65, 'adults', 4, 'What does "thou that art the confidence of all the ends of the earth, and of them that are afar off upon the sea" (Psalm 65:5) reveal about the scope of God''s salvation?', 'God''s power is limited to Israel and its borders', 'God is the hope and security of all nations and peoples everywhere — a universalist missional vision', 'The sea represents chaos that God must restrain', 'The ends of the earth are unreachable by prayer', 'b', 'Psalm 65:5 declares God is the confidence of all earth''s ends — a remarkable missional statement that anticipates the gospel reaching every nation.'),
('Psalms', 65, 'adults', 5, 'What does the agricultural imagery of Psalm 65:9-13 (watering the earth, softening it, blessing the grain, crowning the year) theologically affirm?', 'Israel must perform rain rituals to ensure harvest', 'God is the sovereign provider of all natural blessing — creation itself is sustained by his personal care', 'The harvest is a reward for Israel''s obedience only', 'Nature operates independently of God', 'b', 'The rich agricultural imagery of Psalm 65:9-13 affirms that God personally visits and waters the earth — all creation depends on his providential care.'),
('Psalms', 65, 'adults', 6, 'What does "the river of God, which is full of water" (Psalm 65:9) represent in the context of this psalm?', 'The literal Jordan River', 'The heavenly supply of rain — God''s provision channel for the earth''s fertility', 'A river in the garden of Eden', 'The waters above the firmament', 'b', 'The river of God full of water (Psalm 65:9) is a poetic image of God''s heavenly reservoir of rain that he uses to water and bless the earth.'),
('Psalms', 65, 'adults', 7, 'How does Psalm 65 move structurally from the personal/communal to the cosmic?', 'It begins with creation and ends with personal prayer', 'It moves from personal forgiveness and temple access (65:1-4) through God''s cosmic power (65:5-8) to universal agricultural blessing (65:9-13)', 'It moves from farming to temple worship', 'The structure is random and does not progress', 'b', 'Psalm 65 is structured in three movements: personal salvation (65:1-4), cosmic power (65:5-8), and providential provision in nature (65:9-13).'),
('Psalms', 65, 'adults', 8, 'What does the psalmist mean that the valleys "shout for joy, they also sing" (Psalm 65:13)?', 'Literally, the grain fields make audible sounds', 'Nature itself joins creation''s praise — all of creation is personified as a worshipping community', 'The people in the valleys sing harvest songs', 'Angels sing in the valleys', 'b', 'The singing valleys (Psalm 65:13) personify creation as a worshipping community, anticipating Romans 8:19-22 where creation waits for redemption.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 66, 'kids', 1, 'What does Psalm 66 tell all the earth to make unto God?', 'A large offering', 'A joyful noise', 'A great feast', 'A long prayer', 'b', 'The psalmist declared, "Make a joyful noise unto God, all ye lands" (Psalm 66:1).'),
('Psalms', 66, 'kids', 2, 'What did God do to the sea that the people walked through on dry ground?', 'He parted it', 'He turned it into dry land', 'He froze it solid', 'He drained it away', 'b', 'The psalmist recalled, "He turned the sea into dry land: they went through the flood on foot" (Psalm 66:6).'),
('Psalms', 66, 'kids', 3, 'What did the psalmist say God had not done — proving he heard prayer?', 'Removed his blessings', 'Turned away from him or withheld his mercy', 'Sent enemies against him', 'Forgotten his name', 'b', 'The psalmist said God had "not turned away my prayer, nor his mercy from me" (Psalm 66:20).'),
('Psalms', 66, 'teens', 1, 'What does the psalmist invite people to do in Psalm 66:5?', 'Enter the temple and worship', 'Come and see the works of God', 'Fast and pray for Israel', 'Offer their firstfruits to God', 'b', 'The psalmist called, "Come and see the works of God: he is terrible in his doing toward the children of men" (Psalm 66:5).'),
('Psalms', 66, 'teens', 2, 'What two extreme experiences does the psalmist say God brought his people through in Psalm 66:12?', 'Famine and plenty, war and peace', 'Fire and water, then into a wealthy place', 'The desert and the sea, the valley and the mountain', 'Captivity and freedom, hunger and feasting', 'b', 'The psalmist declared, "Thou hast caused men to ride over our heads; we went through fire and through water: but thou broughtest us out into a wealthy place" (Psalm 66:12).'),
('Psalms', 66, 'teens', 3, 'What specific offering does the psalmist vow to bring to God''s house in Psalm 66:13-15?', 'Grain and wine', 'Burnt offerings, rams, bullocks, and goats', 'Silver and gold', 'Firstfruits and tithes', 'b', 'The psalmist vowed to bring "burnt offerings... bullocks, with rams; I will offer bullocks with goats" (Psalm 66:13-15).'),
('Psalms', 66, 'teens', 4, 'What condition does the psalmist say would prevent God from hearing prayer in Psalm 66:18?', 'Not attending the temple', 'Regarding iniquity in the heart', 'Failing to fast', 'Not offering sacrifices', 'b', 'The psalmist said, "If I regard iniquity in my heart, the Lord will not hear me" (Psalm 66:18).'),
('Psalms', 66, 'teens', 5, 'What does Psalm 66:3 say that God''s enemies do because of his great power?', 'They flee in terror', 'They submit themselves to him', 'They are destroyed immediately', 'They call on him for mercy', 'b', 'The psalmist wrote, "Say unto God, How terrible art thou in thy works! through the greatness of thy power shall thine enemies submit themselves unto thee" (Psalm 66:3).'),
('Psalms', 66, 'adults', 1, 'What does "make a joyful noise" (Psalm 66:1) — the Hebrew rua — specifically connote beyond mere singing?', 'A soft and reverent tone', 'A loud, triumphant shout associated with battle victory and royal acclamation', 'A musical scale or melody', 'A priestly chant', 'b', 'Rua (Psalm 66:1) is a shout of triumph, the same word used for the battle cry and the acclamation of kings — it is joyful clamour before God.'),
('Psalms', 66, 'adults', 2, 'How does Psalm 66:6 allude to the Exodus and what does this say about God''s ongoing identity for Israel?', 'It is a vague reference to any past miracle', 'It recalls the parting of the Red Sea (Exodus 14), establishing that God''s saving acts define his identity for every generation', 'It refers to Joshua crossing the Jordan', 'It describes a future event', 'b', 'Psalm 66:6 recalls God turning the sea to dry land — clearly echoing Exodus 14 — reminding every generation that the Exodus God is still their God.'),
('Psalms', 66, 'adults', 3, 'What does "the eyes of God observe the nations" (Psalm 66:7) assert about divine governance?', 'God is passive and watches without acting', 'God''s omniscient watch over nations means he actively governs history and will not allow rebellion to go unchecked', 'God watches only Israel', 'The nations are unaware of God''s observation', 'b', 'Psalm 66:7 asserts divine sovereignty over world history: God''s watchful eyes over nations means he governs, not merely observes.'),
('Psalms', 66, 'adults', 4, 'What is the theological purpose of the trials described in Psalm 66:10-12 — the refining, burden, and fire and water?', 'God punishes his people for sin without purpose', 'God tests and refines his people as silver is refined — trials are instruments of purification and preparation for blessing', 'The trials are accidents of history', 'The people brought trials upon themselves only', 'b', 'Psalm 66:10 says God has "proved us... as silver is tried" — the fire and water of Psalm 66:12 are intentional purifying trials leading to a wealthy place.'),
('Psalms', 66, 'adults', 5, 'What is the distinction in Psalm 66:13-15 between vows made in distress and their fulfillment in prosperity?', 'The psalmist forgot his vows in prosperity', 'The psalmist faithfully fulfills in public worship what he promised in private crisis — integrity of covenant commitment', 'Vows made in distress are not binding', 'The offerings replace the verbal vows', 'b', 'The psalmist vowed offerings in distress (Psalm 66:14) and now brings them (Psalm 66:13, 15) — a model of vow-keeping integrity (cf. Ecclesiastes 5:4-5).'),
('Psalms', 66, 'adults', 6, 'What does "I regard iniquity in my heart" (Psalm 66:18) teach about the prerequisites for effective prayer?', 'Only priests can pray effectively', 'Cherished unconfessed sin creates a barrier between the worshipper and God''s hearing', 'Prayer is effective regardless of the heart''s state', 'God hears all prayers but not all are answered', 'b', 'Psalm 66:18 teaches that harboured sin (iniquity regarded in the heart) prevents God from hearing prayer — heart purity is prerequisite to answered prayer.'),
('Psalms', 66, 'adults', 7, 'What does the personal testimony section of Psalm 66:16-19 ("Come and hear, all ye that fear God") model for OT believers?', 'Private religion kept to oneself', 'Public declaration of God''s personal acts of salvation — the testimony as worship and witness', 'A priestly proclamation from the temple', 'A legal deposition before the assembly', 'b', 'Psalm 66:16-19 models the public testimony as an act of worship — "I will declare what he hath done for my soul" (Psalm 66:16) — personal faith shared communally.'),
('Psalms', 66, 'adults', 8, 'How does Psalm 66 transition between communal history (66:1-12) and personal testimony (66:13-20)?', 'The speaker changes from a choir to a king', 'The psalm moves from corporate salvation history to individual response and vow-fulfillment, integrating national and personal faith', 'The two sections are unrelated fragments', 'A liturgical rubric marks the division', 'b', 'Psalm 66 is a masterful integration of corporate history (66:1-12) with personal testimony (66:13-20), showing that Israel''s salvation story is also each believer''s story.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 67, 'kids', 1, 'What did the psalmist ask God to do to his face in Psalm 67?', 'Turn it away', 'Make it shine upon us', 'Show it in the heavens', 'Hide it in mercy', 'b', 'The psalmist prayed, "God be merciful unto us, and cause his face to shine upon us" (Psalm 67:1).'),
('Psalms', 67, 'kids', 2, 'What repeated phrase shows the psalmist''s desire for all people to praise God?', 'Praise him all the earth', 'Let the people praise thee, O God; let all the people praise thee', 'Shout for joy all nations', 'Bless the LORD all his works', 'b', 'The refrain "Let the people praise thee, O God; let all the people praise thee" appears in Psalm 67:3 and 67:5.'),
('Psalms', 67, 'kids', 3, 'What does Psalm 67 say God shall do to show he is their God?', 'Send fire from heaven', 'Bless them and make the earth yield her increase', 'Speak to them from a cloud', 'Give them a promised land', 'b', 'The psalmist wrote, "Then shall the earth yield her increase; and God, even our own God, shall bless us" (Psalm 67:6).'),
('Psalms', 67, 'teens', 1, 'What is the purpose stated in Psalm 67:2 for God blessing Israel?', 'That Israel would be the greatest nation', 'That God''s way may be known upon earth and his saving health among all nations', 'That other nations would fear Israel', 'That Israel would multiply greatly', 'b', 'The psalmist prayed for God''s blessing so "that thy way may be known upon earth, thy saving health among all nations" (Psalm 67:2).'),
('Psalms', 67, 'teens', 2, 'What reason is given for the nations to be glad in Psalm 67:4?', 'God gives them prosperity', 'God judges the people righteously and governs the nations upon earth', 'God delivers them from their enemies', 'God gives them wisdom and law', 'b', 'The psalmist said, "O let the nations be glad and sing for joy: for thou shalt judge the people righteously, and govern the nations upon earth" (Psalm 67:4).'),
('Psalms', 67, 'teens', 3, 'Psalm 67 is considered a "missionary psalm." What makes it missionary in character?', 'It commands Israel to go to other nations', 'It prays that God''s salvation and blessing of Israel will become known to and shared with all nations', 'It describes a mission journey', 'It lists nations that will be converted', 'b', 'Psalm 67 is missionary because it prays that Israel''s blessing will reveal God''s way to all nations (Psalm 67:2) — a centripetal mission theology.'),
('Psalms', 67, 'teens', 4, 'The opening of Psalm 67:1 echoes what famous OT blessing?', 'The Shema from Deuteronomy 6', 'The Aaronic blessing from Numbers 6:24-26', 'The blessing of Jacob in Genesis 49', 'The benediction at the end of Leviticus', 'b', 'Psalm 67:1 echoes the Aaronic blessing: "The LORD make his face shine upon thee, and be gracious unto thee" (Numbers 6:25).'),
('Psalms', 67, 'teens', 5, 'How many times does the refrain "let the people praise thee" appear in Psalm 67?', 'Once', 'Twice', 'Three times', 'Four times', 'b', 'The refrain "Let the people praise thee, O God; let all the people praise thee" appears twice — in Psalm 67:3 and 67:5.'),
('Psalms', 67, 'adults', 1, 'How does Psalm 67''s opening allusion to the Aaronic blessing (Numbers 6:24-26) connect Israel''s priestly vocation to missionary purpose?', 'Israel is to be a nation that keeps blessings to itself', 'Israel as a "kingdom of priests" (Exodus 19:6) receives God''s blessing in order to mediate it to all nations', 'The Aaronic blessing was only for the tribe of Levi', 'The psalm rejects the Aaronic blessing as insufficient', 'b', 'By echoing Numbers 6:24-26, Psalm 67 frames Israel''s blessing within its priestly calling (Exodus 19:6) — blessed to be a blessing to all nations (cf. Genesis 12:3).'),
('Psalms', 67, 'adults', 2, 'What does "thy saving health" (Psalm 67:2) — literally "thy salvation" (yeshuah) — anticipate in redemptive history?', 'The military victories of Israel''s kings', 'The universal proclamation of salvation through Yeshua (Jesus) to all nations', 'The physical healing of all nations', 'The agricultural prosperity described in verse 6', 'b', 'The Hebrew yeshuah (saving health/salvation, Psalm 67:2) shares a root with Yeshua (Jesus) — pointing forward to the universal salvation Christ brings to all nations.'),
('Psalms', 67, 'adults', 3, 'What is the structural role of the refrain in Psalm 67:3 and 67:5?', 'It marks liturgical pauses for the congregation to kneel', 'It creates a concentric structure framing the reasons for universal praise — God''s just rule (67:4) and his provision (67:6)', 'It was sung by a different choir', 'It divides the psalm into unrelated sections', 'b', 'The refrain in Psalm 67:3 and 67:5 frames the central verse (67:4) about God''s just governance of nations, creating a chiastic structure for the psalm.'),
('Psalms', 67, 'adults', 4, 'What two aspects of God''s governance are highlighted in Psalm 67:4 as reasons for the nations to rejoice?', 'His power and his wealth', 'Righteous judgment of peoples and just governing of nations', 'His mercy and his patience', 'His creation and his providence', 'b', 'Psalm 67:4 says the nations should rejoice because God "shalt judge the people righteously, and govern the nations upon earth" — just rule is cause for universal joy.'),
('Psalms', 67, 'adults', 5, 'How does the agricultural blessing of Psalm 67:6 function within the psalm''s theological argument?', 'It is merely a prayer for good harvests', 'It connects God''s material provision of Israel to the missionary goal — visible blessing testifies to God''s character before the nations', 'It replaces the need for the temple', 'It is a covenant condition for Israel''s obedience', 'b', 'The earth''s yield (Psalm 67:6) is not isolated — Israel''s visible blessing by God testifies to his character and draws nations to him (cf. Deuteronomy 28:1-10).'),
('Psalms', 67, 'adults', 6, 'What does "God, even our own God" (Psalm 67:6) emphasize in the context of a psalm addressed to all nations?', 'God belongs exclusively to Israel and not the nations', 'The universal God who blesses all nations is also the personal covenant God of Israel — particularity within universality', 'God has different identities for different peoples', 'The nations have their own gods and Israel has hers', 'b', 'The juxtaposition of "all nations" (Psalm 67:2) with "our own God" (Psalm 67:6) holds together God''s universal sovereignty and his particular covenant relationship with Israel.'),
('Psalms', 67, 'adults', 7, 'How does Psalm 67 anticipate the Great Commission (Matthew 28:19)?', 'It commands Israel to go to all nations with the Torah', 'It prays for all nations to know God''s salvation — the same missional goal as Christ''s command to make disciples of all nations', 'It predicts that Israel will rule all nations', 'It has no connection to the New Testament', 'b', 'Psalm 67''s prayer for all nations to know God''s saving way (Psalm 67:2) is the OT anticipation of the Great Commission — the same universal missional heart.'),
('Psalms', 67, 'adults', 8, 'What is the logical flow of Psalm 67''s theology: blessing → knowledge → praise → more blessing?', 'God blesses Israel, all nations see it, all nations praise God, and God blesses all the earth', 'God punishes nations, they repent, they praise, and God blesses them', 'Israel praises God, God blesses them, the nations learn from Israel, and God judges the nations', 'Nations praise God first, then he blesses them, then Israel sees his power', 'a', 'Psalm 67''s logic is: God blesses Israel (67:1) → his way known among nations (67:2) → nations praise (67:3-5) → earth yields increase and all are blessed (67:6-7).');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 68, 'kids', 1, 'What does Psalm 68:1 say will happen to God''s enemies when God arises?', 'They will surrender', 'They will be scattered', 'They will be captured', 'They will flee to other lands', 'b', 'David wrote, "Let God arise, let his enemies be scattered: let them also that hate him flee before him" (Psalm 68:1).'),
('Psalms', 68, 'kids', 2, 'What does Psalm 68:5 call God in relation to those who have no father?', 'The provider of the fatherless', 'A father of the fatherless', 'The protector of the fatherless', 'The comforter of the fatherless', 'b', 'David declared that God is "A father of the fatherless, and a judge of the widows, is God in his holy habitation" (Psalm 68:5).'),
('Psalms', 68, 'kids', 3, 'What did Psalm 68:18 say God did on high — something Paul quotes in Ephesians 4:8?', 'He built a throne in heaven', 'He ascended on high and led captivity captive', 'He sent rain from heaven', 'He spoke from the clouds', 'b', 'David wrote, "Thou hast ascended on high, thou hast led captivity captive: thou hast received gifts for men" (Psalm 68:18).'),
('Psalms', 68, 'teens', 1, 'What does Psalm 68 say God does for the solitary and the prisoners?', 'He gives them strength to endure', 'He sets the solitary in families and brings out prisoners into prosperity', 'He sends angels to comfort them', 'He shortens their suffering', 'b', 'David wrote, "God setteth the solitary in families: he bringeth out those which are bound with chains" (Psalm 68:6).'),
('Psalms', 68, 'teens', 2, 'What natural phenomena accompanied God''s march through the wilderness in Psalm 68?', 'Fire and wind', 'The earth shook and the heavens dropped rain', 'Thunder and lightning', 'The mountains melted like wax', 'b', 'David recalled, "The earth shook, the heavens also dropped at the presence of God: even Sinai itself was moved at the presence of God" (Psalm 68:8).'),
('Psalms', 68, 'teens', 3, 'How does Psalm 68:11 describe those who spread the good news of God''s victory?', 'As mighty warriors', 'As a great company of those that published it', 'As singing priests', 'As prophets sent to the nations', 'b', 'David wrote, "The Lord gave the word: great was the company of those that published it" (Psalm 68:11).'),
('Psalms', 68, 'teens', 4, 'What mountain does Psalm 68:16 identify as the mountain God desires to dwell in?', 'Mount Sinai', 'Mount Zion', 'Mount Carmel', 'Mount Hermon', 'b', 'David wrote, "This is the hill which God desireth to dwell in; yea, the LORD will dwell in it for ever" (Psalm 68:16) — referring to Zion.'),
('Psalms', 68, 'teens', 5, 'What does Psalm 68:20 say about God and the issues of death?', 'Death is a punishment for the wicked only', 'Unto God the Lord belong the issues from death', 'God removes death from those who trust him', 'Death comes only to those who rebel against God', 'b', 'David declared, "Unto God the Lord belong the issues from death" (Psalm 68:20) — God controls the gates of death.'),
('Psalms', 68, 'adults', 1, 'How does Psalm 68:1 echo Numbers 10:35, and what is the theological significance of this echo?', 'Both describe the ark of the covenant in battle', 'Both use the priestly battle cry when the ark advanced, connecting Israel''s worship march to God''s warrior presence', 'Both are thanksgiving psalms for military victory', 'Both describe the return of the ark to Jerusalem', 'b', 'Psalm 68:1 directly quotes Numbers 10:35 — "Rise up, LORD, and let thine enemies be scattered" — the ancient ark-march formula, situating Israel''s worship in God''s warrior-presence.'),
('Psalms', 68, 'adults', 2, 'Paul quotes Psalm 68:18 in Ephesians 4:8, applying it to Christ''s ascension. What does "led captivity captive" mean in both the OT and NT contexts?', 'Both refer to taking prisoners of war as slaves', 'In the OT it describes God''s triumph over enemies; in the NT Paul applies it to Christ''s victory over sin, death, and spiritual powers at his ascension', 'The verse only applies to Pentecost', 'Paul misquotes the verse by changing "received" to "gave"', 'b', 'Psalm 68:18''s triumphal ascent (God leading captives) is applied by Paul (Ephesians 4:8) to Christ''s ascension, which conquered spiritual enemies and distributed gifts to the church.'),
('Psalms', 68, 'adults', 3, 'What does the description of God as "father of the fatherless, and a judge of the widows" (Psalm 68:5) reveal about Israel''s covenant ethics?', 'God only cares for Israel''s military strength', 'God''s character demands care for the most vulnerable — the fatherless and widow are special objects of his concern', 'Widows and orphans were excluded from worship', 'This is merely a poetic exaggeration', 'b', 'God as father of the fatherless and defender of widows (Psalm 68:5) grounds Israel''s social ethics in divine character — care for the vulnerable is a covenant obligation (cf. Deuteronomy 10:18).'),
('Psalms', 68, 'adults', 4, 'What is the significance of Mount Bashan''s envy of Mount Zion in Psalm 68:15-16?', 'Bashan was physically taller than Zion', 'High, imposing mountains are superseded by small Zion — God''s choice of the humble place over the impressive demonstrates his sovereign freedom', 'Bashan was Israel''s enemy territory', 'The psalm describes a literal geological event', 'b', 'The contrast between high Bashan and small Zion (Psalm 68:15-16) shows that God chooses the lowly — his dwelling is not determined by natural grandeur but by his sovereign will.'),
('Psalms', 68, 'adults', 5, 'What is the eschatological scope of Psalm 68:29-32, which anticipates kings bringing gifts to God?', 'It is limited to Solomon''s temple dedications', 'It anticipates the eschatological ingathering of nations to Zion — a Gentile submission to God''s kingship', 'It describes the tribute of conquered enemies', 'It refers to the return from Babylonian exile', 'b', 'Psalm 68:29-32 anticipates kings from Egypt and Ethiopia bringing gifts to God (cf. Isaiah 60) — an eschatological vision of universal Gentile submission to Israel''s God.'),
('Psalms', 68, 'adults', 6, 'How does Psalm 68''s procession theology relate to the physical movement of the ark of the covenant?', 'It is purely metaphorical and unrelated to the ark', 'The psalm likely accompanied the ark''s triumphal procession to Jerusalem, making God''s physical march with his people the occasion for cosmic theology', 'The ark is never mentioned in the psalm', 'The psalm was written centuries after the ark was lost', 'b', 'Psalm 68 is widely understood as a liturgical processional accompanying the ark — God''s physical march with Israel (68:7-8) becomes the lens for cosmic theology.'),
('Psalms', 68, 'adults', 7, 'What does the list of tribes in Psalm 68:27 (Benjamin, Judah, Zebulun, Naphtali) represent?', 'The four tribes that led Israel''s armies', 'A representative gathering of all Israel — north and south, small and great — united in worship', 'The tribes that accompanied the ark from the wilderness', 'The four cardinal points of Israel''s tribal arrangement', 'b', 'The four tribes (Psalm 68:27) represent all Israel — Benjamin and Judah from the south, Zebulun and Naphtali from the north — the whole nation united before God.'),
('Psalms', 68, 'adults', 8, 'What is the theological climax of Psalm 68, and where does it occur?', 'The call to praise in verse 1', 'The universal praise of all kingdoms and nations in verses 32-35, culminating in the declaration of God''s strength and power', 'The ascension of God in verse 18', 'The defeat of enemies in verse 21', 'b', 'Psalm 68 climaxes in a universal call for all kingdoms to sing to God (Psalm 68:32-35) — all the earth declaring his strength and power above all.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 69, 'kids', 1, 'What did the enemies give David to drink in Psalm 69?', 'Bitter water', 'Vinegar', 'Salt water', 'Poison', 'b', 'David wrote, "They gave me also gall for my meat; and in my thirst they gave me vinegar to drink" (Psalm 69:21).'),
('Psalms', 69, 'kids', 2, 'What did David say consumed him regarding God''s house?', 'A great love for its beauty', 'The zeal of thine house', 'A desire to serve as a priest', 'A longing to see God''s glory', 'b', 'David said, "The zeal of thine house hath eaten me up" (Psalm 69:9).'),
('Psalms', 69, 'kids', 3, 'To what was David sinking in the opening of Psalm 69?', 'Quicksand', 'Deep mire and deep waters', 'A dark pit', 'A flooded river', 'b', 'David cried, "I sink in deep mire, where there is no standing: I am come into deep waters, where the floods overflow me" (Psalm 69:2).'),
('Psalms', 69, 'teens', 1, 'What does Psalm 69:9 say about the reproaches of those who reproached God?', 'They were justly punished', 'They fell upon David', 'They were ignored by God', 'They strengthened David''s faith', 'b', 'David wrote, "The reproaches of them that reproached thee are fallen upon me" (Psalm 69:9).'),
('Psalms', 69, 'teens', 2, 'What was David''s condition that made him a stranger to his family in Psalm 69:8?', 'His poverty', 'His zeal for God made him an alien to his brethren and a stranger to his mother''s children', 'His long absence on a journey', 'His leper disease', 'b', 'David wrote, "I am become a stranger unto my brethren, and an alien unto my mother''s children" because of his zeal for God (Psalm 69:8-9).'),
('Psalms', 69, 'teens', 3, 'What did David say his enemies hated him without a cause for in Psalm 69:4?', 'For his wealth', 'They that hate me without a cause are more than the hairs of mine head', 'For his royal power', 'For his righteous judgments', 'b', 'David lamented, "They that hate me without a cause are more than the hairs of mine head" (Psalm 69:4).'),
('Psalms', 69, 'teens', 4, 'How does Psalm 69:21 connect to the crucifixion of Jesus?', 'Jesus quoted this verse on the cross', 'The vinegar given to Jesus at the cross (Matthew 27:48; John 19:29) fulfills this verse', 'Jesus prayed this psalm in Gethsemane', 'John cites it as fulfilled at the Last Supper', 'b', 'Psalm 69:21 — "in my thirst they gave me vinegar to drink" — is fulfilled in John 19:29 when soldiers offered Jesus vinegar (sour wine) at the crucifixion.'),
('Psalms', 69, 'teens', 5, 'What does the psalmist say God will do for the humble and the poor in the closing section of Psalm 69:32-33?', 'Give them wealth and honour', 'The humble shall see and be glad; the LORD heareth the poor', 'Deliver them from all enemies', 'Restore them to their families', 'b', 'David declared, "The humble shall see this, and be glad... For the LORD heareth the poor, and despiseth not his prisoners" (Psalm 69:32-33).'),
('Psalms', 69, 'adults', 1, 'How many times is Psalm 69 quoted or alluded to in the New Testament, making it one of the most-cited OT texts?', 'Twice', 'About three times', 'At least seven times', 'Once', 'c', 'Psalm 69 is one of the most-quoted psalms in the NT — cited at least seven times including Romans 11:9-10, John 2:17, John 15:25, Matthew 27:48, Acts 1:20, and Romans 15:3.'),
('Psalms', 69, 'adults', 2, 'John 2:17 quotes Psalm 69:9 in reference to Jesus cleansing the temple. What theological connection does John draw?', 'Jesus was fulfilling a legal obligation', 'Jesus'' zeal for God''s house consuming him identifies him as the messianic sufferer of Psalm 69 who bears the cost of God''s honour', 'Jesus was angry at the merchants personally', 'John uses the verse to show Jesus loved the temple building', 'b', 'John 2:17 applies Psalm 69:9 to Jesus — his consuming zeal for God''s house identifies him as the messianic servant who bears divine reproach (John 2:17; cf. Romans 15:3).'),
('Psalms', 69, 'adults', 3, 'How does "they hated me without a cause" (Psalm 69:4) function in John 15:25?', 'Jesus quotes it as a legal precedent', 'Jesus applies it to himself — the world''s hatred of him without cause fulfills Scripture, confirming his messianic identity', 'John uses it as a general proverb', 'It is used to defend the disciples'' innocence', 'b', 'Jesus directly applies Psalm 69:4 in John 15:25 — the world''s baseless hatred of him "fulfilleth the word that is written in their law" — messianic fulfillment.'),
('Psalms', 69, 'adults', 4, 'What is the imprecatory nature of Psalm 69:22-28, and how has it been applied in the NT?', 'It is a prayer for enemies'' salvation', 'It calls God''s judgment on enemies; Acts 1:20 applies verse 25 to Judas Iscariot''s fate', 'It is purely historical and never applied in the NT', 'It predicts the destruction of Jerusalem in 70 AD', 'b', 'Psalm 69:25 ("Let their habitation be desolate") is quoted in Acts 1:20 as fulfilled in Judas Iscariot, whose betrayal brought upon him the judgment prophesied here.'),
('Psalms', 69, 'adults', 5, 'What does the opening water imagery (sinking in mire, floods, deep waters, Psalm 69:1-3, 14-15) represent as a metaphorical system?', 'Literal drowning David experienced', 'Chaotic, overwhelming suffering threatening to extinguish life — the deep waters symbolize mortal crisis beyond human rescue', 'The waters of the Red Sea', 'A spiritual purification ritual', 'b', 'The deep waters and mire of Psalm 69:1-3, 14-15 are ancient Near Eastern chaos imagery — overwhelming, life-threatening suffering from which only God can save.'),
('Psalms', 69, 'adults', 6, 'What does "blot them out of the book of the living" (Psalm 69:28) imply about Israel''s theology of divine records?', 'It is merely a poetic wish', 'It implies a heavenly register of the living from which the condemned are erased — anticipating the book of life in Revelation', 'It refers to the genealogical records of Israel', 'It is a priestly curse formula', 'b', 'Psalm 69:28''s book of the living anticipates the NT book of life (Revelation 3:5; 20:15) — a divine register of those in covenant relationship with God.'),
('Psalms', 69, 'adults', 7, 'How does Psalm 69:30-31 theologically reorder Israel''s sacrificial system?', 'It abolishes animal sacrifice entirely', 'It subordinates animal sacrifice to the praise of a thankful heart — God is more pleased with grateful song than burnt offerings', 'It argues that sacrifices are more important than praise', 'It restricts praise to the Levitical singers', 'b', 'Psalm 69:30-31 declares that praising God with a song pleases him more than an ox or bullock — an OT anticipation of the prophetic critique of empty ritual (cf. Psalm 51:16-17; Hosea 6:6).'),
('Psalms', 69, 'adults', 8, 'What does Psalm 69''s structure (lament → imprecation → praise → eschatological hope) model for NT believers facing unjust suffering?', 'That imprecatory prayer is forbidden in the NT', 'That honest lament can coexist with praise, and God''s ultimate justice transforms present suffering into eschatological hope', 'That believers should suppress their complaints', 'That suffering is always the result of personal sin', 'b', 'Psalm 69 models the journey from raw lament (69:1-4) through honest prayer (69:5-28) to confident praise (69:30-36) — a model for NT believers facing unjust suffering (cf. Romans 8:18-25).');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 70, 'kids', 1, 'What did David urgently ask God to do in the very first verse of Psalm 70?', 'Give him victory in battle', 'Make haste to deliver him', 'Send his angels to protect him', 'Forgive all his sins', 'b', 'David prayed, "Make haste, O God, to deliver me; make haste to help me, O LORD" (Psalm 70:1).'),
('Psalms', 70, 'kids', 2, 'What did David ask God to do to those who sought his life?', 'Forgive them', 'Let them be ashamed and confounded', 'Send them away to other lands', 'Give them a chance to repent', 'b', 'David prayed, "Let them be ashamed and confounded that seek after my soul" (Psalm 70:2).'),
('Psalms', 70, 'kids', 3, 'What did David call himself — showing his need for God?', 'A mighty warrior', 'Poor and needy', 'A humble servant', 'A faithful king', 'b', 'David concluded, "But I am poor and needy: make haste unto me, O God" (Psalm 70:5).'),
('Psalms', 70, 'teens', 1, 'What does David say the seekers of God should continually say?', 'Bless the LORD all ye peoples', 'Let God be magnified', 'Praise the LORD for he is good', 'Holy is the LORD God Almighty', 'b', 'David said, "Let all those that seek thee rejoice and be glad in thee: and let such as love thy salvation say continually, Let God be magnified" (Psalm 70:4).'),
('Psalms', 70, 'teens', 2, 'What does David pray about those who say "Aha, aha!" (mocking him)?', 'That they will be converted', 'That they will be turned backward and put to shame', 'That they will be silenced', 'That they will be defeated in battle', 'b', 'David prayed, "Let them be turned backward, and put to confusion, that desire my hurt... that say, Aha, aha" (Psalm 70:2-3).'),
('Psalms', 70, 'teens', 3, 'Psalm 70 is almost identical to which earlier psalm?', 'Psalm 22:19-21', 'Psalm 40:13-17', 'Psalm 51:1-5', 'Psalm 35:4-8', 'b', 'Psalm 70 is nearly identical to Psalm 40:13-17 — both are urgent prayers for deliverance, with Psalm 70 being an independent liturgical use of that section.'),
('Psalms', 70, 'teens', 4, 'What does the brevity of Psalm 70 (only 5 verses) communicate about the nature of urgent prayer?', 'Short prayers are less effective', 'Genuine crisis prayer can be intense and brief — urgency strips prayer to its essentials', 'David was too tired to write more', 'Only long prayers receive answers', 'b', 'Psalm 70''s five-verse brevity captures the essence of crisis prayer — urgency and desperate need strip the prayer down to its bare essentials before God.'),
('Psalms', 70, 'teens', 5, 'What superscription or title does Psalm 70 carry that indicates its liturgical function?', 'A prayer of the afflicted', 'A psalm of David to bring to remembrance', 'A song of degrees', 'A maskil for understanding', 'b', 'Psalm 70 is headed "A Psalm of David, to bring to remembrance" — suggesting it was used as a memorial/petition in Israel''s liturgy.'),
('Psalms', 70, 'adults', 1, 'What does "to bring to remembrance" in Psalm 70''s superscription suggest about its liturgical use?', 'David wanted future generations to memorize it', 'It was used in the context of the "memorial offering" (azkarah) — a ritual bringing the worshipper''s need before God''s attention', 'It was a royal decree', 'It was placed in the temple archives', 'b', 'The title "to bring to remembrance" (Psalm 70 superscription) likely connects to the azkarah (memorial portion of the grain offering) — a liturgical bringing of oneself before God.'),
('Psalms', 70, 'adults', 2, 'How does Psalm 70''s repetition of "make haste" (verses 1 and 5) function rhetorically?', 'It shows David''s impatience with God', 'The double urgency frames the entire psalm — every word is under the pressure of desperate need', 'It is a liturgical chorus', 'It balances the two stanzas', 'b', 'The twin urgency of "make haste" in Psalm 70:1 and 70:5 creates an envelope of crisis — the whole psalm breathes urgency and radical dependence on God.'),
('Psalms', 70, 'adults', 3, 'What does the contrast between the fate of enemies (ashamed, confounded, 70:2-3) and the righteous (glad, rejoicing, 70:4) reveal about OT theodicy?', 'Righteous and wicked have identical destinies', 'God''s justice guarantees opposite outcomes — the wicked''s shame is the necessary counterpart to the righteous''s joy', 'Righteousness guarantees immediate reward', 'The wicked are not judged until death', 'b', 'Psalm 70''s sharp contrast — enemies confounded (70:2-3) vs. seekers rejoicing (70:4) — reflects OT theodicy: God''s justice ensures that righteousness and wickedness lead to opposite ends.'),
('Psalms', 70, 'adults', 4, 'What is the theological significance of David''s self-description as "poor and needy" (Psalm 70:5) for a king?', 'David was literally impoverished at this time', 'It expresses radical spiritual poverty — total dependence on God regardless of earthly status, the posture of the "anawim" (humble poor)', 'It was a rhetorical device to gain sympathy', 'It describes David''s early pre-royal life', 'b', 'David calling himself poor and needy (Psalm 70:5) despite being king reflects the anawim spirituality — the humble poor who depend entirely on God (cf. Matthew 5:3, "poor in spirit").'),
('Psalms', 70, 'adults', 5, 'When Psalm 70 is compared to Psalm 40:13-17, what does the independent use of this prayer section reveal?', 'One version is a scribal error', 'Individual psalm sections circulated independently and were reused in different liturgical contexts — scripture is organically living', 'Psalm 70 corrects an error in Psalm 40', 'David wrote Psalm 40 first and regretted it', 'b', 'The existence of Psalm 70 as a standalone version of Psalm 40:13-17 shows that psalm sections were excerpted and reused liturgically — Israel''s prayer treasury was fluid and living.'),
('Psalms', 70, 'adults', 6, 'How does "let God be magnified" (Psalm 70:4) function as a statement of priority within urgent crisis prayer?', 'It delays God''s help by praising first', 'Even in desperate crisis, David''s ultimate concern is God''s magnification — the worshipper''s need is subordinated to God''s glory', 'It is a standard liturgical formula', 'It means David wants God to appear visibly', 'b', 'David''s cry "let God be magnified" (Psalm 70:4) within an urgent lament reveals that even crisis prayer is ultimately theocentric — God''s glory is the supreme concern.'),
('Psalms', 70, 'adults', 7, 'What does the use of "LORD" (YHWH) in Psalm 70:1 and "God" (Elohim) in Psalm 70:1 and 5 reveal about the psalm''s divine address?', 'David is uncertain which name to use', 'Both the personal covenant name (YHWH) and the generic divine name (Elohim) are used, appealing to God in both his covenant relationship and universal power', 'The names are interchangeable with no significance', 'YHWH is used for praise and Elohim for petition', 'b', 'Psalm 70 addresses both YHWH (covenant name, 70:1) and Elohim (universal name, 70:1, 5), appealing to both God''s personal covenant faithfulness and his omnipotent power.'),
('Psalms', 70, 'adults', 8, 'How does Psalm 70''s raw urgency contribute to the Psalter''s honest theology of prayer?', 'It models polished, formal prayer', 'It validates desperate, unadorned cries to God — the Psalter permits and models raw urgency as legitimate prayer', 'It shows that only emotional prayers are answered', 'It warns against praying too urgently', 'b', 'Psalm 70''s unadorned urgency contributes to the Psalter''s honest prayer theology — it legitimises stripped-down crisis prayer as fully valid before God (cf. Romans 8:26).');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 71, 'kids', 1, 'What did the psalmist ask God not to do in his old age in Psalm 71?', 'Let him grow weak', 'Cast him off in the time of old age', 'Forget his prayers', 'Leave him without children', 'b', 'The psalmist prayed, "Cast me not off in the time of old age; forsake me not when my strength faileth" (Psalm 71:9).'),
('Psalms', 71, 'kids', 2, 'What did the psalmist say he had leaned on since his birth?', 'His family''s wisdom', 'God who took him out of his mother''s womb', 'The strength of his own body', 'The teachings of his people', 'b', 'The psalmist said, "By thee have I been holden up from the womb: thou art he that took me out of my mother''s bowels" (Psalm 71:6).'),
('Psalms', 71, 'kids', 3, 'What did the psalmist say he would always hope in and praise God more and more?', 'God''s provision of food', 'The righteousness of God', 'God''s mercy and strength', 'The laws of God', 'b', 'The psalmist declared, "But I will hope continually, and will yet praise thee more and more" (Psalm 71:14).'),
('Psalms', 71, 'teens', 1, 'What did the psalmist''s enemies say when they plotted against him in Psalm 71:11?', 'God has given him to us', 'God hath forsaken him: persecute and take him; for there is none to deliver him', 'He has no friends to help him', 'His God will not hear his prayer', 'b', 'The psalmist''s enemies said, "God hath forsaken him: persecute and take him; for there is none to deliver him" (Psalm 71:11).'),
('Psalms', 71, 'teens', 2, 'What does the psalmist say he will shew to this generation and everyone to come?', 'The law of Moses', 'God''s strength and righteous acts', 'The history of Israel', 'The words of the prophets', 'b', 'The psalmist declared, "I will shew thy strength unto this generation, and thy power to every one that is to come" (Psalm 71:18).'),
('Psalms', 71, 'teens', 3, 'What musical instrument does the psalmist mention praising God with in Psalm 71?', 'The trumpet', 'The psaltery and harp', 'The flute and drum', 'The cymbals', 'b', 'The psalmist declared, "I will also praise thee with the psaltery, even thy truth, O my God: unto thee will I sing with the harp" (Psalm 71:22).'),
('Psalms', 71, 'teens', 4, 'What does the psalmist ask God to do after showing him troubles and adversities in Psalm 71?', 'Give him peace at last', 'Quicken him again and bring him up again from the depths of the earth', 'Give him rest in death', 'Send him a young successor', 'b', 'The psalmist prayed, "Thou, which hast shewed me great and sore troubles, shalt quicken me again, and shalt bring me up again from the depths of the earth" (Psalm 71:20).'),
('Psalms', 71, 'teens', 5, 'How does the psalmist describe God as his refuge from his youth in Psalm 71:5?', 'As his daily bread and water', 'As his hope and his trust from his youth', 'As the guide of all his ways', 'As the teacher of his people', 'b', 'The psalmist said, "For thou art my hope, O Lord GOD: thou art my trust from my youth" (Psalm 71:5).'),
('Psalms', 71, 'adults', 1, 'What is the likely setting of Psalm 71 and what makes it distinctive among the Psalms?', 'A young warrior going into battle', 'It is the prayer of an elderly believer — the only psalm explicitly voiced from the perspective of old age and lifelong faith', 'A king celebrating his coronation', 'A priest performing his annual duties', 'b', 'Psalm 71 is unique as the prayer of an aged person (Psalm 71:9, 18) — a lifelong believer reviewing God''s faithfulness from birth to old age.'),
('Psalms', 71, 'adults', 2, 'What does the psalmist''s phrase "thou art my strong refuge" (Psalm 71:7) — using the Hebrew "mahseh" — convey about his theology?', 'God is physically protective like a wall', 'Mahseh (refuge/shelter) describes God as a place of total security — the aged believer''s whole life has been spent under divine shelter', 'God rescued the psalmist from a specific battle', 'God is the refuge only in times of crisis', 'b', 'Mahseh (Psalm 71:7) is a rich refuge word — not just emergency protection but a lifelong dwelling in God''s sheltering care from womb to old age.'),
('Psalms', 71, 'adults', 3, 'How does Psalm 71''s interlacing of petition and praise (e.g., 71:1-4 petition, 71:5-8 praise, 71:9-13 petition) model the rhythm of mature prayer?', 'It shows that the psalmist forgot his train of thought', 'It models prayer as a living dialogue where trust and need alternate — praise does not wait until deliverance but interrupts lament', 'The sections were originally separate prayers', 'Petition and praise are kept strictly separate', 'b', 'Psalm 71''s interweaving of petition and praise models mature prayer — praise interrupts lament (71:5-8) because faith does not wait for deliverance to worship God.'),
('Psalms', 71, 'adults', 4, 'What does "I will go in the strength of the Lord GOD" (Psalm 71:16) declare about the aged believer''s source of ongoing vitality?', 'Physical strength is restored to the aged', 'In the absence of youthful strength, God''s strength becomes the sole source of the aged believer''s forward movement', 'The psalmist is beginning a military campaign', 'God gives the aged special supernatural ability', 'b', 'Psalm 71:16''s "I will go in the strength of the Lord GOD" is a declaration of radical dependence — the aged believer''s vitality comes entirely from God, not from self.'),
('Psalms', 71, 'adults', 5, 'What does the psalmist''s request in Psalm 71:18 — "forsake me not...until I have shewed thy strength unto this generation" — reveal about his understanding of his life''s purpose in old age?', 'Old age has no remaining purpose', 'The aged believer''s final purpose is testimony — to pass the knowledge of God''s power to the next generation', 'The psalmist fears death before completing temple service', 'God abandons the elderly when their strength fails', 'b', 'Psalm 71:18''s request to live until he can testify to the next generation reveals that the aged believer''s final vocation is intergenerational witness — faith passed to the next generation.'),
('Psalms', 71, 'adults', 6, 'How does the psalmist''s reference to being held from the womb (71:6) relate to his trust in God in old age?', 'It is a nostalgic memory', 'It creates a theological arc: if God was faithful from birth, he will be faithful in old age — the whole life as evidence for continued trust', 'Birth and old age are unrelated in the psalm', 'It refers to a miraculous birth like Isaac or Samuel', 'b', 'Psalm 71''s womb-to-old-age arc (71:6, 9, 18) builds a cumulative argument: God''s faithfulness across an entire life is the basis for trust in life''s final chapter.'),
('Psalms', 71, 'adults', 7, 'What is the significance of the psalmist''s vow to praise God with "lips that rejoice" (Psalm 71:23) when God restores him?', 'Praise is contingent on restoration', 'The lips that cried in lament will become the lips of praise — suffering and praise are part of one continuous testimony', 'Praise is only appropriate after complete victory', 'The psalmist had previously been silenced', 'b', 'Psalm 71:23''s rejoicing lips complete the journey from the crying soul of 71:2-3 — the same mouth that begged becomes the mouth that praises, unifying lament and doxology.'),
('Psalms', 71, 'adults', 8, 'How does Psalm 71 relate to the broader wisdom tradition''s teaching on the value of old age?', 'Old age is seen as a burden without spiritual value', 'It affirms the wisdom tradition''s view (Proverbs 16:31; 20:29) that old age can be a crown of lifelong faithfulness — a platform for testimony', 'The psalm is pessimistic about aging', 'Psalm 71 contradicts Proverbs on old age', 'b', 'Psalm 71 aligns with wisdom tradition (Proverbs 16:31 — "hoary head is a crown of glory") by presenting old age as the culmination of faithful life and a platform for testimony.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 72, 'kids', 1, 'How far will the king''s dominion reach according to Psalm 72?', 'Only over Israel', 'From sea to sea and to the ends of the earth', 'Over all the mountains', 'From the north to the south only', 'b', 'The psalmist prayed, "He shall have dominion also from sea to sea, and from the river unto the ends of the earth" (Psalm 72:8).'),
('Psalms', 72, 'kids', 2, 'What does the psalmist say the king will do for the poor and needy?', 'Give them more work', 'Save the children of the needy and break in pieces the oppressor', 'Build them bigger cities', 'Teach them to be strong', 'b', 'The psalmist prayed, "He shall save the children of the needy, and shall break in pieces the oppressor" (Psalm 72:4).'),
('Psalms', 72, 'kids', 3, 'What is said about the king''s name in Psalm 72?', 'It shall be feared by all nations', 'His name shall endure for ever', 'It shall be written in the heavens', 'All kings shall know his name', 'b', 'The psalmist declared, "His name shall endure for ever: his name shall be continued as long as the sun" (Psalm 72:17).'),
('Psalms', 72, 'teens', 1, 'What two things does the king judge righteously in Psalm 72?', 'The rich and the powerful', 'The poor and the children of the needy', 'The priests and the prophets', 'The young and the old', 'b', 'The psalmist prayed that the king would "judge thy people with righteousness, and thy poor with judgment" (Psalm 72:2) and deliver the needy.'),
('Psalms', 72, 'teens', 2, 'What natural image illustrates the king''s refreshing rule over the people in Psalm 72:6?', 'A mighty wind that cools the land', 'He shall come down like rain upon the mown grass', 'A river of water in a dry land', 'A spring that never runs dry', 'b', 'The psalmist said, "He shall come down like rain upon the mown grass: as showers that water the earth" (Psalm 72:6).'),
('Psalms', 72, 'teens', 3, 'Who does Psalm 72 say shall bow before the king — specifically mentioning nations from the south?', 'The kings of the north only', 'The kings of Sheba and Seba shall offer gifts, all kings shall fall down before him', 'The nations conquered in battle', 'The people of Egypt and Babylon', 'b', 'The psalmist prayed, "The kings of Sheba and Seba shall offer gifts... all kings shall fall down before him: all nations shall serve him" (Psalm 72:10-11).'),
('Psalms', 72, 'teens', 4, 'What phrase closes Book II of the Psalms (Psalms 42-72) at the end of Psalm 72?', 'The LORD is my shepherd', 'The prayers of David the son of Jesse are ended', 'Let all the earth be filled with his glory', 'Praise ye the LORD for ever and ever', 'b', 'Psalm 72:20 reads, "The prayers of David the son of Jesse are ended" — the editorial colophon closing Book II of the Psalter.'),
('Psalms', 72, 'teens', 5, 'What does the psalmist say the king will do to the man in need who has no helper in Psalm 72:12?', 'Give him a judge to plead his case', 'Deliver him; he shall spare the poor and needy', 'Send him to the priests for help', 'Give him a field to work', 'b', 'The psalmist prayed, "He shall deliver the needy when he crieth; the poor also, and him that hath no helper" (Psalm 72:12).'),
('Psalms', 72, 'adults', 1, 'What is the dual horizon of Psalm 72 — which two kings does it simultaneously address?', 'David and his son Absalom', 'Solomon historically and the Messiah eschatologically — it is both a royal coronation prayer and a Messianic prophecy', 'David and Moses', 'Solomon and Hezekiah', 'b', 'Psalm 72 is simultaneously a prayer for Solomon at his coronation (its historical horizon) and a Messianic prophecy (its eschatological horizon) — no earthly king fully fulfills its vision.'),
('Psalms', 72, 'adults', 2, 'How does "he shall have dominion from sea to sea" (Psalm 72:8) connect to the Abrahamic covenant and its land promises?', 'It refers to Israel''s conquest of Canaan', 'It expands the land promise beyond Canaan to universal sovereignty — the king is the heir of all God''s covenant promises to Abraham', 'It describes the borders of Solomon''s kingdom', 'It is merely poetic hyperbole', 'b', 'Psalm 72:8''s universal dominion echoes the Abrahamic promise (Genesis 22:17-18) that Abraham''s seed would possess the gates of enemies — the king is the covenant heir.'),
('Psalms', 72, 'adults', 3, 'What does the abundance-of-grain image (Psalm 72:16 — "handful of corn on top of mountains") convey about the ideal king''s reign?', 'Israel will become an agricultural superpower', 'Messianic rule brings abundant, impossible fruitfulness — even barren mountaintops overflow with grain, reversing the curse', 'The king will be known for farming innovations', 'The mountains will be terraced for agriculture', 'b', 'Grain on mountain tops (Psalm 72:16) is a hyperbole of impossible abundance — Messianic rule reverses the curse and creates superabundant shalom (cf. Amos 9:13).'),
('Psalms', 72, 'adults', 4, 'How does Paul connect the universal blessing through the king''s name (Psalm 72:17 — "all nations shall be blessed in him") to the Abrahamic covenant in Galatians 3?', 'Paul does not connect these texts', 'Psalm 72:17 echoes Genesis 12:3 ("all families of the earth shall be blessed") — the Messianic king is the Seed of Abraham through whom all nations are blessed', 'The blessing is limited to nations that accept the Torah', 'The blessing refers to material prosperity only', 'b', 'Psalm 72:17''s "all nations shall be blessed in him" directly echoes Genesis 12:3 — the Messianic king is identified as the Abrahamic Seed through whom universal blessing comes (cf. Galatians 3:16).'),
('Psalms', 72, 'adults', 5, 'What is the ethical centre of Psalm 72''s vision of ideal kingship?', 'Military conquest and territorial expansion', 'Justice for the poor, needy, and oppressed — the king''s greatness is measured by his care for the vulnerable', 'Wisdom and learning above all virtues', 'Wealth and international tribute', 'b', 'The ethical centre of Psalm 72 is justice for the poor and oppressed (72:2, 4, 12-14) — the ideal king''s greatness is measured not by conquest but by how he protects the vulnerable.'),
('Psalms', 72, 'adults', 6, 'What does "he shall live" (Psalm 72:15) in the context of the psalm''s universalism suggest about the Messianic king''s life?', 'The king will simply have a long reign', 'It anticipates the eternal life of the Messianic king whose reign has no end — fulfilled in Christ''s resurrection', 'It is a prayer for Solomon''s health', 'It means the king will survive his enemies', 'b', 'Psalm 72:15''s "he shall live" within the context of eternal dominion (72:5, 17) points beyond any mortal king to the Messiah whose life and reign are eternal.'),
('Psalms', 72, 'adults', 7, 'What is the doxological function of Psalm 72:18-19 within the Psalter?', 'It concludes only Psalm 72', 'It is the closing doxology of Book II (Psalms 42-72), a liturgical benediction praising God whose glory fills the whole earth', 'It introduces Book III', 'It is a separate psalm misplaced here', 'b', 'Psalm 72:18-19 is the closing doxology of Book II of the Psalter (Psalms 42-72), blessing God and praying for his glory to fill all the earth.'),
('Psalms', 72, 'adults', 8, 'How does the image of the king defending the poor (Psalm 72:12-14) — "their blood shall be precious in his sight" — anticipate Christ''s redemptive work?', 'It is limited to economic welfare programs', 'The king who redeems the weak from oppression and counts their blood precious foreshadows Christ who redeems at the cost of his own precious blood', 'It describes Solomon''s judicial reforms', 'It is a military metaphor for protecting citizens', 'b', 'The king''s redemption of the needy with precious blood (Psalm 72:14) foreshadows Christ whose own blood (1 Peter 1:19) is the price of redemption for the weak and helpless.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 73, 'kids', 1, 'Who wrote Psalm 73?', 'Asaph', 'David', 'Moses', 'Solomon', 'a', 'The heading says "A Psalm of Asaph." Asaph was a worship leader appointed by David.'),
('Psalms', 73, 'kids', 2, 'What almost happened to Asaph when he saw wicked people doing well?', 'His feet almost slipped — he nearly lost his faith', 'He became very sick', 'He ran away from the temple', 'He stopped singing songs', 'a', 'Psalm 73:2 — "But as for me, my feet were almost gone; my steps had well nigh slipped."'),
('Psalms', 73, 'kids', 3, 'Where did Asaph finally understand why the wicked prosper?', 'In the sanctuary of God', 'In a dream at night', 'On top of a mountain', 'By asking his friends', 'a', 'Psalm 73:17 — "Until I went into the sanctuary of God; then understood I their end."'),
('Psalms', 73, 'teens', 1, 'What troubled Asaph about the wicked in Psalm 73:3-5?', 'They prospered with no troubles — healthy, strong, and free from common burdens', 'They were being punished severely', 'They were losing everything', 'They were turning to God', 'a', 'Psalm 73:3-5 — "I was envious at the foolish, when I saw the prosperity of the wicked...They are not in trouble as other men."'),
('Psalms', 73, 'teens', 2, 'What did the wicked arrogantly say about God in Psalm 73:11?', '"How doth God know? and is there knowledge in the most High?"', '"God is great and we fear Him"', '"We must obey God always"', '"God will reward us for our deeds"', 'a', 'Psalm 73:11 — The wicked deny that God sees or knows what they do.'),
('Psalms', 73, 'teens', 3, 'What realization changed Asaph''s perspective?', 'He understood their final end — they are set in slippery places and cast down to destruction', 'He received more wealth than them', 'His enemies all died suddenly', 'A prophet explained everything', 'a', 'Psalm 73:17-19 — "Then understood I their end. Surely thou didst set them in slippery places."'),
('Psalms', 73, 'teens', 4, 'What beautiful declaration does Asaph make in Psalm 73:25?', '"Whom have I in heaven but thee? and there is none upon earth that I desire beside thee"', '"The Lord is my shepherd I shall not want"', '"Create in me a clean heart O God"', '"The heavens declare the glory of God"', 'a', 'Psalm 73:25 — One of the most devotional verses in the entire Psalter.'),
('Psalms', 73, 'teens', 5, 'What does Asaph conclude is good for him at the end?', 'Drawing near to God and putting his trust in the Lord', 'Becoming wealthy like the wicked', 'Leaving Israel for a better land', 'Stopping all worship activities', 'a', 'Psalm 73:28 — "But it is good for me to draw near to God: I have put my trust in the Lord GOD."'),
('Psalms', 73, 'adults', 1, 'How does Psalm 73 function as the theological introduction to Book III of the Psalter (Psalms 73-89)?', 'It opens Book III with a crisis of theodicy — the prosperity of the wicked versus the suffering of the righteous — setting the theme for the darkest section of the Psalter, dominated by national lament', 'It is simply the next psalm numerically', 'It introduces temple worship songs', 'It serves as a personal diary with no broader significance', 'a', 'Book III (Ps 73-89) is the darkest section of the Psalter, reflecting exilic crisis. Psalm 73 opens with the foundational theodicy question that frames the entire book, culminating in Psalm 89''s cry over God''s apparent abandonment of the Davidic covenant.'),
('Psalms', 73, 'adults', 2, 'What is the significance of Asaph''s confession "I was as a beast before thee" (Psalm 73:22)?', 'It acknowledges that envying the wicked was sub-rational — reducing himself to animal-level thinking that evaluates life purely by visible material outcomes rather than by faith; the sanctuary visit restored spiritual cognition', 'He literally believed he turned into an animal', 'He is comparing himself to sacrificial animals', 'It is a standard humility formula', 'a', 'Psalm 73:22 — behemoth (beast/brute). Evaluating reality by sight alone (material prosperity) is beastly cognition. The sanctuary (v.17) restores the capacity to see beyond the visible to the eternal.'),
('Psalms', 73, 'adults', 3, 'How does Psalm 73:24 — "Thou shalt guide me with thy counsel, and afterward receive me to glory" — contribute to OT eschatology?', 'The phrase "afterward receive me to glory" suggests post-death reception into God''s glorious presence, providing one of the clearest OT intimations of afterlife hope, parallel to Psalm 49:15 and the Enoch tradition (Gen 5:24, same verb laqach)', 'It refers to receiving earthly honours', 'Glory means military victory', 'The verse only describes guidance in this life', 'a', 'Psalm 73:24 — "afterward receive me to glory." The verb laqach (take/receive) is the same used for Enoch (Gen 5:24). Combined with 73:26 — "my portion for ever" — the psalm envisions permanent relationship with God beyond death.'),
('Psalms', 73, 'adults', 4, 'What does the sanctuary as the epistemological turning point (Psalm 73:17) reveal about worship and understanding?', 'Certain truths are inaccessible through isolated reason and become visible only in the context of worship — communal worship reorients cognition from horizontal comparison to vertical encounter', 'The sanctuary gave Asaph a quiet place to think logically', 'He received a prophetic vision there', 'The sanctuary had scrolls with answers', 'a', 'Psalm 73:16-17 — Reason alone (v.16) produced pain. Worship (v.17) produced understanding. Worship provides an epistemological context that pure reason cannot.'),
('Psalms', 73, 'adults', 5, 'How does Asaph''s movement from envy to supreme devotion parallel the book of Job?', 'Both follow the same trajectory: observing unjust prosperity → crisis of faith → encounter with God → transformed perspective that finds God Himself as the supreme good; both resolve theodicy relationally, not intellectually', 'The two texts have nothing in common', 'Asaph agrees with Job''s friends', 'They address completely different topics', 'a', 'Psalm 73 parallels Job: crisis over the wicked''s prosperity (73:3 ≈ Job 21:7-13), near despair (73:13 ≈ Job 9:22), turning point through encounter (73:17 ≈ Job 42:5), resolution in God Himself (73:25 ≈ Job 42:5-6). Both conclude that God''s presence, not explanations, resolves faith crises.'),
('Psalms', 73, 'adults', 6, 'What is the theological import of "God is the strength of my heart, and my portion for ever" (Psalm 73:26)?', 'By claiming God as his "portion" (cheleq), Asaph uses Levitical inheritance language — the Levites received no land because God was their portion (Num 18:20); this democratizes the Levitical privilege, making God-as-inheritance available to every believer', 'Portion simply means God gives him food', 'It refers to land inheritance', 'It is a conventional formula', 'a', 'Psalm 73:26 — chelqi (my portion). Num 18:20 — "I am thy part and thine inheritance." Asaph extends the Levitical principle: God-as-portion is the highest possible inheritance. Lam 3:24 — "The LORD is my portion, saith my soul."'),
('Psalms', 73, 'adults', 7, 'How does the wicked''s end as "a dream when one awaketh" (Psalm 73:20) inform the psalm''s reality theology?', 'It inverts apparent reality: the wicked''s prosperity that seemed solid is actually the dream, while the righteous sufferer''s relationship with God is true reality — what appears real to observation dissolves, while what appears invisible persists eternally', 'It means the wicked will have nightmares', 'It predicts the wicked will die in sleep', 'It refers to God waking from inattention', 'a', 'Psalm 73:20 — Material prosperity = dream (temporary, illusory). God''s presence = waking reality (permanent). 2 Cor 4:18 — "the things which are seen are temporal; but the things which are not seen are eternal."'),
('Psalms', 73, 'adults', 8, 'What does Asaph''s concern that speaking his doubt would "offend against the generation of thy children" (Psalm 73:15) reveal about faith''s communal dimension?', 'Faith is not purely individual — theological doubt affects the community; Asaph restrains public doubt not from dishonesty but from pastoral responsibility, recognizing his crisis could undermine weaker believers'' faith', 'He feared punishment by authorities', 'He was embarrassed, not concerned for others', 'The generation of God''s children refers to angels', 'a', 'Psalm 73:15 — Asaph holds private doubt and public responsibility in tension. He processes doubt within the sanctuary (v.17) rather than broadcasting it. Cf. Rom 14:13 — "that no man put a stumblingblock...in his brother''s way."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 74, 'kids', 1, 'What sad thing happened to God''s sanctuary in Psalm 74?', 'The enemy destroyed it and set it on fire', 'It was filled with beautiful decorations', 'It was moved to a new city', 'Animals came to live inside it', 'a', 'Psalm 74:3,7 — "The enemy hath done wickedly in the sanctuary...They have cast fire into thy sanctuary."'),
('Psalms', 74, 'kids', 2, 'What powerful things did Asaph say God did to the sea?', 'He divided the sea and broke the dragons'' heads in the waters', 'He made the sea completely dry', 'He turned the sea into fresh water', 'He filled the sea with gold', 'a', 'Psalm 74:13 — "Thou didst divide the sea by thy strength: thou brakest the heads of the dragons in the waters."'),
('Psalms', 74, 'kids', 3, 'What did Asaph ask God to remember?', 'His congregation that He had purchased long ago', 'The songs they sang in the temple', 'The food they offered as sacrifices', 'The walls around the city', 'a', 'Psalm 74:2 — "Remember thy congregation, which thou hast purchased of old."'),
('Psalms', 74, 'teens', 1, 'What complaint does Asaph make about prophetic signs in Psalm 74:9?', '"We see not our signs; there is no more any prophet; neither is there among us any that knoweth how long"', 'There are too many prophets giving contradictory messages', 'The signs are coming too quickly', 'People do not cry loud enough', 'a', 'Psalm 74:9 — A cry of prophetic silence during national catastrophe.'),
('Psalms', 74, 'teens', 2, 'What does Asaph say God established in Psalm 74:16-17?', 'Day and night, the sun, the borders of the earth, summer and winter', 'Only the stars and moon', 'The mountains and valleys', 'The rivers and lakes', 'a', 'Psalm 74:16-17 — "The day is thine, the night also is thine...Thou hast set all the borders of the earth: thou hast made summer and winter."'),
('Psalms', 74, 'teens', 3, 'What does Asaph ask God not to forget in Psalm 74:19?', 'The life of His turtledove — not to deliver it to the wicked', 'The songs of the temple', 'The gold of the treasury', 'The soldiers who fought bravely', 'a', 'Psalm 74:19 — "O deliver not the soul of thy turtledove unto the multitude of the wicked."'),
('Psalms', 74, 'teens', 4, 'What appeal does Asaph make in Psalm 74:22?', '"Arise, O God, plead thine own cause — remember how the foolish man reproaches thee daily"', 'Please send rain upon the crops', 'Build us a new temple', 'Make us the wealthiest nation', 'a', 'Psalm 74:22 — "Arise, O God, plead thine own cause."'),
('Psalms', 74, 'teens', 5, 'What imagery does Psalm 74:5-6 use to describe the temple''s destruction?', 'Enemies lifting axes like chopping thick trees — hacking the carved woodwork', 'A flood washing away the foundations', 'Lightning striking from heaven', 'Earthquakes splitting the walls', 'a', 'Psalm 74:5-6 — "A man was famous according as he had lifted up axes upon the thick trees. But now they break down the carved work thereof."'),
('Psalms', 74, 'adults', 1, 'How does Psalm 74''s reference to God breaking Leviathan''s heads (v.14) connect to Job 41?', 'Both use the Leviathan motif differently: Job 41 presents Leviathan as God''s untameable creature; Psalm 74 recalls God''s historical defeat of chaos at creation/exodus — together they show God as both Creator and Conqueror of chaotic forces', 'The two texts contradict each other', 'Psalm 74 refers to a literal sea creature', 'Both describe the same event at the Red Sea', 'a', 'Psalm 74:13-14 recasts creation/exodus as cosmic victory over chaos. Job 41 shows God governing Leviathan; Psalm 74 remembers God defeating it. Together: God creates, governs, and conquers chaos.'),
('Psalms', 74, 'adults', 2, 'What is the theological significance of "there is no more any prophet" (Psalm 74:9)?', 'It describes prophetic silence where God''s people have no mediating voice — intensifying the lament and anticipating periods of divine silence (e.g., the 400 years between testaments) where faith must persist without fresh revelation', 'The prophets had all died of old age', 'It contradicts other psalms', 'People stopped listening', 'a', 'Psalm 74:9 — Amos 8:11 — "a famine...of hearing the words of the LORD." Prophetic absence during catastrophe creates maximum theological distress: suffering without interpretation.'),
('Psalms', 74, 'adults', 3, 'How does the appeal to covenant (Psalm 74:20) function as the psalm''s theological leverage?', 'By invoking the covenant, Asaph shifts from emotional plea to legal argument — God has bound Himself by covenant, and the temple''s destruction appears to violate it; the appeal is juridical, calling God to account for His own commitments', 'The covenant reference is vague sentiment', 'Asaph negotiates a new covenant', 'It is the Noahic covenant about floods', 'a', 'Psalm 74:20 — "Have respect unto the covenant." The covenant (berit) is the Abrahamic/Davidic covenant. By invoking it, Asaph provides theological grounds for intervention: God''s own faithfulness demands action.'),
('Psalms', 74, 'adults', 4, 'What does the juxtaposition of cosmic creation (vv.13-17) with national destruction (vv.3-8) achieve?', 'A deliberately jarring contrast: the God who split the sea and crushed Leviathan is the same God whose sanctuary lies in ruins — the gap between divine power and present reality IS the lament', 'The creation section is a later insertion', 'It proves God has grown weaker', 'The juxtaposition is accidental', 'a', 'The psalm alternates: destruction (vv.3-8) → silence (v.9) → creation power (vv.13-17) → appeal (vv.18-23). The creation recital is argument: You who did THIS cannot be indifferent to THAT.'),
('Psalms', 74, 'adults', 5, 'How does the turtledove metaphor (Psalm 74:19) illuminate Israel''s self-understanding during crisis?', 'The turtledove is vulnerable, gentle, and covenantally significant (used in sacrifice, Gen 15:9) — Israel sees itself as a fragile bird handed over to predators, with vulnerability language that is both honest and theologically loaded with sacrificial overtones', 'It was Asaph''s favourite bird', 'Doves are common in the region', 'No theological significance', 'a', 'Psalm 74:19 — The tor (turtledove) appears in Abrahamic covenant sacrifice (Gen 15:9), purification offerings (Lev 12:6), and as a love symbol (Song 2:12). Israel as God''s turtledove is simultaneously sacrificial victim, covenant partner, and beloved.'),
('Psalms', 74, 'adults', 6, 'What is the canonical significance of Psalm 74 after the triumph of Psalm 73?', 'Psalm 73''s individual resolution is immediately challenged by collective catastrophe — personal faith must coexist with communal devastation; Book III progressively deepens the tension between individual trust and national crisis toward the Davidic covenant crisis of Psalm 89', 'Placement is purely numerical', 'Psalm 74 undoes Psalm 73', 'Book III has no organizing principle', 'a', 'The sequence: Ps 73 (individual theodicy resolved) → Ps 74 (national faith in crisis). Solving theodicy personally does not eliminate communal suffering. Book III''s arc traces deepening corporate crisis.'),
('Psalms', 74, 'adults', 7, 'How does Psalm 74:12 function as the psalm''s theological fulcrum?', 'It pivots from lament to confidence: "my King" personalizes the sovereign; "of old" appeals to track record; "working salvation in the midst of the earth" insists God acts within history — grounding the creation recital in historical, not merely mythological, categories', 'It is a transition verse with minimal weight', 'It contradicts the lament', 'It refers to an earthly king', 'a', 'Psalm 74:12 — (1) "my King" — personal relationship. (2) "of old" — appeal to precedent. (3) "in the midst of the earth" — God works within creation. This transforms the creation recital from cosmogony to soteriology.'),
('Psalms', 74, 'adults', 8, 'What does "plead thine own cause" (Psalm 74:22) reveal about the nature of Israel''s destruction as a theological problem?', 'It reframes Israel''s suffering as God''s problem: if Israel is destroyed, God''s reputation is mocked; the destruction is not merely humanitarian crisis but crisis of divine honour — God must act for His own name''s sake', 'Asaph selfishly asks God to avenge personal enemies', 'The plea has no theological depth', 'Asaph suggests God needs a lawyer', 'a', 'Psalm 74:22-23 — Ezek 36:22 — "I do not this for your sakes...but for mine holy name''s sake." Asaph deploys the divine-honour argument: Israel''s fate and God''s reputation are inseparable.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 75, 'kids', 1, 'Who holds up the pillars of the earth according to Psalm 75?', 'God holds them up', 'The strongest angels', 'Giant mountains', 'Great tree roots', 'a', 'Psalm 75:3 — "I bear up the pillars of it." God sustains the earth.'),
('Psalms', 75, 'kids', 2, 'What does God tell the wicked not to lift up?', 'Their horn — meaning their proud power', 'Their hands in worship', 'Their voices in song', 'Their feet to dance', 'a', 'Psalm 75:4-5 — "Lift not up the horn." The horn symbolizes proud strength.'),
('Psalms', 75, 'kids', 3, 'What is in God''s hand according to Psalm 75?', 'A cup of wine that the wicked must drink', 'A golden sceptre', 'A sword of fire', 'A book of names', 'a', 'Psalm 75:8 — "For in the hand of the LORD there is a cup, and the wine is red."'),
('Psalms', 75, 'teens', 1, 'Where does promotion and authority come from according to Psalm 75:6-7?', 'Not from east, west, or south — God is the judge who puts down one and sets up another', 'From hard work alone', 'From military victory', 'From popular vote', 'a', 'Psalm 75:6-7 — "Promotion cometh neither from the east, nor from the west, nor from the south. But God is the judge."'),
('Psalms', 75, 'teens', 2, 'What does the cup in God''s hand represent?', 'Divine judgment — the wicked must drink it to the dregs', 'A cup of blessing for the righteous', 'The cup used in temple worship', 'A cup of water for the thirsty', 'a', 'Psalm 75:8 — "the dregs thereof, all the wicked of the earth shall wring them out, and drink them." Cf. Jer 25:15 and Rev 14:10.'),
('Psalms', 75, 'teens', 3, 'When does God say He will judge in Psalm 75:2?', 'When He receives the congregation — at His appointed time He will judge uprightly', 'At the end of every year', 'Only on the Day of Atonement', 'Whenever people ask Him to', 'a', 'Psalm 75:2 — "When I shall receive the congregation I will judge uprightly."'),
('Psalms', 75, 'teens', 4, 'What happens to the horns of the wicked according to Psalm 75:10?', 'All the horns of the wicked will be cut off, but the righteous horn shall be exalted', 'The wicked grow even more powerful', 'Their horns turn to gold', 'They are given to the righteous as trophies', 'a', 'Psalm 75:10 — "All the horns of the wicked also will I cut off; but the horns of the righteous shall be exalted."'),
('Psalms', 75, 'teens', 5, 'What does Asaph promise to do in response to God''s justice?', 'Declare forever and sing praises to the God of Jacob', 'Build a new temple', 'Gather an army against the wicked', 'Fast for forty days', 'a', 'Psalm 75:9 — "But I will declare for ever; I will sing praises to the God of Jacob."'),
('Psalms', 75, 'adults', 1, 'How does the cup metaphor in Psalm 75:8 connect to Christ''s Gethsemane prayer?', 'The judgment cup that the wicked must drink is the same cup Christ asked to pass from Him (Matt 26:39) — He drank the judgment cup on behalf of sinners, transforming the image from judgment on the wicked to substitutionary atonement', 'The cups are completely unrelated', 'Christ''s cup was literal wine', 'The Gethsemane cup is only physical suffering', 'a', 'Psalm 75:8 — judgment cup. Isa 51:17 — "cup of his fury." Matt 26:39 — "let this cup pass from me." Christ willingly drank the judgment cup meant for sinners.'),
('Psalms', 75, 'adults', 2, 'What does the absence of "north" in the list of directions (v.6) suggest theologically?', 'The north is associated with God''s dwelling place in Israelite tradition (Isa 14:13, Ps 48:2); by omitting north, the psalmist implies promotion/judgment comes from God who dwells in the north — the divine direction is excluded because God is the source', 'The north was simply forgotten', 'North was excluded because no one lived there', 'It is a scribal error', 'a', 'Psalm 75:6 — East, west, south listed; north (tsaphon) omitted. Ps 48:2 — "the sides of the north, the city of the great King." Tsaphon was the divine mountain. The omission points to God as the source.'),
('Psalms', 75, 'adults', 3, 'How does God''s first-person speech in Psalm 75:2-5 function within an Asaph psalm?', 'It creates a prophetic oracle embedded within worship — Asaph speaks as God''s mouthpiece, reflecting the Levitical worship leader''s dual role as musician and prophet (1 Chr 25:1-2)', 'God''s speech is a later editorial insertion', 'Asaph imagines what God might say', 'The first-person speech is Asaph himself', 'a', 'God speaks directly in vv.2-5. 1 Chr 25:1 — David set apart Asaph to "prophesy with harps." Asaph''s role was both musical and prophetic — the divine oracle within a psalm reflects the cultic prophet tradition.'),
('Psalms', 75, 'adults', 4, 'What does "I bear up the pillars" (Psalm 75:3) reveal about cosmic stability and divine justice?', 'God''s sustaining of cosmic order is an act of will, not mechanical necessity — the same God who upholds the earth''s pillars also judges at His appointed time; cosmic stability and moral judgment flow from the same sovereign will', 'The pillars are literal geological structures', 'God struggles to hold up the earth', 'It describes Atlas from Greek mythology', 'a', 'Psalm 75:3 — The dissolving earth is social/moral chaos; God''s pillars are cosmic and moral order. Col 1:17 — "by him all things consist." God upholds both physics and ethics.'),
('Psalms', 75, 'adults', 5, 'How does the horn imagery (Psalm 75:4-5, 10) connect to messianic hope in the Psalter?', 'The horn represents power — wicked horns cut off, righteous horns exalted; this develops through the Psalter toward the messianic King (Ps 89:17,24; 132:17) and culminates in Mary''s Magnificat (Luke 1:52,69)', 'Horns are literal animal horns', 'The imagery is unique to Psalm 75', 'Horns represent musical instruments', 'a', 'Psalm 75:10 → Ps 89:17 → Ps 132:17 → Luke 1:69 — "hath raised up an horn of salvation for us." The horn trajectory leads to Christ as the ultimate exalted horn.'),
('Psalms', 75, 'adults', 6, 'What is the literary structure of Psalm 75 and how does it create theological balance?', 'It alternates between human praise (vv.1,9) and divine speech (vv.2-5), with the centre (vv.6-8) providing theological explanation — God alone judges; the chiastic structure frames sovereignty within worship', 'The psalm has no discernible structure', 'It follows chronological narrative', 'The structure is identical to all psalms', 'a', 'Structure: A — thanksgiving (v.1); B — God speaks (vv.2-5); C — Centre: God alone promotes/demotes (vv.6-7); B'' — judgment cup (v.8); A'' — praise (vv.9-10). The chiastic pattern centres on God as sole judge.'),
('Psalms', 75, 'adults', 7, 'How does Psalm 75''s theology of divine timing ("When I shall receive the congregation," v.2) address delayed justice?', 'Justice has an appointed divine schedule that does not conform to human urgency — the apparent delay is human perception, not negligence, anticipating 2 Peter 3:9 where God''s patience is purposeful', 'God is sometimes too late', 'The timing is metaphorical', 'God judges immediately without delay', 'a', 'Psalm 75:2 — The moed (appointed time) is God''s, not ours. Hab 2:3 — "it will surely come, it will not tarry." 2 Pet 3:9 — "The Lord is not slack concerning his promise."'),
('Psalms', 75, 'adults', 8, 'What does "the wine is red; it is full of mixture" (Psalm 75:8) reveal about divine judgment?', 'The spiced wine indicates fully prepared, potent judgment — not diluted; God''s justice is deliberate, thorough, and proportionally crafted, not impulsive', 'The red wine is grape juice', 'The mixture is water to dilute judgment', 'A literal wine recipe', 'a', 'Psalm 75:8 — mesekh = spiced wine for maximum potency. Isa 51:17 — "thou hast drunken the dregs of the cup of trembling." The dregs are the most concentrated — the wicked drain every drop.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 76, 'kids', 1, 'Where is God known and where is His name great?', 'In Judah and in Israel', 'In Egypt and Babylon', 'In the desert and mountains', 'In the sea and sky', 'a', 'Psalm 76:1 — "In Judah is God known: his name is great in Israel."'),
('Psalms', 76, 'kids', 2, 'What did God break in Psalm 76:3?', 'The arrows, shield, sword, and the battle', 'The walls of the enemy city', 'The chains of the prisoners', 'The bread for the hungry', 'a', 'Psalm 76:3 — "There brake he the arrows of the bow, the shield, and the sword, and the battle."'),
('Psalms', 76, 'kids', 3, 'What happened to the horse and chariot riders when God rebuked them?', 'They fell into a dead sleep', 'They rode away very fast', 'They became friendly helpers', 'They hid in the mountains', 'a', 'Psalm 76:6 — "At thy rebuke, O God of Jacob, both the chariot and horse are cast into a dead sleep."'),
('Psalms', 76, 'teens', 1, 'Where are God''s tabernacle and dwelling place according to Psalm 76:2?', 'In Salem (Jerusalem) and in Zion', 'In heaven above the clouds', 'In the temple Solomon built', 'On Mount Sinai', 'a', 'Psalm 76:2 — "In Salem also is his tabernacle, and his dwelling place in Zion."'),
('Psalms', 76, 'teens', 2, 'What happens when God arises to judgment in Psalm 76:8-9?', 'The earth feared and was still — God arose to save the meek of the earth', 'The mountains crumbled', 'Stars fell from the sky', 'All people ran to the temple', 'a', 'Psalm 76:8-9 — "the earth feared, and was still, When God arose to judgment, to save all the meek of the earth."'),
('Psalms', 76, 'teens', 3, 'What does Psalm 76:10 say about the wrath of man?', 'The wrath of man shall praise God — He restrains the remainder of wrath', 'Human anger always leads to good', 'God is powerless against anger', 'Anger is always sinful', 'a', 'Psalm 76:10 — "Surely the wrath of man shall praise thee: the remainder of wrath shalt thou restrain."'),
('Psalms', 76, 'teens', 4, 'What should people do because God is to be feared (Psalm 76:11)?', 'Vow and pay vows unto the LORD — bring presents to Him who ought to be feared', 'Build walls around their cities', 'Gather armies to protect themselves', 'Hide from God in caves', 'a', 'Psalm 76:11 — "Vow, and pay unto the LORD your God: let all that be round about him bring presents unto him that ought to be feared."'),
('Psalms', 76, 'teens', 5, 'What does Psalm 76:12 say God does to rulers?', 'He cuts off the spirit of princes and is terrible to kings of the earth', 'He gives them more power', 'He makes them live forever', 'He turns them into priests', 'a', 'Psalm 76:12 — "He shall cut off the spirit of princes: he is terrible to the kings of the earth."'),
('Psalms', 76, 'adults', 1, 'What is the significance of "Salem" as God''s dwelling in Psalm 76:2?', 'Salem connects Zion to Melchizedek''s pre-Davidic city (Gen 14:18) — the name means "peace," establishing Jerusalem as the place of God''s shalom with universal theological significance beyond tribal boundaries', 'Salem is a different city from Jerusalem', 'The name has no etymological significance', 'It refers to a heavenly city', 'a', 'Psalm 76:2 — Gen 14:18 — "Melchizedek king of Salem." Heb 7:2 — "King of Salem, which is, King of peace." The Melchizedek-Salem connection makes Zion''s priesthood older than Levi.'),
('Psalms', 76, 'adults', 2, 'How does "the wrath of man shall praise thee" (Psalm 76:10) articulate divine sovereignty over evil?', 'Even hostile human actions ultimately serve God''s purposes — wrath intended to destroy becomes the occasion for glory; human evil is repurposed within divine governance, as in Joseph (Gen 50:20) and the cross (Acts 2:23)', 'It means angry worship is acceptable', 'Human wrath is always praiseworthy', 'God causes human wrath', 'a', 'Gen 50:20 — "ye thought evil...but God meant it unto good." Acts 2:23 — "by wicked hands have crucified and slain" yet "by the determinate counsel of God." Human evil is real, culpable, and yet sovereignly governed.'),
('Psalms', 76, 'adults', 3, 'What does the "dead sleep" of horse and chariot (Psalm 76:6) evoke in Israel''s history?', 'The Red Sea victory where Egypt''s chariots were rendered powerless by divine intervention — radam (supernatural stupor) suggests divine causation; the psalm uses exodus language to celebrate God''s ongoing power against military might', 'It describes a literal sleeping spell on animals', 'Normal nighttime rest', 'A metaphor for diplomatic negotiations', 'a', 'Psalm 76:6 — radam (deep sleep). The chariot-and-horse motif: Ex 15:1 — "the horse and his rider hath he thrown into the sea." Every military victory is re-enactment of the exodus.'),
('Psalms', 76, 'adults', 4, 'How does Psalm 76''s divine warrior-judge contribute to Book III''s theology of transcendence?', 'God is supremely powerful — more glorious than mountains of prey, silencing the earth, cutting off princes; this transcendence serves Book III''s argument that the God who seems absent from Israel''s crisis is actually sovereign over all earthly power', 'The warrior imagery contradicts God''s peaceful nature', 'Book III has no transcendence theology', 'God is portrayed as one king among many', 'a', 'Psalm 76: more glorious than mountains (v.4), silences earth (v.8), governs wrath (v.10), terrifies kings (v.12). Within Book III''s crisis context, this transcendence insists: the God who allows crisis is not weak.'),
('Psalms', 76, 'adults', 5, 'What is the theological function of "the earth feared, and was still" (Psalm 76:8)?', 'The still earth functions as the silenced courtroom when the Judge arises — creation becomes hushed witness to divine verdict; God''s judgment is universal, affecting all creation and silencing all protest', 'The earth literally stopped rotating', 'It describes an earthquake', 'Nothing unusual happened', 'a', 'Cf. Hab 2:20 — "let all the earth keep silence before him." Zech 2:13 — "Be silent, O all flesh, before the LORD." Cosmic silence before divine judgment is a recurring motif: creation yields to the Judge.'),
('Psalms', 76, 'adults', 6, 'What specific historical event may Psalm 76 celebrate?', 'Sennacherib''s defeat — 2 Kings 19:35 describes the angel of the LORD smiting 185,000 Assyrians in their sleep, paralleling "the stouthearted are spoiled, they have slept their sleep" (v.5)', 'It was composed for royal banquets', 'It had no historical referent', 'It was a private meditation', 'a', 'Psalm 76:5 — "the stouthearted are spoiled, they have slept their sleep." 2 Kings 19:35 — "when they arose early in the morning, behold, they were all dead corpses." The parallels suggest Sennacherib''s miraculous defeat.'),
('Psalms', 76, 'adults', 7, 'What does "bring presents unto him that ought to be feared" (Psalm 76:11) reveal about fear and worship?', 'Fear of God is not the opposite of worship but its prerequisite — the God who terrifies kings is the God to whom offerings are brought; true worship is impossible without proper fear, and proper fear naturally produces worship', 'Fear and worship are opposites', 'Bringing presents is bribery', 'The command applies only to foreigners', 'a', 'Psalm 76:11-12 — Worship because He is feared. Prov 1:7 — "The fear of the LORD is the beginning of knowledge." Heb 12:28 — "serve God acceptably with reverence and godly fear." Biblical fear draws near, not away.'),
('Psalms', 76, 'adults', 8, 'How does Psalm 76''s theology of saving "all the meek of the earth" (v.9) contribute to the biblical theme of divine preference for the humble?', 'God''s judicial intervention specifically targets the rescue of the meek (anavim) — divine power is exercised preferentially toward the powerless; this runs through the Psalter and peaks in the Beatitudes (Matt 5:5)', 'God saves all people equally', 'The meek is a specific tribe', 'Saving the meek is secondary to demonstrating power', 'a', 'Ps 37:11 — "the meek shall inherit the earth." Ps 147:6 — "The LORD lifteth up the meek." Matt 5:5 — "Blessed are the meek." The divine preferential option for the meek runs from Psalms to Beatitudes.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 77, 'kids', 1, 'What did Asaph do all night when he was sad?', 'He stretched out his hand to God and his sore ran in the night', 'He slept peacefully', 'He played music for the king', 'He read scrolls by candlelight', 'a', 'Psalm 77:2 — "In the day of my trouble I sought the Lord: my sore ran in the night, and ceased not."'),
('Psalms', 77, 'kids', 2, 'What did Asaph remember to make himself feel better?', 'God''s wonders and works from long ago', 'His favourite childhood stories', 'The feasts and celebrations', 'Songs his mother sang to him', 'a', 'Psalm 77:11 — "I will remember the works of the LORD: surely I will remember thy wonders of old."'),
('Psalms', 77, 'kids', 3, 'What great event does Asaph recall God doing to the waters?', 'The waters saw God and were afraid — He led His people through the sea', 'He made the waters turn sweet', 'He filled the waters with fish', 'He made the waters stand still forever', 'a', 'Psalm 77:16,20 — "The waters saw thee, O God, the waters saw thee; they were afraid...Thou leddest thy people like a flock."'),
('Psalms', 77, 'teens', 1, 'What anguished questions does Asaph ask in Psalm 77:7-9?', '"Will the Lord cast off for ever? Is his mercy clean gone? Hath God forgotten to be gracious?"', '"When will God send rain for the crops?"', '"Why do the wicked live so long?"', '"How many stars are in the sky?"', 'a', 'Psalm 77:7-9 — A series of questions about whether God has permanently abandoned His people.'),
('Psalms', 77, 'teens', 2, 'What turning point occurs in Psalm 77:10-11?', 'Asaph decides to remember God''s works and wonders of old, shifting from despair to remembrance', 'Asaph receives a visit from an angel', 'God speaks audibly to Asaph', 'The enemies of Israel are defeated', 'a', 'Psalm 77:10-11 — "I will remember the works of the LORD: surely I will remember thy wonders of old." Memory of God''s past faithfulness breaks the spiral of despair.'),
('Psalms', 77, 'teens', 3, 'How does Asaph describe God''s path through the sea in Psalm 77:19?', '"Thy way is in the sea, and thy path in the great waters, and thy footsteps are not known"', '"Thy way is on the mountain and thy path in the forest"', '"Thy way is in the heavens and thy path among the stars"', '"Thy way is in the desert and thy path in the sand"', 'a', 'Psalm 77:19 — God''s way through the sea was real but invisible — His footsteps left no trace in the water.'),
('Psalms', 77, 'teens', 4, 'Who does Asaph say led Israel like a flock?', 'Moses and Aaron', 'Joshua and Caleb', 'Abraham and Isaac', 'David and Solomon', 'a', 'Psalm 77:20 — "Thou leddest thy people like a flock by the hand of Moses and Aaron."'),
('Psalms', 77, 'teens', 5, 'What does Asaph meditate on during his sleepless night?', 'His song in the night — he communes with his own heart and his spirit searches', 'Plans for building the temple', 'Ways to defeat his enemies', 'The laws of Moses', 'a', 'Psalm 77:6 — "I call to remembrance my song in the night: I commune with mine own heart: and my spirit made diligent search."'),
('Psalms', 77, 'adults', 1, 'How does Psalm 77 model the movement from existential crisis to theological resolution?', 'The psalm divides into lament (vv.1-9) and remembrance (vv.10-20) — the turning point is a deliberate act of memory; resolution comes not through new revelation but through recollecting known acts of God, making historical memory the antidote to present despair', 'The psalm offers no resolution', 'The crisis is solved by material blessing', 'A prophet arrives to explain everything', 'a', 'Psalm 77:10-11 marks the pivot: "I will remember." The structure: present crisis (vv.1-9) → deliberate remembrance (vv.10-12) → exodus recital (vv.13-20). Historical memory functions as epistemological therapy.'),
('Psalms', 77, 'adults', 2, 'What does "thy footsteps are not known" (Psalm 77:19) reveal about divine providence?', 'God acts powerfully (parting the sea) yet inscrutably (footsteps invisible) — divine providence is real but its mechanics are hidden; we see the effects (Israel crossed) but not the process; this affirms both God''s intervention and its mystery simultaneously', 'God literally has invisible feet', 'It means God was not present at the Red Sea', 'The verse describes normal wave patterns', 'a', 'Psalm 77:19 — "thy path in the great waters, and thy footsteps are not known." The paradox: the most dramatic divine intervention (Red Sea) left no visible trace. Providence is real but invisible. Rom 11:33 — "how unsearchable are his judgments, and his ways past finding out!"'),
('Psalms', 77, 'adults', 3, 'How does the theophanic storm description in Psalm 77:16-18 transform the exodus narrative?', 'It recasts the Red Sea crossing in cosmic/theophanic terms — waters afraid, clouds pouring, thunder, lightning, earthquake — elevating a historical event to cosmic significance; the exodus was not merely political liberation but a theophanic encounter where creation itself responded to God''s presence', 'It describes a different event from the exodus', 'The storm language is purely metaphorical', 'It contradicts the Exodus account', 'a', 'Psalm 77:16-18 — waters "afraid" (chul), arrows/thunder/lightning/earthquake. The exodus is retold as theophany: nature responds to God''s passage. This cosmic retelling reveals that every divine act in history has cosmic dimensions.'),
('Psalms', 77, 'adults', 4, 'What is the significance of the series of rhetorical questions in Psalm 77:7-9?', 'The questions articulate the darkest possibilities of faith: permanent rejection, mercy exhausted, promises failed, grace forgotten; by voicing these fears explicitly, the psalm validates honest spiritual darkness and demonstrates that questioning God is part of legitimate faith rather than its antithesis', 'The questions are rhetorical tricks with no real feeling', 'Asaph expects literal answers to each question', 'The questions prove Asaph has lost his faith', 'a', 'Psalm 77:7-9 — Seven questions (some count six) systematically explore worst-case theological scenarios. By naming the fears, the psalm prevents them from remaining unnamed anxieties. The voicing itself is therapeutic — and the rest of the psalm (vv.10-20) provides implicit answers through remembered faithfulness.'),
('Psalms', 77, 'adults', 5, 'How does "thy way, O God, is in the sanctuary" (Psalm 77:13) connect to Psalm 73:17?', 'Both psalms locate understanding of God''s ways in the sanctuary — Psalm 73:17 ("until I went into the sanctuary of God") and 77:13 both affirm that God''s way becomes comprehensible in worship, not in isolated reflection; the sanctuary is the epistemological locus where God''s governance makes sense', 'The two verses are coincidentally similar', 'Psalm 77 refers to a different sanctuary', 'The sanctuary means the desert tabernacle only', 'a', 'Psalm 73:17 + 77:13 — both Asaph psalms that locate divine comprehension in the sanctuary. This is a consistent Asaphite epistemology: worship is where God''s ways become understandable. Outside the sanctuary = confusion; inside = clarity.'),
('Psalms', 77, 'adults', 6, 'What does the shepherd-flock imagery in Psalm 77:20 contribute to the psalm''s theological resolution?', 'After cosmic theophany (vv.16-18), the psalm ends with intimate pastoral imagery — God who terrifies the waters also tenderly leads His flock; the juxtaposition of cosmic power and pastoral care reveals a God who is simultaneously sovereign and intimate', 'The flock imagery is a cliché with no theological weight', 'It reduces God to a mere shepherd', 'The flock refers to literal sheep, not Israel', 'a', 'Psalm 77:20 — "Thou leddest thy people like a flock by the hand of Moses and Aaron." After thunderbolts, arrows, and earthquakes (vv.17-18), the psalm resolves with a shepherd leading sheep. Cosmic warrior = tender shepherd. John 10:11 — "I am the good shepherd." The same Christ who holds all power leads with pastoral care.'),
('Psalms', 77, 'adults', 7, 'How does Asaph''s "song in the night" (Psalm 77:6) function in the psalm''s emotional-spiritual progression?', 'The night song is a fragment of remembered worship that breaks through the darkness — even in sleepless anguish, a remembered song triggers the deliberate act of memory that transforms the psalm; worship residue from better times becomes the catalyst for renewed faith', 'The song is a lullaby he sings to fall asleep', 'Night songs are pagan rituals Asaph is rejecting', 'The song has no function in the psalm''s structure', 'a', 'Psalm 77:6 — "I call to remembrance my song in the night." Cf. Job 35:10 — "God my maker, who giveth songs in the night." Acts 16:25 — Paul and Silas singing at midnight. The night song is worship''s persistence in darkness — a seed from which full remembrance (vv.11-20) can grow.'),
('Psalms', 77, 'adults', 8, 'What does Psalm 77''s structure suggest about the relationship between theological crisis and historical memory in Israelite faith?', 'The psalm demonstrates that Israelite faith is fundamentally historical — when present experience contradicts theology (vv.1-9), the remedy is not philosophical argument but historical recollection (vv.10-20); God''s character is known through His acts, and remembered acts sustain faith when present circumstances threaten it', 'Historical memory is irrelevant to present faith', 'The psalm suggests forgetting the past and focusing on the present', 'Philosophical argument is superior to historical memory', 'a', 'The psalm''s two halves model Israel''s faith method: crisis → remember → resolve. Deut 6:12 — "beware lest thou forget the LORD, which brought thee forth." The exodus is not merely history but living memory that sustains present faith. The Lord''s Supper ("do this in remembrance of me") extends this principle.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 78, 'kids', 1, 'What does Asaph say parents should tell their children?', 'The praises of the LORD and His wonderful works', 'Stories about faraway lands', 'How to become wealthy', 'Rules for playing games', 'a', 'Psalm 78:4 — "We will not hide them from their children, shewing to the generation to come the praises of the LORD."'),
('Psalms', 78, 'kids', 2, 'What food did God rain down from heaven for the Israelites?', 'Manna — the bread of heaven', 'Figs and dates', 'Roasted lamb', 'Fresh vegetables', 'a', 'Psalm 78:24 — "And had rained down manna upon them to eat, and had given them of the corn of heaven."'),
('Psalms', 78, 'kids', 3, 'Which tribe and person did God choose at the end of Psalm 78?', 'The tribe of Judah and David His servant', 'The tribe of Levi and Moses', 'The tribe of Benjamin and Saul', 'The tribe of Ephraim and Joshua', 'a', 'Psalm 78:68,70 — "But chose the tribe of Judah...He chose David also his servant, and took him from the sheepfolds."'),
('Psalms', 78, 'teens', 1, 'What is the purpose of Psalm 78 according to its opening verses?', 'To teach the next generation God''s works so they would set their hope in God and not forget His deeds or be like their stubborn fathers', 'To record Israel''s military victories', 'To list the genealogy of David', 'To describe the temple''s construction', 'a', 'Psalm 78:6-8 — "That the generation to come might know them...that they might set their hope in God...And might not be as their fathers, a stubborn and rebellious generation."'),
('Psalms', 78, 'teens', 2, 'Which tribe is specifically criticised for turning back in the day of battle?', 'The children of Ephraim', 'The children of Judah', 'The children of Levi', 'The children of Dan', 'a', 'Psalm 78:9 — "The children of Ephraim, being armed, and carrying bows, turned back in the day of battle."'),
('Psalms', 78, 'teens', 3, 'What miracles in the wilderness does Psalm 78 recall?', 'Splitting the rock for water, manna from heaven, and quail for meat', 'Parting the Jordan River', 'Making the sun stand still', 'Bringing down the walls of Jericho', 'a', 'Psalm 78:15-16,24-27 — Water from the rock, manna from heaven, and quails blown in by wind.'),
('Psalms', 78, 'teens', 4, 'What plagues on Egypt does Psalm 78 mention?', 'Flies, frogs, hail, locusts, and the death of the firstborn', 'Only the plague of darkness', 'Only the parting of the Red Sea', 'Earthquakes and volcanic eruptions', 'a', 'Psalm 78:44-51 — The psalm recounts several Egyptian plagues: blood (v.44), flies (v.45), frogs (v.45), locusts (v.46), hail (v.47-48), and death of firstborn (v.51).'),
('Psalms', 78, 'teens', 5, 'How does Psalm 78 describe David''s shepherding of Israel?', 'He fed them according to the integrity of his heart and guided them by the skilfulness of his hands', 'He conquered all their enemies with great armies', 'He built them a magnificent temple', 'He wrote the law for them to follow', 'a', 'Psalm 78:72 — "So he fed them according to the integrity of his heart; and guided them by the skilfulness of his hands."'),
('Psalms', 78, 'adults', 1, 'What is the genre and function of Psalm 78 within the Psalter?', 'It is a historical psalm (maskil) that uses salvation history as pedagogical material — recounting Israel''s cycle of rebellion and grace to teach subsequent generations; it functions as catechetical instruction embedding theology within narrative', 'It is a hymn of praise with no historical content', 'It is a personal lament about Asaph''s suffering', 'It is a royal coronation psalm', 'a', 'Psalm 78:1 — "Give ear, O my people, to my law (torah): incline your ears to the words of my mouth." The psalm uses narrative theology — teaching through story. Jesus references this method in Matt 13:35 — "I will open my mouth in parables; I will utter things which have been kept secret."'),
('Psalms', 78, 'adults', 2, 'How does Jesus'' quotation of Psalm 78:2 in Matthew 13:35 reinterpret the psalm?', 'Jesus applies Asaph''s teaching method to His own parabolic ministry — "I will open my mouth in parables" — identifying Himself as the ultimate teacher who reveals hidden things; this Christological reading makes all of salvation history (Psalm 78''s content) a parable pointing to Christ', 'Matthew''s quotation is a coincidence', 'Jesus is simply using a teaching technique', 'The connection is forced by later editors', 'a', 'Psalm 78:2 — "I will open my mouth in a parable: I will utter dark sayings of old." Matt 13:35 — applied to Jesus'' parables. Matthew sees Jesus as fulfilling the Asaphite pedagogical tradition: all salvation history is a "parable" whose hidden meaning is Christ.'),
('Psalms', 78, 'adults', 3, 'What is the theological significance of the psalm''s cycle of sin-judgment-mercy repeated throughout Israel''s history?', 'The cycle (rebel → punish → cry → deliver → rebel again) reveals both the persistence of human sin and the greater persistence of divine mercy — grace always outlasts rebellion; the cycle is not vicious but progressive, moving toward the election of David (vv.70-72) as God''s definitive answer', 'The cycle proves God is inconsistent', 'It shows Israel was worse than all other nations', 'The repetition is poor writing', 'a', 'The cycle repeats throughout Psalm 78: wilderness rebellion (vv.17-41), continued unfaithfulness in Canaan (vv.56-64), until God''s election of Judah and David (vv.68-72) breaks the pattern. Divine patience outlasts human rebellion. Rom 5:20 — "where sin abounded, grace did much more abound."'),
('Psalms', 78, 'adults', 4, 'How does the criticism of Ephraim (Psalm 78:9-11) function in the psalm''s narrative arc?', 'The Ephraim reference sets up the psalm''s conclusion: God rejected the tabernacle of Shiloh (in Ephraim, v.60) and chose Judah/Zion/David instead (vv.67-72) — the psalm traces the transfer of divine election from the northern to the southern tribe, legitimating the Davidic dynasty', 'Ephraim is criticised for unrelated military failures', 'The reference is to a minor border skirmish', 'Ephraim is praised for their bravery', 'a', 'Psalm 78:9-11 (Ephraim''s failure) → v.60 (Shiloh abandoned) → v.67 (Ephraim rejected) → v.68 (Judah chosen) → v.70 (David chosen). The narrative arc legitimates the transition from Shiloh to Zion, from Ephraim to Judah, from Saul to David.'),
('Psalms', 78, 'adults', 5, 'What does the description of God as "wrathful" yet "compassionate" (Psalm 78:38-39) reveal about the divine character?', 'God holds justice and mercy simultaneously — "he, being full of compassion, forgave their iniquity...For he remembered that they were but flesh" — divine wrath is real but restrained by divine compassion; God''s knowledge of human frailty (flesh/wind) moderates His just anger', 'God alternates between wrath and compassion randomly', 'Compassion cancels out wrath entirely', 'The attributes contradict each other', 'a', 'Psalm 78:38-39 — "But he, being full of compassion, forgave their iniquity, and destroyed them not...For he remembered that they were but flesh; a wind that passeth away, and cometh not again." Divine anthropology informs divine response: God''s knowledge of human fragility tempers His justice with mercy.'),
('Psalms', 78, 'adults', 6, 'How does the abandonment of Shiloh (Psalm 78:60-64) function as a warning within Israel''s theology?', 'It establishes that no sacred site is immune from divine judgment — if God abandoned Shiloh (His first dwelling), He can abandon any place, including the Jerusalem temple; Jeremiah explicitly uses this precedent (Jer 7:12-14) to warn Jerusalem', 'Shiloh was destroyed by an earthquake, not divine judgment', 'The passage has no connection to later prophetic warnings', 'Shiloh is mentioned only for historical completeness', 'a', 'Psalm 78:60 — "he forsook the tabernacle of Shiloh." Jer 7:12-14 — "go ye now unto my place which was in Shiloh...and see what I did to it...Therefore will I do unto this house." Shiloh''s destruction serves as permanent warning: sacred space is not unconditionally guaranteed.'),
('Psalms', 78, 'adults', 7, 'What does the ending of Psalm 78 — David shepherding with "integrity of heart" and "skilfulness of hands" (v.72) — reveal about the ideal of biblical leadership?', 'Ideal leadership requires both moral character (integrity/tom, wholeness) and practical competence (skilfulness/tevunah, understanding) — neither alone is sufficient; David embodies the integration of character and skill that makes him the standard against which all subsequent leaders are measured', 'Only integrity matters for leadership', 'Only skill matters for leadership', 'The verse describes David''s pre-royal shepherding career only', 'a', 'Psalm 78:72 — tom levavo (integrity of heart) + tevunot kappav (skilfulness of hands). Tom = wholeness, moral completeness. Tevunah = insight, practical wisdom. Biblical leadership demands both character AND competence — the union of who you are and what you can do. Christ fulfills this perfectly (Heb 7:26 + Col 2:3).'),
('Psalms', 78, 'adults', 8, 'How does Psalm 78''s pedagogical purpose (teaching children, v.5-6) relate to Deuteronomy''s educational mandate?', 'Both share the conviction that faith is transmitted through deliberate intergenerational instruction — Psalm 78:5-6 echoes Deut 6:6-7 ("teach them diligently unto thy children"); the psalm enacts this mandate by providing the actual content (salvation history) that parents are to transmit', 'The psalm has no connection to Deuteronomy', 'Teaching children is mentioned only as a side point', 'The educational mandate was for priests only', 'a', 'Psalm 78:5-6 — "he commanded our fathers, that they should make them known to their children." Deut 6:6-7 — "these words...thou shalt teach them diligently unto thy children." The psalm both commands intergenerational transmission AND provides the curriculum (Israel''s history with God).');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 79, 'kids', 1, 'What happened to Jerusalem in Psalm 79?', 'The heathen came in and destroyed God''s temple and the city', 'It was decorated with gold', 'A great feast was held there', 'New walls were built around it', 'a', 'Psalm 79:1 — "O God, the heathen are come into thine inheritance; thy holy temple have they defiled; they have laid Jerusalem on heaps."'),
('Psalms', 79, 'kids', 2, 'What did Asaph ask God to do with their sins?', 'Not remember them — show tender mercies instead', 'Write them down in a book', 'Tell them to the nations', 'Punish them for every single one', 'a', 'Psalm 79:8 — "O remember not against us former iniquities: let thy tender mercies speedily prevent us."'),
('Psalms', 79, 'kids', 3, 'What did Asaph promise the people would do if God saved them?', 'Give thanks forever and show forth His praise to all generations', 'Build the biggest temple ever', 'Never sin again', 'Conquer all their enemies', 'a', 'Psalm 79:13 — "So we thy people and sheep of thy pasture will give thee thanks for ever: we will shew forth thy praise to all generations."'),
('Psalms', 79, 'teens', 1, 'What has happened to the bodies of God''s servants according to Psalm 79:2-3?', 'Given to beasts and birds — their blood poured out like water around Jerusalem with no one to bury them', 'They were carried away as captives', 'They were burned in a fire', 'They were buried with great honour', 'a', 'Psalm 79:2-3 — "The dead bodies of thy servants have they given to be meat unto the fowls of the heaven...their blood have they shed like water round about Jerusalem."'),
('Psalms', 79, 'teens', 2, 'What does Asaph ask God to pour out on the nations?', 'His wrath upon the heathen that have not known God and upon kingdoms that have not called upon His name', 'Blessings and peace', 'Rain for their crops', 'Wisdom and understanding', 'a', 'Psalm 79:6 — "Pour out thy wrath upon the heathen that have not known thee, and upon the kingdoms that have not called upon thy name."'),
('Psalms', 79, 'teens', 3, 'Why does Asaph say God should help them?', 'For the glory of His name — to help, deliver, and purge their sins for His name''s sake', 'Because they have always been perfectly obedient', 'Because they offered enough sacrifices', 'Because they are wealthier than other nations', 'a', 'Psalm 79:9 — "Help us, O God of our salvation, for the glory of thy name: and deliver us, and purge away our sins, for thy name''s sake."'),
('Psalms', 79, 'teens', 4, 'What taunting question do the nations ask according to Psalm 79:10?', '"Where is their God?"', '"Why is their temple so small?"', '"When will they surrender?"', '"How long will they resist?"', 'a', 'Psalm 79:10 — "Wherefore should the heathen say, Where is their God?" The nations mock Israel''s God because of their defeat.'),
('Psalms', 79, 'teens', 5, 'What does Asaph ask God to preserve in Psalm 79:11?', 'Those who are appointed to die — the prisoners and condemned', 'The temple treasures', 'The royal family', 'The city walls', 'a', 'Psalm 79:11 — "Let the sighing of the prisoner come before thee; according to the greatness of thy power preserve thou those that are appointed to die."'),
('Psalms', 79, 'adults', 1, 'How does Psalm 79 parallel Psalm 74 and what does the repetition achieve?', 'Both lament the temple''s destruction from different angles — Psalm 74 focuses on God''s creative power as grounds for intervention, while Psalm 79 emphasises the nations'' mockery and God''s honour; the repetition within Book III creates cumulative weight, refusing to let the crisis be quickly resolved in the reader''s mind', 'They are accidentally similar', 'Psalm 79 is a copy of Psalm 74', 'The repetition serves no purpose', 'a', 'Psalm 74: focus on divine power and covenant. Psalm 79: focus on national disgrace and divine honour. Together they represent the communal trauma from multiple perspectives, preventing facile theological resolution.'),
('Psalms', 79, 'adults', 2, 'What does the appeal "for thy name''s sake" (Psalm 79:9) reveal about the psalm''s theology of divine motivation?', 'It appeals to God''s own reputation rather than Israel''s merit — God should act because His honour is at stake when His people are defeated; this "name theology" makes God''s glory, not human worthiness, the ultimate ground of salvation', 'It is a polite formula with no theological content', 'It means Israel deserves rescue for their faithfulness', 'It refers to a specific divine name that has magical power', 'a', 'Psalm 79:9 — "for the glory of thy name...for thy name''s sake." Ezek 36:22 — "I do not this for your sakes...but for mine holy name''s sake." The appeal to divine honour is the most powerful prayer argument: God''s glory demands intervention regardless of human merit.'),
('Psalms', 79, 'adults', 3, 'How does the unburied-dead imagery (Psalm 79:2-3) intensify the lament beyond mere military defeat?', 'In ancient Israelite culture, unburied dead was the ultimate dishonour — denial of proper burial meant the dead were treated as non-persons; giving bodies to beasts and birds violated the basic dignity of the covenant community and constituted a cosmic affront to God whose people were desecrated', 'The imagery is conventional war poetry with no special significance', 'Unburied dead was common and unremarkable', 'The passage describes animal sacrifices, not human bodies', 'a', 'Psalm 79:2-3 — bodies given to "fowls of the heaven...flesh of thy saints unto the beasts of the earth." Deut 28:26 — "thy carcase shall be meat unto all fowls of the air" — a covenant curse. The unburied dead signal that covenant curses have been activated, making this the worst possible national catastrophe.'),
('Psalms', 79, 'adults', 4, 'What does the nations'' taunt "Where is their God?" (Psalm 79:10) reveal about ancient Near Eastern theology?', 'In ANE theology, a nation''s defeat proved their god''s weakness — the taunt challenges YHWH''s power and existence based on Israel''s visible defeat; the psalmist turns this challenge back by making it God''s problem to solve: God must act to vindicate His own name before the nations', 'The question is merely rhetorical with no theological weight', 'It proves that the nations were correct about God', 'The taunt is directed at Israel''s priests, not their God', 'a', 'Psalm 79:10 — "Where is their God?" Cf. Joel 2:17, Ps 42:3,10, Ps 115:2. In ANE worldview, military defeat = divine defeat. The psalmist weaponizes the taunt: if God''s honour is at stake, God must respond. The taunt becomes a prayer lever.'),
('Psalms', 79, 'adults', 5, 'How does the "sevenfold into their bosom" request (Psalm 79:12) relate to the lex talionis?', 'Sevenfold surpasses the lex talionis (equal retaliation) and echoes Gen 4:15 (Cain''s sevenfold vengeance) — the request is for overwhelming divine justice that makes the punishment exceed proportional retribution; this hyperbolic justice-language expresses the depth of trauma rather than prescribing literal vengeance', 'Sevenfold is literal mathematical calculation', 'It refers to seven specific punishments', 'The request is moderate and proportional', 'a', 'Psalm 79:12 — "render unto our neighbours sevenfold into their bosom their reproach." Gen 4:15 — Cain''s sevenfold vengeance. The language is hyperbolic: trauma demands expression beyond proportional justice. The imprecatory element voices honest anguish while leaving actual vengeance to God (Rom 12:19).'),
('Psalms', 79, 'adults', 6, 'What does the self-description "sheep of thy pasture" (Psalm 79:13) contribute to the psalm''s concluding theology?', 'It returns to the shepherd-flock relationship — after all the violence and desecration, the people affirm their identity as God''s flock; this relational claim functions as both appeal (a good shepherd protects his sheep) and commitment (we belong to You and will praise You forever)', 'It means Israel raises sheep for a living', 'The sheep imagery is a cliché', 'It describes only the Levitical priests', 'a', 'Psalm 79:13 — "we thy people and sheep of thy pasture." After bloody imagery of unburied dead (vv.2-3), the psalm ends with pastoral warmth: we are still Your sheep. The shepherd-flock metaphor reclaims relationship after catastrophe. Cf. Psalm 23, John 10:27-28.'),
('Psalms', 79, 'adults', 7, 'How does Psalm 79:8''s plea "remember not against us former iniquities" balance the psalm''s imprecatory elements?', 'While asking God to judge the nations (vv.6-7,12), the psalmist simultaneously acknowledges Israel''s own sin (v.8-9) — the prayer for vengeance is not self-righteous but comes from a community that confesses its own guilt; this balance prevents the imprecation from becoming triumphalism', 'The acknowledgment of sin is merely formulaic', 'It contradicts the imprecatory verses', 'Asaph believes Israel is sinless', 'a', 'Psalm 79:8-9 — "remember not against us former iniquities...purge away our sins." Combined with vv.6-7,12 (judgment on nations). The psalmist holds both truths: Israel sinned AND the nations overstepped. This dual acknowledgment prevents imprecation from becoming self-righteousness.'),
('Psalms', 79, 'adults', 8, 'What is the eschatological dimension of Psalm 79 and how does Revelation draw on its imagery?', 'Psalm 79''s imagery of blood poured out around Jerusalem, bodies given to beasts, and nations taunting "Where is their God?" echoes through Revelation''s bowls of wrath (Rev 16), the cry of martyrs "How long?" (Rev 6:10), and the vindication of God''s honour before all nations', 'Revelation does not reference any psalms', 'Psalm 79 has no eschatological dimension', 'The connections are too vague to be meaningful', 'a', 'Psalm 79:5 "How long, LORD?" → Rev 6:10 "How long, O Lord...dost thou not judge and avenge our blood?" Psalm 79:10 "Where is their God?" → Rev 11:17-18 God''s vindication before nations. The psalm''s communal trauma becomes eschatological template for the final reckoning.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 80, 'kids', 1, 'What does Asaph compare Israel to in Psalm 80?', 'A vine that God brought out of Egypt and planted', 'A tall cedar tree', 'A mighty river', 'A flock of birds', 'a', 'Psalm 80:8 — "Thou hast brought a vine out of Egypt: thou hast cast out the heathen, and planted it."'),
('Psalms', 80, 'kids', 2, 'What does Asaph ask God to do three times in this psalm?', 'Turn us again and cause thy face to shine, and we shall be saved', 'Send us food from heaven', 'Build us a new temple', 'Give us a new king', 'a', 'Psalm 80:3,7,19 — The refrain "Turn us again, O God, and cause thy face to shine; and we shall be saved" appears three times.'),
('Psalms', 80, 'kids', 3, 'What animals does Asaph say are destroying God''s vine?', 'The boar from the forest and wild beasts of the field', 'Lions and bears', 'Eagles and hawks', 'Snakes and scorpions', 'a', 'Psalm 80:13 — "The boar out of the wood doth waste it, and the wild beast of the field doth devour it."'),
('Psalms', 80, 'teens', 1, 'What title for God does Psalm 80 open with?', '"O Shepherd of Israel" — the one who leads Joseph like a flock', 'O King of kings', 'O Creator of heaven and earth', 'O Judge of all the earth', 'a', 'Psalm 80:1 — "Give ear, O Shepherd of Israel, thou that leadest Joseph like a flock."'),
('Psalms', 80, 'teens', 2, 'How far did the vine grow according to Psalm 80:10-11?', 'Its shadow covered the hills, its branches reached the great cedars, its boughs reached the sea and the river', 'It only grew in one small garden', 'It reached the height of the temple', 'It filled only the land of Judah', 'a', 'Psalm 80:10-11 — "The hills were covered with the shadow of it...She sent out her boughs unto the sea, and her branches unto the river."'),
('Psalms', 80, 'teens', 3, 'What does Asaph ask God to look down from heaven and do?', 'Visit this vine, behold and protect it — the vineyard thy right hand hath planted', 'Count the stars above', 'Send rain upon the land', 'Move the mountains', 'a', 'Psalm 80:14-15 — "Return, we beseech thee, O God of hosts: look down from heaven, and behold, and visit this vine; And the vineyard which thy right hand hath planted."'),
('Psalms', 80, 'teens', 4, 'What does Psalm 80:17 ask God to strengthen?', 'The man of thy right hand and the son of man whom thou madest strong for thyself', 'The walls of Jerusalem', 'The army of Israel', 'The priests of the temple', 'a', 'Psalm 80:17 — "Let thy hand be upon the man of thy right hand, upon the son of man whom thou madest strong for thyself."'),
('Psalms', 80, 'teens', 5, 'What does Asaph say God has fed His people in Psalm 80:5?', 'The bread of tears, and given them tears to drink in great measure', 'The finest wheat and honey', 'Manna from heaven again', 'Bitter herbs and unleavened bread', 'a', 'Psalm 80:5 — "Thou feedest them with the bread of tears; and givest them tears to drink in great measure."'),
('Psalms', 80, 'adults', 1, 'How does the vine metaphor in Psalm 80 connect to Jesus'' "I am the vine" discourse in John 15?', 'Psalm 80 establishes Israel as God''s vine transplanted from Egypt; when the vine fails and is cut down, the psalm prays for the "son of man" at God''s right hand (v.17) to restore it; Jesus claims "I am the true vine" (John 15:1), identifying Himself as the faithful Israel that the original vine failed to be', 'The vine metaphors are unrelated', 'Jesus is quoting Isaiah, not Psalms', 'The vine in John 15 refers to a literal grapevine', 'a', 'Psalm 80:8 (vine from Egypt) + v.17 (son of man) → John 15:1 ("I am the true vine"). Israel-as-vine failed (Isa 5:1-7); Christ-as-vine fulfills. The "true" (alethinos) in John 15:1 implies all previous vines were shadows; He is the reality.'),
('Psalms', 80, 'adults', 2, 'What is the messianic significance of "the man of thy right hand" and "the son of man" in Psalm 80:17?', 'These titles point beyond any contemporary leader to a future figure whom God strengthens — "son of man" (ben-adam) anticipates Daniel 7:13''s heavenly figure and Jesus'' self-designation; "man of thy right hand" anticipates Psalm 110:1''s enthronement at God''s right hand', 'The titles refer only to the current king', 'Son of man simply means a human being', 'The verse is about Benjamin (whose name means "son of the right hand")', 'a', 'Psalm 80:17 — "the man of thy right hand...the son of man." Ps 110:1 — "Sit thou at my right hand." Dan 7:13 — "one like the Son of man." Matt 26:64 — Jesus combines both: "the Son of man sitting on the right hand of power." Psalm 80:17 is a convergence point for messianic expectation.'),
('Psalms', 80, 'adults', 3, 'How does the threefold refrain (vv.3,7,19) with escalating divine titles create theological progression?', 'The titles escalate: "O God" (Elohim, v.3) → "O God of hosts" (Elohim Tsevaoth, v.7) → "O LORD God of hosts" (YHWH Elohim Tsevaoth, v.19) — each repetition intensifies the appeal from generic divinity to covenant name with full military-sovereign authority', 'The repetition is monotonous with no progression', 'The titles are interchangeable', 'The escalation was accidental', 'a', 'Elohim (v.3) → Elohim Tsevaoth (v.7) → YHWH Elohim Tsevaoth (v.19). Each refrain adds divine authority: generic God → God of heavenly armies → covenant LORD God of heavenly armies. The escalation reflects increasing desperation matched by increasing theological specificity.'),
('Psalms', 80, 'adults', 4, 'What does "cause thy face to shine" in the refrain draw from and how does it function?', 'It echoes the Aaronic blessing (Num 6:25 — "The LORD make his face shine upon thee") — the refrain is essentially a prayer for the priestly blessing to be reactivated; God''s shining face = favour, presence, salvation; His hidden face = abandonment, suffering', 'The shining face refers to the sun god', 'It means God should appear visibly', 'It is a prayer for good weather', 'a', 'Psalm 80:3 — "cause thy face to shine." Num 6:25 — "The LORD make his face shine upon thee." The Aaronic blessing was Israel''s fundamental assurance of divine presence. The refrain prays for its restoration: when God''s face shines, salvation follows; when hidden, devastation ensues.'),
('Psalms', 80, 'adults', 5, 'How does the vine''s growth in Psalm 80:10-11 ("hills covered...boughs unto the sea...branches unto the river") describe the theological ideal of the Davidic kingdom?', 'The vine covering from the Mediterranean (sea) to the Euphrates (river) describes the fullest extent of the land promise (Gen 15:18, 1 Kings 4:21) — the vine''s growth represents the theological ideal of covenant fulfillment under David/Solomon, making its destruction doubly tragic', 'The description is geographical exaggeration', 'The vine only represents the northern tribes', 'The sea and river are metaphorical', 'a', 'Psalm 80:11 — "boughs unto the sea...branches unto the river." Gen 15:18 — "from the river of Egypt unto the great river, the river Euphrates." 1 Kings 4:21 — Solomon''s domain. The vine''s geographical span = covenant fulfillment. Its destruction = covenant apparently reversed.'),
('Psalms', 80, 'adults', 6, 'What does the question "Why hast thou then broken down her hedges?" (Psalm 80:12) imply about the relationship between divine protection and divine judgment?', 'It implies that Israel''s protection was never self-generated but divinely maintained — God built the hedges and God broke them; this means both prosperity and disaster come from the same divine hand, making God the first cause of both blessing and judgment on His own vine', 'The hedges were literal walls that enemies destroyed', 'It implies God was negligent in protecting Israel', 'The question is merely rhetorical', 'a', 'Psalm 80:12 — "Why hast thou then broken down her hedges?" Cf. Isa 5:5 — "I will take away the hedge thereof, and it shall be eaten up." The vine/vineyard tradition consistently presents God as both planter and uprooted — protection and judgment both flow from divine sovereignty.'),
('Psalms', 80, 'adults', 7, 'How does the "boar out of the wood" (Psalm 80:13) function as a political and theological symbol?', 'The boar represents foreign invading powers (Assyria/Babylon) — an unclean animal (Lev 11:7) devastating God''s vine symbolizes the defilement of covenant purity by pagan empires; the specifically unclean animal intensifies the theological horror of gentile invasion of sacred space', 'The boar is a literal wild pig damaging crops', 'It represents internal corruption, not external invasion', 'The boar is a mythological creature', 'a', 'Psalm 80:13 — "The boar (chazir) out of the wood doth waste it." Chazir = pig/boar — the quintessentially unclean animal (Lev 11:7). The vine (covenant Israel) ravaged by a boar (unclean gentile power) = maximum theological desecration. Dan 8''s "little horn" and 1 Macc''s pig-sacrifice on the altar extend this imagery.'),
('Psalms', 80, 'adults', 8, 'What is the theological significance of the psalm ending with a promise rather than a lament (v.18 — "we will not go back from thee")?', 'The promise of perpetual faithfulness in v.18 transforms the psalm from mere complaint to covenant renewal — the people pledge never to turn away again if God revives them; this conditional promise creates a theological contract: revival in exchange for permanent loyalty, anticipating the new covenant''s promise of an undivided heart (Jer 32:39-40)', 'The ending is abrupt and unresolved', 'The promise is insincere based on Israel''s history', 'It is a later addition to soften the lament', 'a', 'Psalm 80:18 — "So will not we go back from thee: quicken us, and we will call upon thy name." The logic: give us life → we will be faithful. This conditional promise anticipates the new covenant where God ensures permanent faithfulness: Jer 32:40 — "I will put my fear in their hearts, that they shall not depart from me."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 81, 'kids', 1, 'What instruments does Psalm 81 tell people to play?', 'The timbrel, the harp, and the psaltery with the trumpet', 'Only the flute', 'Only drums', 'Bells and chimes', 'a', 'Psalm 81:2-3 — "Take a psalm, and bring hither the timbrel, the pleasant harp with the psaltery. Blow up the trumpet in the new moon."'),
('Psalms', 81, 'kids', 2, 'What did God say He took off Israel''s shoulders in Egypt?', 'Their burden — He freed them from carrying heavy loads', 'Their old clothes', 'Their sandals', 'Their weapons of war', 'a', 'Psalm 81:6 — "I removed his shoulder from the burden: his hands were delivered from the pots."'),
('Psalms', 81, 'kids', 3, 'What did God wish His people would do?', 'Listen to Him and walk in His ways', 'Build Him a bigger house', 'Give Him more sacrifices', 'Sing louder songs', 'a', 'Psalm 81:13 — "Oh that my people had hearkened unto me, and Israel had walked in my ways!"'),
('Psalms', 81, 'teens', 1, 'What festival does Psalm 81 likely celebrate?', 'The Feast of Tabernacles — with new moon trumpet and appointed feast references', 'Passover only', 'The Day of Atonement', 'Purim', 'a', 'Psalm 81:3 — "Blow up the trumpet in the new moon, in the time appointed, on our solemn feast day." This fits the Feast of Tabernacles (Lev 23:24,34) with its new moon trumpet.'),
('Psalms', 81, 'teens', 2, 'What does God say Israel should have no part of in Psalm 81:9?', 'A strange god — there shall no strange god be in thee, neither shalt thou worship any strange god', 'Strange food from other nations', 'Strange customs from foreigners', 'Strange languages', 'a', 'Psalm 81:9 — "There shall no strange god be in thee; neither shalt thou worship any strange god."'),
('Psalms', 81, 'teens', 3, 'What sad consequence came because Israel would not listen to God?', 'God gave them up unto their own hearts'' lust and they walked in their own counsels', 'God sent a great flood to punish them', 'God took away their ability to speak', 'God sent them to live in the desert', 'a', 'Psalm 81:11-12 — "But my people would not hearken to my voice...So I gave them up unto their own hearts'' lust."'),
('Psalms', 81, 'teens', 4, 'What does God promise He would have given Israel if they had listened?', 'He would have fed them with the finest wheat and honey out of the rock', 'He would have made them the largest army', 'He would have given them wings to fly', 'He would have made every day a holiday', 'a', 'Psalm 81:16 — "He should have fed them also with the finest of the wheat: and with honey out of the rock should I have satisfied thee."'),
('Psalms', 81, 'teens', 5, 'What would God have done to Israel''s enemies if they had obeyed?', 'He would have subdued them soon and turned His hand against their adversaries', 'He would have sent them to a faraway land', 'He would have converted them to worship God', 'He would have ignored them entirely', 'a', 'Psalm 81:14 — "I should soon have subdued their enemies, and turned my hand against their adversaries."'),
('Psalms', 81, 'adults', 1, 'What is the theological significance of God speaking in first person in Psalm 81:6-16?', 'God''s direct speech transforms the psalm from festive worship into prophetic oracle — at the height of celebration, God interrupts with a speech of longing and rebuke, revealing that liturgy without obedience is incomplete; the divine voice within worship is simultaneously judgment and invitation', 'The first person is Asaph speaking as himself', 'It is a scribal convention with no significance', 'God''s speech is a later addition', 'a', 'Psalm 81:6-16 — God speaks directly during festival worship. The effect: the worshipping community hears God''s own voice expressing grief over disobedience. Worship becomes encounter — not merely celebrating what God did but hearing what God says NOW.'),
('Psalms', 81, 'adults', 2, 'How does "I gave them up unto their own hearts'' lust" (Psalm 81:12) anticipate Romans 1:24-28?', 'Both describe divine judgment as withdrawal — God does not actively punish but removes restraining grace, allowing people to experience the natural consequences of their own desires; this "giving up" is among the most terrifying forms of divine judgment because it feels like freedom while being abandonment', 'The two texts are unrelated', 'Romans describes pagan sin while Psalm 81 describes Israel', 'Being given up to one''s desires is a blessing', 'a', 'Psalm 81:12 — "I gave them up (shalach) unto their own hearts'' lust." Rom 1:24 — "God also gave them up (paradidomi) to uncleanness through the lusts of their own hearts." The most severe judgment: God grants what sinners want, and the getting IS the punishment.'),
('Psalms', 81, 'adults', 3, 'What does the divine pathos expressed in "Oh that my people had hearkened unto me!" (Psalm 81:13) reveal about God''s character?', 'It reveals divine grief over human disobedience — God is not impassibly indifferent but genuinely sorrowful when His people reject Him; this "Oh that" (lu) expresses unrealised divine desire, showing that God''s sovereignty coexists with genuine divine longing for human response', 'God is simply frustrated, like a human parent', 'The exclamation is hyperbolic', 'God does not experience emotion', 'a', 'Psalm 81:13 — lu (Oh that!) — a particle of unfulfilled desire. Cf. Deut 5:29 — "O that there were such an heart in them." Matt 23:37 — "O Jerusalem...how often would I have gathered thy children...and ye would not!" Divine sovereignty does not eliminate divine pathos. God genuinely grieves unfaithfulness.'),
('Psalms', 81, 'adults', 4, 'How does the command "open thy mouth wide, and I will fill it" (Psalm 81:10) function as both promise and test?', 'It is simultaneously a promise of abundant provision (God will fill every need) and a test of faith (will Israel trust God enough to open wide?); the image of an open mouth receiving food mirrors a nestling''s total dependence — the invitation is to radical trust that receives everything from God', 'It is dietary advice about eating well', 'The open mouth refers to singing louder', 'It means Israel should ask for specific gifts', 'a', 'Psalm 81:10 — "open thy mouth wide, and I will fill it." The baby-bird image: total dependence, mouth open, receiving everything from the parent. But Israel "would not" (v.11) — refusing the posture of dependent trust. The tragedy: unlimited provision was available but unclaimed.'),
('Psalms', 81, 'adults', 5, 'What does the conditional "if" structure (Psalm 81:13-16) reveal about the relationship between divine sovereignty and human responsibility?', 'The conditional "if my people had hearkened" implies genuine human responsibility — God''s blessings were available but contingent on Israel''s response; divine sovereignty did not override human choice; the unrealised blessings (finest wheat, honey from rock) show what obedience would have produced, making disobedience genuinely tragic', 'The conditional structure is merely hypothetical', 'God predetermined both the disobedience and its consequences', 'The "if" proves God was unable to make Israel obey', 'a', 'Psalm 81:13-16 — "Oh that my people had hearkened...I should soon have subdued their enemies...He should have fed them with the finest of the wheat." The counterfactual conditional presents a genuinely unrealised possibility: God''s best was available, but human refusal prevented it. Both sovereignty and responsibility are real.'),
('Psalms', 81, 'adults', 6, 'How does "honey out of the rock" (Psalm 81:16) function as a covenantal image?', 'It alludes to the wilderness provision (water from rock, Deut 32:13 — "honey out of the rock") and the land promise ("a land flowing with milk and honey") — combining wilderness miracle and Canaan abundance into a single image of God providing sweetness from impossibility; covenant faithfulness transforms barrenness into abundance', 'It describes a literal geological phenomenon', 'The honey is metaphorical for basic survival food', 'It refers to wild beehives in rocky terrain', 'a', 'Psalm 81:16 — Deut 32:13 — "He made him to suck honey out of the rock." Ex 3:8 — "land flowing with milk and honey." The image combines exodus miracle (rock) with Canaan promise (honey): God provides impossible sweetness. 1 Cor 10:4 — "they drank of that spiritual Rock that followed them: and that Rock was Christ."'),
('Psalms', 81, 'adults', 7, 'What is the liturgical setting of Psalm 81 and how does the divine speech disrupt the expected worship pattern?', 'Set at the Feast of Tabernacles (trumpet, new moon, feast), the psalm begins with joyful worship commands (vv.1-5) but shifts to divine speech that rebukes and pleads (vv.6-16) — the festive mood is interrupted by God''s own voice, transforming celebration into confrontation and preventing worship from becoming merely commemorative', 'The psalm has no liturgical setting', 'The divine speech enhances the celebration', 'The interruption was unintended', 'a', 'The pattern: vv.1-5 (festive commands — sing, play, blow trumpet) → vv.6-16 (God speaks — "I tested...you did not listen"). The shift from celebration to confrontation mirrors prophetic disruption of worship (cf. Amos 5:21-24). True worship includes hearing God''s uncomfortable word.'),
('Psalms', 81, 'adults', 8, 'How does "I am the LORD thy God, which brought thee out of the land of Egypt" (Psalm 81:10) function as the theological foundation for all subsequent commands?', 'It recapitulates the Decalogue preamble (Ex 20:2) — God''s identity as Liberator precedes and grounds all commands; obedience is response to grace, not its prerequisite; the exodus identity establishes both God''s right to command and Israel''s obligation to obey within a relationship of deliverance', 'It is historical background with no theological function', 'It restricts the psalm''s application to the exodus generation', 'The phrase is a later interpolation', 'a', 'Psalm 81:10 = Ex 20:2 (Decalogue preamble). The logic: because I liberated you, therefore obey me. Grace precedes law. Obedience is grateful response, not contractual obligation. This gospel structure (indicative → imperative) runs through Scripture: you ARE saved, therefore live accordingly.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 82, 'kids', 1, 'Where does God stand to judge in Psalm 82?', 'In the congregation of the mighty — among the judges', 'On top of a mountain', 'By the river', 'In the temple', 'a', 'Psalm 82:1 — "God standeth in the congregation of the mighty; he judgeth among the gods."'),
('Psalms', 82, 'kids', 2, 'What does God tell the judges to do for the poor?', 'Defend them and do justice to the afflicted and needy', 'Give them extra food', 'Build them bigger houses', 'Send them to another country', 'a', 'Psalm 82:3 — "Defend the poor and fatherless: do justice to the afflicted and needy."'),
('Psalms', 82, 'kids', 3, 'What does God say will happen to the unjust judges?', 'They shall die like men and fall like one of the princes', 'They will become kings', 'They will live forever', 'They will get richer', 'a', 'Psalm 82:7 — "But ye shall die like men, and fall like one of the princes."'),
('Psalms', 82, 'teens', 1, 'Who are the "gods" (elohim) addressed in Psalm 82?', 'Human judges and rulers who were given divine authority to judge but failed to use it justly', 'Literal pagan deities who exist as real gods', 'Angels in heaven who serve God', 'The priests of the temple', 'a', 'Psalm 82:6-7 — "I have said, Ye are gods...But ye shall die like men." The "gods" are human authorities whom God entrusted with judicial power. Jesus references this in John 10:34.'),
('Psalms', 82, 'teens', 2, 'What accusation does God bring against these judges in Psalm 82:2?', 'They judge unjustly and accept the persons (show favouritism to) the wicked', 'They charge too much money for their services', 'They refuse to work on the Sabbath', 'They speak in languages no one understands', 'a', 'Psalm 82:2 — "How long will ye judge unjustly, and accept the persons of the wicked?"'),
('Psalms', 82, 'teens', 3, 'What does Psalm 82 say is shaken because of unjust judgment?', 'All the foundations of the earth are out of course', 'The walls of the city', 'The pillars of the temple', 'The throne of the king', 'a', 'Psalm 82:5 — "All the foundations of the earth are out of course." Injustice destabilises the very foundations of the world.'),
('Psalms', 82, 'teens', 4, 'What does the psalmist ask God to do in the final verse?', 'Arise and judge the earth, for He shall inherit all nations', 'Forgive the unjust judges', 'Send new judges to replace the old', 'Destroy all the nations', 'a', 'Psalm 82:8 — "Arise, O God, judge the earth: for thou shalt inherit all nations."'),
('Psalms', 82, 'teens', 5, 'How did Jesus use Psalm 82:6 in John 10:34?', 'He argued that if Scripture called human judges "gods," then He was not blaspheming by calling Himself the Son of God — how much more should the one whom the Father sanctified and sent be called God''s Son', 'Jesus rejected the psalm as outdated', 'Jesus said the psalm was about angels', 'Jesus used it to criticise the Pharisees', 'a', 'John 10:34-36 — "Is it not written in your law, I said, Ye are gods? If he called them gods, unto whom the word of God came...Say ye of him, whom the Father hath sanctified...Thou blasphemest; because I said, I am the Son of God?"'),
('Psalms', 82, 'adults', 1, 'What is the divine council motif in Psalm 82:1 and how does it relate to broader ANE theology?', 'Psalm 82 depicts God presiding over a divine council (adat-El) where heavenly beings or divinised rulers are judged — this parallels ANE divine council imagery (Ugaritic texts, Enuma Elish) but radically subverts it: YHWH is not one god among equals but the supreme Judge who sentences all other "gods" to death', 'The divine council is a Christian invention', 'Psalm 82 is purely monotheistic with no council imagery', 'The council is a human court', 'a', 'Psalm 82:1 — "God standeth in the congregation of the mighty (adat-El); he judgeth among the gods (elohim)." ANE parallels: Ugaritic texts describe El presiding over the divine assembly. But Psalm 82 is unique: YHWH judges and condemns the other elohim to death (v.7), establishing absolute monotheism through judicial sentence.'),
('Psalms', 82, 'adults', 2, 'How does "all the foundations of the earth are out of course" (Psalm 82:5) connect injustice to cosmic instability?', 'It establishes a direct link between moral order and cosmic order — when justice fails, creation itself is destabilised; the foundations of the earth rest not on physics alone but on justice; unjust governance literally undermines reality, anticipating the prophetic vision where justice and creation are inseparable (Isa 24:4-5)', 'The verse describes a literal earthquake', 'It is poetic exaggeration with no theological meaning', 'Cosmic stability has nothing to do with human justice', 'a', 'Psalm 82:5 — injustice → "foundations of the earth...out of course." Isa 24:4-5 — "The earth mourneth...because they have transgressed the laws." Prov 29:4 — "The king by judgment establisheth the land." In biblical theology, justice is not merely social policy but a cosmic force that sustains creation.'),
('Psalms', 82, 'adults', 3, 'What is the theological significance of God sentencing the "gods" to "die like men" (Psalm 82:7)?', 'It strips these rulers of their pretended divinity — they were called "gods" (given divine authority to judge) but will die as mere mortals; this simultaneously affirms that human authority derives from divine delegation and warns that abused authority will be revoked; only YHWH is truly God', 'It proves that pagan gods are mortal beings', 'It is a threat to literal angels', 'The death sentence is metaphorical for losing political power', 'a', 'Psalm 82:6-7 — "I have said, Ye are gods (elohim)...But ye shall die like men (ke-adam)." The sentence: you were elevated to god-like judicial authority, but you abused it; therefore mortality is your destiny. The contrast between "gods" (v.6) and "die like men" (v.7) is the psalm''s theological punch: only just governance reflects true divine character.'),
('Psalms', 82, 'adults', 4, 'How does Jesus'' use of Psalm 82:6 in John 10:34-36 employ a fortiori (qal va-chomer) reasoning?', 'Jesus argues from lesser to greater: if Scripture called corrupt human judges "gods" merely because they received God''s word, then surely the one whom the Father sanctified and sent into the world — who IS God''s Word incarnate — has a greater right to the title "Son of God"; the argument is Christological, not anthropological', 'Jesus is simply making a pun on the word "gods"', 'He is claiming that all humans are gods', 'Jesus misquotes the psalm', 'a', 'John 10:34-36 — The a fortiori logic: (1) human judges called "gods" (lesser case); (2) Jesus, sanctified and sent by the Father (greater case); (3) if the lesser case is in Scripture, the greater case cannot be blasphemy. The argument validates Jesus'' divine claim by appeal to the psalm''s own precedent.'),
('Psalms', 82, 'adults', 5, 'What does the closing prayer "Arise, O God, judge the earth: for thou shalt inherit all nations" (Psalm 82:8) reveal about the psalm''s eschatological vision?', 'Having exposed the failure of all delegated authority (human judges/gods), the psalm appeals for direct divine governance — God Himself must judge because all proxies have failed; this anticipates the NT vision of Christ''s universal judgment (Matt 25:31-32) when God''s direct rule replaces all inadequate human governance', 'The prayer is for a military conquest', 'It asks God to destroy all nations', 'The verse has no eschatological dimension', 'a', 'Psalm 82:8 — All human/angelic governance has failed (vv.2-7); therefore God must judge directly (v.8). This is the eschatological conclusion: history moves toward direct divine rule because all delegated authority inevitably corrupts. Rev 11:15 — "The kingdoms of this world are become the kingdoms of our Lord, and of his Christ."'),
('Psalms', 82, 'adults', 6, 'How does Psalm 82''s theme of social justice for the poor (vv.3-4) function within the divine council setting?', 'By placing the justice-for-the-poor mandate within the divine council, the psalm elevates social justice from political policy to cosmic responsibility — caring for the poor, fatherless, afflicted, and needy is not optional charity but the defining test of whether rulers reflect God''s character; failure is cosmic treason', 'Social justice is a secondary concern', 'The poor are mentioned only as background', 'Justice for the poor is a separate topic from the divine council', 'a', 'Psalm 82:3-4 — "Defend the poor and fatherless: do justice to the afflicted and needy. Deliver the poor and needy: rid them out of the hand of the wicked." These commands are what the "gods" failed to do. Social justice is the criterion of divine authority: rulers who neglect the vulnerable lose their "divine" status.'),
('Psalms', 82, 'adults', 7, 'What does the darkness/ignorance of the judges (Psalm 82:5 — "they know not, neither will they understand; they walk on in darkness") suggest about the moral epistemology of injustice?', 'Injustice is not merely moral failure but epistemological darkness — the judges do not merely refuse justice; they cannot perceive it; their corruption has blinded them; this connects moral degradation with cognitive impairment, anticipating Romans 1:21 where refusal to honour God leads to darkened understanding', 'The judges are literally blind', 'Darkness refers to nighttime court sessions', 'The ignorance is educational, not moral', 'a', 'Psalm 82:5 — "They know not, neither will they understand; they walk on in darkness." Rom 1:21 — "their foolish heart was darkened." Eph 4:18 — "darkened in understanding." Injustice produces cognitive darkness: the unjust lose the capacity to perceive justice. Moral failure degrades intellectual capacity.'),
('Psalms', 82, 'adults', 8, 'How does Psalm 82 contribute to the Bible''s developing monotheism?', 'The psalm represents a stage in revelatory monotheism where the existence of other "gods/elohim" is acknowledged but their power is denied through judicial sentence — YHWH does not merely claim supremacy but strips all competitors of authority and sentences them to mortality; monotheism is established not by philosophical argument but by divine verdict', 'The psalm is fully polytheistic', 'It contradicts monotheism', 'Monotheism was established before this psalm', 'a', 'Psalm 82 represents "judicial monotheism": other elohim may exist in some sense, but YHWH judges, sentences, and demotes them all. The result is practical-effective monotheism: even if other spiritual beings exist, none possesses authority or permanence. Only YHWH is worthy of worship. Isa 44:6 — "besides me there is no God."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 83, 'kids', 1, 'What did Asaph ask God not to do in Psalm 83?', 'Not to keep silent — not to hold His peace or be still', 'Not to send rain', 'Not to move the mountains', 'Not to close the temple', 'a', 'Psalm 83:1 — "Keep not thou silence, O God: hold not thy peace, and be not still, O God."'),
('Psalms', 83, 'kids', 2, 'What did the enemy nations want to do to Israel?', 'Cut them off from being a nation — wipe out the name of Israel', 'Invite them to a feast', 'Trade with them', 'Build a wall around them', 'a', 'Psalm 83:4 — "They have said, Come, and let us cut them off from being a nation; that the name of Israel may be no more in remembrance."'),
('Psalms', 83, 'kids', 3, 'What does Asaph ask God to make the enemies like?', 'Like a wheel of dust and stubble blown by the wind', 'Like fish caught in a net', 'Like flowers that bloom in spring', 'Like birds flying south', 'a', 'Psalm 83:13 — "O my God, make them like a wheel; as the stubble before the wind."'),
('Psalms', 83, 'teens', 1, 'How many enemy nations/peoples are listed in the coalition against Israel in Psalm 83:6-8?', 'Ten groups — Edom, Ishmaelites, Moab, Hagarenes, Gebal, Ammon, Amalek, Philistines, Tyre, and Assur', 'Only three enemies', 'Seven groups', 'Twelve tribes of enemies', 'a', 'Psalm 83:6-8 lists ten enemy nations/peoples forming a coalition against Israel from all directions.'),
('Psalms', 83, 'teens', 2, 'Which Old Testament heroes does Asaph ask God to defeat the enemies like?', 'Like the defeat of Midian, Sisera, and Jabin — judges-era victories', 'Like David''s defeat of Goliath', 'Like Joshua''s conquest of Jericho', 'Like Moses'' defeat of Pharaoh', 'a', 'Psalm 83:9-11 — "Do unto them as unto the Midianites; as to Sisera, as to Jabin, at the brook of Kison." References to Judges 4-7.'),
('Psalms', 83, 'teens', 3, 'What did the enemies say they would take for themselves?', 'The houses (pastures) of God as their possession', 'The gold of the temple', 'The livestock of the people', 'The throne of the king', 'a', 'Psalm 83:12 — "Who said, Let us take to ourselves the houses of God in possession."'),
('Psalms', 83, 'teens', 4, 'What does Asaph want the defeated enemies to ultimately seek?', 'The name of the LORD — that they may seek thy name, O LORD', 'Revenge against Israel', 'Shelter in caves', 'New lands to conquer', 'a', 'Psalm 83:16 — "Fill their faces with shame; that they may seek thy name, O LORD."'),
('Psalms', 83, 'teens', 5, 'What is Asaph''s ultimate desire for the outcome in Psalm 83:18?', 'That men may know that God, whose name is JEHOVAH, is the most high over all the earth', 'That Israel becomes the richest nation', 'That all enemies are completely destroyed', 'That a new temple is built', 'a', 'Psalm 83:18 — "That men may know that thou, whose name alone is JEHOVAH, art the most high over all the earth."'),
('Psalms', 83, 'adults', 1, 'How does the ten-nation coalition in Psalm 83:6-8 function as a theological symbol beyond its historical referent?', 'The comprehensive coalition (surrounding Israel from every direction — east, south, west, north) represents the totality of gentile opposition to God''s people; the round number ten suggests completeness, making this an archetypal pattern of universal hostility that echoes through history (Ezek 38''s Gog coalition, Rev 20:8)', 'It is a literal record of one specific historical war', 'The number ten is coincidental', 'The coalition is purely fictional', 'a', 'Psalm 83:6-8 — Ten nations from every compass point. This pattern of universal coalition against God''s people recurs: Ezek 38-39 (Gog and Magog), Rev 20:8-9. The psalm establishes the archetype: the people of God are perpetually surrounded but divinely preserved.'),
('Psalms', 83, 'adults', 2, 'What is the theological tension in Asaph''s imprecation: he prays for enemies'' destruction (vv.13-15) yet also for their conversion (v.16)?', 'The psalm holds judgment and mission in tension — Asaph wants enemies humbled ("fill their faces with shame") so that they "may seek thy name, O LORD"; divine judgment serves evangelistic purpose; the ultimate goal is not annihilation but recognition of YHWH as most high over all the earth (v.18)', 'The tension is a contradiction showing poor theology', 'Asaph only wants destruction, not conversion', 'The conversion prayer is sarcastic', 'a', 'Psalm 83:16 — "that they may seek thy name." V.18 — "that men may know that thou...art the most high over all the earth." The telos of judgment is revelation, not annihilation. The prayer moves from destruction (means) to recognition (end). Divine judgment serves divine self-revelation.'),
('Psalms', 83, 'adults', 3, 'How does the appeal to judges-era victories (Midian, Sisera, Jabin, Oreb, Zeeb — vv.9-12) function as theological argument?', 'By citing specific historical deliverances, Asaph argues from precedent: God has defeated coalitions before; the historical memory of judges-era victories creates theological expectation that God will do it again; past acts of God are not merely history but promise', 'The historical references are mere literary decoration', 'Asaph is confused about which battles occurred', 'The judges era was too long ago to be relevant', 'a', 'Psalm 83:9-12 references Judg 4-5 (Sisera, Jabin, Kishon) and Judg 7-8 (Midianites, Oreb, Zeeb). The argument from precedent: God who defeated these coalitions will defeat this one. Historical memory becomes theological promissory note.'),
('Psalms', 83, 'adults', 4, 'What is the significance of Psalm 83 being the last Asaph psalm in the Psalter?', 'As the final Asaph psalm, Psalm 83 represents the climax of the Asaphite tradition''s engagement with national crisis — from individual theodicy (Ps 73) through communal lament (Ps 74,79) to universal conflict (Ps 83); the collection ends with universal scope: "thou...art the most high over all the earth" (v.18)', 'Its placement is accidental', 'Asaph wrote many more psalms after this', 'The placement has no significance', 'a', 'The Asaph collection (Ps 73-83) traces: individual crisis (73) → temple destruction (74) → divine judgment (75) → divine victory (76) → historical memory (77-78) → Jerusalem''s fall (79) → Israel as vine (80) → divine plea (81) → cosmic justice (82) → universal scope (83). The collection moves from personal to universal.'),
('Psalms', 83, 'adults', 5, 'How does "let us take to ourselves the houses of God" (Psalm 83:12) frame the conflict as fundamentally theological?', 'The enemies'' goal is not merely territorial but theological — they want to possess God''s pastures/dwelling places, making this a war against God Himself, not merely against Israel; the conflict is over divine real estate, transforming a political war into a cosmic one', 'The enemies simply want fertile grazing land', 'Houses of God refers to private homes', 'The statement is diplomatic posturing', 'a', 'Psalm 83:12 — "the houses (neoth, pastures/habitations) of God." The enemies target not just Israel but God''s own territory. This elevates the conflict from political to theological: attacking Israel = attacking God''s inheritance. Compare Psalm 2:1-3 where nations conspire against "the LORD, and against his anointed."'),
('Psalms', 83, 'adults', 6, 'What does the fire/forest metaphor (Psalm 83:14 — "as the fire burneth a wood") contribute to the psalm''s theology of divine judgment?', 'Fire consuming a forest is unstoppable, comprehensive, and purifying — divine judgment is not surgical precision but overwhelming force that transforms the entire landscape; the metaphor conveys irresistibility while connecting to theophanic fire imagery throughout Scripture (Deut 4:24 — "God is a consuming fire")', 'The metaphor describes a literal forest fire', 'Fire represents human anger, not divine judgment', 'The image is purely aesthetic', 'a', 'Psalm 83:14-15 — fire burning wood, flame setting mountains ablaze. Deut 4:24 — "the LORD thy God is a consuming fire." Heb 12:29 — "our God is a consuming fire." The fire imagery connects temporal judgment to God''s essential nature: divine holiness encounters sin as fire encounters wood.'),
('Psalms', 83, 'adults', 7, 'How does Psalm 83:18''s declaration that YHWH is "most high (elyon) over all the earth" relate to the divine council theme of Psalm 82?', 'Psalm 82 judged the "gods" and found them wanting; Psalm 83 concludes the Asaph collection by declaring YHWH as elyon (most high) over all the earth — the result of the divine council judgment: all competitors are eliminated, YHWH alone reigns; the two psalms together establish definitive monotheistic sovereignty', 'The two psalms are unrelated', 'Elyon is a different deity from YHWH', 'Psalm 83 contradicts Psalm 82', 'a', 'Psalm 82:1 (God judges the gods) → 82:8 (arise, judge the earth) → 83:18 (YHWH is elyon over all the earth). The sequence: divine council → judgment → universal sovereignty. The Asaph collection ends with YHWH''s unchallenged supremacy over all — gods, nations, and earth.'),
('Psalms', 83, 'adults', 8, 'What is the relationship between Psalm 83''s prayer and Ezekiel 38-39''s Gog prophecy?', 'Both describe a comprehensive coalition of nations attacking Israel that God Himself defeats — Psalm 83''s ten-nation alliance and Ezekiel''s Gog coalition share the same theological pattern: universal hostility against God''s people met by overwhelming divine intervention; both end with universal recognition of YHWH (Ps 83:18, Ezek 38:23)', 'The two texts describe completely different situations', 'Ezekiel copied Psalm 83 without theological development', 'There is no connection between the texts', 'a', 'Psalm 83 pattern: coalition forms → attacks Israel → God intervenes → nations recognise YHWH. Ezek 38-39 pattern: Gog coalition forms → attacks Israel → God intervenes (fire, hailstones) → nations recognise YHWH (38:23). Rev 20:8-9 completes the pattern eschatologically.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 84, 'kids', 1, 'What does the writer of Psalm 84 say about God''s house?', 'How amiable (lovely) are thy tabernacles, O LORD of hosts!', 'It is too far away to visit', 'It needs to be cleaned', 'It is very cold inside', 'a', 'Psalm 84:1 — "How amiable are thy tabernacles, O LORD of hosts!"'),
('Psalms', 84, 'kids', 2, 'What little birds found a home in God''s house?', 'The sparrow and the swallow built nests near God''s altars', 'Eagles and hawks', 'Owls and bats', 'Peacocks and parrots', 'a', 'Psalm 84:3 — "Yea, the sparrow hath found an house, and the swallow a nest for herself...even thine altars, O LORD of hosts."'),
('Psalms', 84, 'kids', 3, 'How long does the psalmist say one day in God''s courts is worth?', 'Better than a thousand days elsewhere', 'The same as any other day', 'Worth half a day', 'Not as good as being outside', 'a', 'Psalm 84:10 — "For a day in thy courts is better than a thousand."'),
('Psalms', 84, 'teens', 1, 'What does the psalmist say about those who dwell in God''s house?', 'Blessed are they — they will be still praising God', 'They must follow strict rules every day', 'They will become priests automatically', 'They will never experience hardship', 'a', 'Psalm 84:4 — "Blessed are they that dwell in thy house: they will be still praising thee."'),
('Psalms', 84, 'teens', 2, 'What happens when pilgrims pass through the valley of Baca?', 'They make it a well — the rain fills the pools, and they go from strength to strength', 'They become lost and cannot find their way', 'They grow tired and give up', 'They have to turn back', 'a', 'Psalm 84:6-7 — "Who passing through the valley of Baca make it a well; the rain also filleth the pools. They go from strength to strength."'),
('Psalms', 84, 'teens', 3, 'What would the psalmist rather be than dwell in the tents of wickedness?', 'A doorkeeper in the house of God', 'A rich merchant in the marketplace', 'A soldier in a great army', 'A king in a foreign land', 'a', 'Psalm 84:10 — "I had rather be a doorkeeper in the house of my God, than to dwell in the tents of wickedness."'),
('Psalms', 84, 'teens', 4, 'What two things does God give according to Psalm 84:11?', 'Grace and glory — and no good thing will He withhold from those who walk uprightly', 'Wealth and power', 'Long life and many children', 'Victory in battle and fertile land', 'a', 'Psalm 84:11 — "The LORD will give grace and glory: no good thing will he withhold from them that walk uprightly."'),
('Psalms', 84, 'teens', 5, 'What does the psalmist call the LORD in Psalm 84:11?', 'A sun and shield', 'A mighty warrior', 'A great king', 'A wise counsellor', 'a', 'Psalm 84:11 — "For the LORD God is a sun and shield."'),
('Psalms', 84, 'adults', 1, 'How does the sparrow/swallow finding a nest at God''s altars (Psalm 84:3) function theologically?', 'If even insignificant birds find home and security at God''s altars, how much more should God''s people find welcome there — the argument moves from lesser to greater; the birds'' instinctive homing to God''s presence shames humans who wander from it', 'The birds are pests that need to be removed from the temple', 'It describes the temple''s poor maintenance', 'The birds are symbolic of angels', 'a', 'Psalm 84:3 — "the sparrow hath found an house, and the swallow a nest for herself...even thine altars." Matt 10:29 — "Are not two sparrows sold for a farthing? and one of them shall not fall on the ground without your Father." Even the least creatures find refuge in God''s presence.'),
('Psalms', 84, 'adults', 2, 'What does the "valley of Baca" (Psalm 84:6) represent and how does the transformation happen?', 'Baca (weeping/balsam trees, arid valley) represents suffering and hardship — pilgrims whose strength is in God transform barren valleys into wells; the transformation is not circumstantial (the valley does not change) but perspectival — faith makes dry places into springs; this is pilgrimage theology', 'Baca is a literal geographic location with actual wells', 'The valley is metaphorical for death', 'Baca means "happiness" not "weeping"', 'a', 'Psalm 84:6 — Baca (from bakah, to weep). The valley of weeping becomes a place of springs (mayan) for those who pass through with God-directed strength. The transformation is not external but internal: faith reinterprets suffering. 2 Cor 12:9 — "my strength is made perfect in weakness."'),
('Psalms', 84, 'adults', 3, 'How does "a day in thy courts is better than a thousand" (Psalm 84:10) establish a theology of divine presence as the supreme good?', 'It creates an absolute value hierarchy: one day of God''s presence outweighs a thousand days without it by a factor of infinity; the comparison is not merely quantitative but qualitative — God''s presence is categorically different from all other goods, making proximity to God the definition of blessing itself', 'The verse describes efficient temple services', 'It means temple visits should be short', 'It is hyperbolic with no real meaning', 'a', 'Psalm 84:10 — "a day in thy courts is better than a thousand." Combined with 84:10b (doorkeeper vs. tent-dweller): the lowest position in God''s presence surpasses the highest position outside it. This establishes presence-based rather than prosperity-based theology. Cf. Phil 1:23 — "to be with Christ; which is far better."'),
('Psalms', 84, 'adults', 4, 'What is the significance of God being called "a sun and shield" (Psalm 84:11)?', 'Sun = source of life, light, warmth, growth; shield = protection from danger — together they represent God as both the positive source of all blessing and the negative protector from all harm; this is the only place in the OT where God is called "sun" (shemesh), likely because of the danger of solar worship (2 Kings 23:11)', 'Sun and shield are military symbols', 'The sun reference promotes sun worship', 'It means God is distant like the sun', 'a', 'Psalm 84:11 — "the LORD God is a sun (shemesh) and shield (magen)." Sun = positive provision (light, life, Mal 4:2 — "Sun of righteousness"). Shield = negative protection (Ps 3:3). The rarity of calling God "sun" reflects caution against solar syncretism, but here the metaphor is irresistible: God IS the ultimate source of light and life.'),
('Psalms', 84, 'adults', 5, 'How does the threefold "blessed" (ashre) structure (vv.4,5,12) organise the psalm''s theology?', 'First blessed: those who dwell in God''s house (v.4, permanent presence). Second: those whose strength is in God, who journey through Baca (v.5, pilgrimage faith). Third: those who trust in God (v.12, general faith). The progression: dwelling → journeying → trusting — from temple to road to heart, universalising access to blessedness', 'The three beatitudes are repetitive', 'They describe three different groups with no connection', 'Only the first beatitude is genuinely about God', 'a', 'Three ashre statements: v.4 (dwell in house), v.5 (highways in heart/pilgrimage), v.12 (trust in YHWH). The movement: location-based → journey-based → faith-based blessedness. This universalises: you need not live in the temple; even on the road (v.5-7) or anywhere (v.12), trust in God = blessedness.'),
('Psalms', 84, 'adults', 6, 'What does "they go from strength to strength" (Psalm 84:7) reveal about the nature of spiritual pilgrimage?', 'Contrary to physical journey where travellers grow weaker, spiritual pilgrimage produces increasing strength — proximity to God energises rather than depletes; the pilgrim arrives stronger than when departing; this reverses natural expectation and reveals that God is the source of energy that increases with approach', 'It means the pilgrims carry weights to build muscle', 'The phrase describes relay running', 'Strength to strength means they rest frequently', 'a', 'Psalm 84:7 — "They go from strength to strength (chayil el chayil), every one of them in Zion appeareth before God." Physical travel depletes; spiritual travel replenishes. Isa 40:31 — "they that wait upon the LORD shall renew their strength...they shall run, and not be weary." Proximity to God = increasing vitality.'),
('Psalms', 84, 'adults', 7, 'How does Psalm 84 function within Book III''s movement from lament to hope?', 'After the darkness of Psalms 74, 79, 80 (temple destroyed, Jerusalem fallen), Psalm 84 introduces radiant hope — the beauty of God''s house, the joy of pilgrimage, the blessing of trust; this shift from lament to longing represents faith persisting through and beyond catastrophe, refusing despair''s finality', 'Psalm 84 ignores Book III''s earlier laments', 'It contradicts the previous psalms', 'It was placed here accidentally', 'a', 'Book III movement: 73-74 (theodicy/temple destruction) → 75-76 (divine justice) → 77-78 (memory) → 79-80 (national lament) → 81-82 (divine rebuke) → 83 (coalition threat) → 84-85 (hope/restoration). Psalm 84''s radiant devotion after earlier darkness demonstrates faith''s resilience.'),
('Psalms', 84, 'adults', 8, 'What does "no good thing will he withhold from them that walk uprightly" (Psalm 84:11) contribute to biblical prosperity theology when read in context?', 'In context, the "good thing" is defined by the psalm itself: God''s presence, grace, glory, protection — not material wealth; the psalm redefines goodness as relational (proximity to God) rather than material; a doorkeeper''s position in God''s house IS the good thing withheld from no upright walker', 'It promises unlimited material wealth to the righteous', 'It contradicts the rest of the psalm', 'The verse applies only to Levites', 'a', 'Psalm 84:11 — "no good thing will he withhold." But what is "good"? The psalm defines it: v.1 (God''s lovely house), v.3 (home near altars), v.4 (dwelling in presence), v.10 (one day in courts > thousand elsewhere). "Good" = God Himself, not goods. Rom 8:32 — "He that spared not his own Son...shall he not with him also freely give us all things?"');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 85, 'kids', 1, 'What did God do for His land according to Psalm 85?', 'He brought back the captivity of Jacob — He forgave their sins', 'He made it rain every day', 'He built new cities', 'He planted new trees', 'a', 'Psalm 85:1-2 — "LORD, thou hast been favourable unto thy land: thou hast brought back the captivity of Jacob. Thou hast forgiven the iniquity of thy people."'),
('Psalms', 85, 'kids', 2, 'What four beautiful things meet together in Psalm 85:10?', 'Mercy and truth, righteousness and peace', 'Sun and moon, stars and clouds', 'Gold and silver, gems and pearls', 'Bread and water, milk and honey', 'a', 'Psalm 85:10 — "Mercy and truth are met together; righteousness and peace have kissed each other."'),
('Psalms', 85, 'kids', 3, 'What does the psalmist say will spring out of the earth?', 'Truth shall spring out of the earth and righteousness shall look down from heaven', 'Flowers of every colour', 'Mighty trees', 'Rivers of water', 'a', 'Psalm 85:11 — "Truth shall spring out of the earth; and righteousness shall look down from heaven."'),
('Psalms', 85, 'teens', 1, 'What does the psalmist ask God to do again in Psalm 85:6?', '"Wilt thou not revive us again: that thy people may rejoice in thee?"', 'Build a bigger temple', 'Send more prophets', 'Give them a new king', 'a', 'Psalm 85:6 — "Wilt thou not revive us again: that thy people may rejoice in thee?"'),
('Psalms', 85, 'teens', 2, 'What does Psalm 85:8 say God will speak to His people?', 'Peace — God will speak peace unto His people and to His saints', 'Judgment and condemnation', 'Commands for war', 'Nothing — He will remain silent', 'a', 'Psalm 85:8 — "I will hear what God the LORD will speak: for he will speak peace unto his people, and to his saints: but let them not turn again to folly."'),
('Psalms', 85, 'teens', 3, 'What does Psalm 85:9 say is near to those who fear God?', 'His salvation — that glory may dwell in the land', 'His anger and punishment', 'His army of angels', 'His hidden treasure', 'a', 'Psalm 85:9 — "Surely his salvation is nigh them that fear him; that glory may dwell in our land."'),
('Psalms', 85, 'teens', 4, 'What goes before God to prepare the way according to Psalm 85:13?', 'Righteousness shall go before him and shall set us in the way of his steps', 'An army of angels clearing the path', 'Thunder and lightning', 'A pillar of cloud and fire', 'a', 'Psalm 85:13 — "Righteousness shall go before him; and shall set us in the way of his steps."'),
('Psalms', 85, 'teens', 5, 'What does God give and what does the land yield in Psalm 85:12?', 'The LORD shall give that which is good, and the land shall yield her increase', 'Gold from mines and fish from seas', 'Soldiers from cities and weapons from forges', 'Wisdom from books and skill from practice', 'a', 'Psalm 85:12 — "Yea, the LORD shall give that which is good; and our land shall yield her increase."'),
('Psalms', 85, 'adults', 1, 'How does Psalm 85:10 — "Mercy and truth are met together; righteousness and peace have kissed each other" — describe the atonement?', 'It depicts the cross as the convergence point where God''s seemingly conflicting attributes are reconciled: mercy (chesed, desire to forgive) and truth (emet, requirement of justice) meet; righteousness (tsedeq, God''s standard) and peace (shalom, restored relationship) kiss — only at the cross do all four unite without compromise', 'It describes a diplomatic peace treaty', 'The meeting is metaphorical for good weather', 'It has no connection to the atonement', 'a', 'Psalm 85:10 — The theological problem: mercy wants to forgive; truth demands accountability; righteousness requires punishment; peace requires reconciliation. These appear contradictory. At the cross: mercy forgives through Christ''s sacrifice; truth is upheld because sin is punished; righteousness is satisfied; peace is achieved. Rom 3:26 — God is "just, and the justifier."'),
('Psalms', 85, 'adults', 2, 'What does "truth shall spring out of the earth; and righteousness shall look down from heaven" (Psalm 85:11) envision about the restored creation?', 'It describes a renewed cosmic order where heaven and earth cooperate — truth (emet/faithfulness) growing from the earth below and righteousness raining from heaven above; the image envisions a healed creation where the vertical (divine-human) relationship produces horizontal (earthly) flourishing', 'It describes literal plants growing', 'Truth springing from earth means archaeology will vindicate Israel', 'It is purely figurative with no theological content', 'a', 'Psalm 85:11 — Heaven (righteousness) and earth (truth) cooperate in the restored order. Isa 45:8 — "Drop down, ye heavens, from above, and let the skies pour down righteousness: let the earth open, and let them bring forth salvation." The vision: when God and creation are reconciled, the whole cosmos flourishes.'),
('Psalms', 85, 'adults', 3, 'How does the psalm''s movement from past deliverance (vv.1-3) through present plea (vv.4-7) to future vision (vv.8-13) structure Israel''s prayer theology?', 'The threefold structure models prayer as historical recollection (You HAVE forgiven) → present petition (WILL you revive?) → prophetic vision (You WILL speak peace); past grace grounds present petition, and present petition opens future vision; the three tenses of salvation (past, present, future) are held together in a single prayer', 'The three sections are disconnected', 'Only the petition section matters', 'The structure is accidental', 'a', 'The structure: vv.1-3 (past: "thou hast been favourable") → vv.4-7 (present: "wilt thou not revive us?") → vv.8-13 (future: "he will speak peace"). This models mature prayer: remember → ask → envision. Past faithfulness creates expectation; expectation produces vision; vision sustains hope.'),
('Psalms', 85, 'adults', 4, 'What does the warning "let them not turn again to folly" (Psalm 85:8) reveal about the fragility of revival?', 'It acknowledges that revival is not irreversible — the people who receive God''s peace can return to folly; this realistic spiritual anthropology prevents triumphalism and maintains the tension between divine grace and human responsibility even in the context of restoration', 'It is a minor aside with no significance', 'Revival is always permanent once achieved', 'Folly refers to intellectual mistakes, not spiritual failure', 'a', 'Psalm 85:8 — "let them not turn again to folly (kiselah)." Kiselah = foolishness, the opposite of wisdom. Even after revival, relapse is possible. This realistic note prevents cheap grace: God''s peace is gift, but maintaining it requires ongoing faithfulness. Heb 6:4-6 explores this same concern in NT terms.'),
('Psalms', 85, 'adults', 5, 'How does "glory may dwell in our land" (Psalm 85:9) connect to the tabernacle/temple theology of divine kabod?', 'Kabod (glory) dwelling in the land recalls the glory-cloud filling the tabernacle (Ex 40:34-35) and Solomon''s temple (1 Kings 8:10-11); the psalmist prays for the return of God''s visible presence to the land, anticipating the ultimate dwelling: John 1:14 — "the Word was made flesh, and dwelt (tabernacled) among us...and we beheld his glory"', 'Glory refers to national prestige, not divine presence', 'The glory-cloud was only for Moses', 'Glory dwelling in the land means material prosperity', 'a', 'Psalm 85:9 — "glory (kabod) may dwell in our land." Ex 40:34 — "the glory of the LORD filled the tabernacle." The progression: tabernacle → temple → land → incarnation (John 1:14) → new creation (Rev 21:3 — "the tabernacle of God is with men"). The psalm prays for a stage in glory''s progressive dwelling.'),
('Psalms', 85, 'adults', 6, 'What is the eschatological dimension of Psalm 85''s vision in verses 10-13?', 'The convergence of mercy/truth/righteousness/peace, truth springing from earth, and righteousness from heaven describes a new creation that transcends any historical restoration — it envisions the messianic age where cosmic harmony replaces the broken world; this is eschatological hope, not merely political restoration', 'The vision is limited to a good harvest season', 'It describes post-exilic restoration only', 'There is no eschatological dimension', 'a', 'Psalm 85:10-13 — The vision exceeds any historical fulfillment: mercy and truth meeting, earth and heaven cooperating, righteousness preceding God''s steps. This points beyond restoration from exile to the messianic kingdom. Isa 11:6-9 shares the vision: cosmic reconciliation that only God''s direct reign can produce.'),
('Psalms', 85, 'adults', 7, 'How does Psalm 85''s request for revival (v.6) function as a model for Christian revival prayer?', 'The psalm''s revival theology includes: (1) remembrance of past grace (vv.1-3); (2) honest assessment of present distance from God (vv.4-5); (3) petition for renewed life (v.6); (4) expectation that revival produces rejoicing (v.6b); (5) listening for God''s word (v.8) — this comprehensive model prevents revival prayer from becoming mere emotionalism', 'Revival is a modern concept with no biblical basis', 'The psalm does not model prayer', 'Revival prayer requires no specific elements', 'a', 'Psalm 85:6 — "Wilt thou not revive us again: that thy people may rejoice in thee?" The Hebrew chayah (revive, give life) grounds the concept. The psalm''s sequence provides structure: recall grace → confess distance → ask for life → listen for God''s voice → envision restoration. This prevents revival from being emotional frenzy detached from theological content.'),
('Psalms', 85, 'adults', 8, 'How does "righteousness shall go before him; and shall set us in the way of his steps" (Psalm 85:13) connect to Isaiah''s highway theology?', 'Righteousness as God''s forerunner preparing the way anticipates Isaiah 40:3 — "Prepare ye the way of the LORD" — and ultimately John the Baptist''s ministry of preparation; God does not arrive without preparation; righteousness clears the path for divine presence, making Psalm 85:13 a proto-Advent text', 'The verse describes a royal processional with no broader connection', 'It refers to literal road construction', 'There is no connection to Isaiah', 'a', 'Psalm 85:13 — righteousness as forerunner. Isa 40:3 — "Prepare ye the way of the LORD, make straight in the desert a highway for our God." Mal 3:1 — "my messenger...shall prepare the way before me." Luke 1:76 — John will "go before the face of the Lord to prepare his ways." Psalm 85:13''s righteousness-forerunner = the precursor tradition fulfilled in John the Baptist.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 86, 'kids', 1, 'What did David ask God to do because he was poor and needy?', 'Bow down His ear and hear him', 'Give him a palace to live in', 'Send him a powerful army', 'Make him the richest king', 'a', 'Psalm 86:1 — "Bow down thine ear, O LORD, hear me: for I am poor and needy."'),
('Psalms', 86, 'kids', 2, 'What does David say about God in Psalm 86:5?', 'God is good, ready to forgive, and plenteous in mercy to all who call upon Him', 'God is very strict and never forgives', 'God only listens to kings and priests', 'God is too busy to hear prayers', 'a', 'Psalm 86:5 — "For thou, Lord, art good, and ready to forgive; and plenteous in mercy unto all them that call upon thee."'),
('Psalms', 86, 'kids', 3, 'What does David ask God to teach him?', 'Teach me thy way, O LORD; I will walk in thy truth', 'How to ride a horse', 'How to build a temple', 'How to count the stars', 'a', 'Psalm 86:11 — "Teach me thy way, O LORD; I will walk in thy truth: unite my heart to fear thy name."'),
('Psalms', 86, 'teens', 1, 'What unique request does David make in Psalm 86:11 about his heart?', '"Unite my heart to fear thy name" — asking God to bring his divided heart into single-minded devotion', 'Remove all sadness from my heart', 'Make my heart as hard as stone', 'Give me two hearts instead of one', 'a', 'Psalm 86:11 — "unite my heart to fear thy name." David recognises that his heart is divided and asks God to unify it in reverence.'),
('Psalms', 86, 'teens', 2, 'What does David declare about God among the other gods in Psalm 86:8?', '"Among the gods there is none like unto thee, O Lord; neither are there any works like unto thy works"', 'The other gods are equally powerful', 'The other gods help the LORD', 'The other gods rule different parts of the world', 'a', 'Psalm 86:8 — A declaration of YHWH''s incomparability — no god or works can compare.'),
('Psalms', 86, 'teens', 3, 'What does David say all nations will eventually do?', 'Come and worship before the LORD and glorify His name', 'Fight against Israel', 'Ignore the LORD completely', 'Build their own temples', 'a', 'Psalm 86:9 — "All nations whom thou hast made shall come and worship before thee, O Lord; and shall glorify thy name."'),
('Psalms', 86, 'teens', 4, 'How does David describe God''s mercy toward him in Psalm 86:13?', 'Great — God has delivered his soul from the lowest hell (sheol)', 'Small and barely noticeable', 'Equal to what everyone else receives', 'Only temporary until David sins again', 'a', 'Psalm 86:13 — "For great is thy mercy toward me: and thou hast delivered my soul from the lowest hell."'),
('Psalms', 86, 'teens', 5, 'What does David ask God to give his servant as a sign in Psalm 86:17?', 'A token for good — so that his enemies may see it and be ashamed', 'A crown of gold', 'A chariot of fire', 'A flaming sword', 'a', 'Psalm 86:17 — "Shew me a token for good; that they which hate me may see it, and be ashamed."'),
('Psalms', 86, 'adults', 1, 'What is the significance of Psalm 86 being the only Davidic psalm in Book III (Psalms 73-89)?', 'Its sole Davidic attribution amid Asaph and Korah psalms keeps the Davidic voice alive during Book III''s darkest section — even as the Davidic covenant appears to collapse (Psalm 89), David''s personal prayer of trust persists, suggesting that individual Davidic faith survives even when the institutional covenant is in crisis', 'Its placement is accidental', 'There are several other Davidic psalms in Book III', 'It was originally in Book II but was misplaced', 'a', 'Book III: Ps 73-83 (Asaph), 84-85,87-88 (Korah), 86 (David), 89 (Ethan). The lone Davidic psalm keeps David''s voice alive in the book that questions the Davidic covenant most severely (Ps 89). Individual faith and institutional covenant are distinct but related.'),
('Psalms', 86, 'adults', 2, 'How does David''s prayer "unite my heart to fear thy name" (Psalm 86:11) anticipate the new covenant promise of Jeremiah 32:39?', 'David acknowledges heart-dividedness and asks for unification — a prayer God promises to answer eschatologically: Jer 32:39 — "I will give them one heart...that they may fear me for ever"; David prays for what the new covenant will provide: a unified heart devoted to God, showing that OT saints desired the grace the NT provides', 'The two texts are unrelated', 'David''s prayer was fully answered in his lifetime', 'Jeremiah contradicts David''s theology', 'a', 'Psalm 86:11 — yached levavi (unite my heart). Jer 32:39 — "I will give them one heart (lev echad)." Ezek 11:19 — "I will give them one heart." David''s prayer becomes God''s new covenant promise: the unification of the divided heart is grace, not achievement. This is regeneration theology in seed form.'),
('Psalms', 86, 'adults', 3, 'How does Psalm 86 function as a mosaic of other scriptural phrases and what does this compositional technique reveal?', 'Nearly every verse echoes other psalms or the Torah (v.1 ≈ Ps 40:17; v.5 ≈ Ex 34:6; v.8 ≈ Ex 15:11; v.9 ≈ Isa 2:2) — David prays in the language of Scripture, demonstrating that biblical prayer is not original composition but faithful re-appropriation of God''s own words back to God', 'The echoes are coincidental', 'David lacked originality', 'The psalm is a scribal error combining fragments', 'a', 'Psalm 86 is a tissue of allusions: v.5 echoes Ex 34:6 (compassionate God), v.8 echoes Ex 15:11 (incomparability), v.9 echoes Isa 2:2 (all nations coming), v.15 directly quotes Ex 34:6. This mosaic technique reveals that the best prayer is Scripture prayed back to God — God''s words become our words.'),
('Psalms', 86, 'adults', 4, 'What does Psalm 86:9 — "All nations whom thou hast made shall come and worship before thee" — contribute to the Psalter''s universalism?', 'It grounds universal worship in creation theology — all nations worship because God MADE them all; the basis for universal worship is not Israel''s superiority but God''s universal creatorship; this creation-based universalism appears within a personal Davidic prayer, showing that Israel''s particular God has universal claims', 'Universal worship is limited to allied nations', 'The verse predicts forced conversion', 'It contradicts Israel''s election', 'a', 'Psalm 86:9 — "All nations whom thou hast MADE." The creation basis: God made all nations, therefore all nations owe worship. This is not imperialistic projection but creation theology. Acts 17:26 — "hath made of one blood all nations." Rev 15:4 — "all nations shall come and worship before thee." Universal worship is the destiny of universal creation.'),
('Psalms', 86, 'adults', 5, 'How does the direct quotation of Exodus 34:6 in Psalm 86:15 function within the psalm?', 'By quoting God''s self-revelation at Sinai ("The LORD, The LORD God, merciful and gracious, longsuffering, and abundant in goodness and truth"), David grounds his personal petition in God''s definitive self-disclosure — he does not argue from his own worthiness but from God''s revealed character; Sinai theology becomes prayer language', 'The quotation is coincidental', 'Psalm 86:15 is the original and Exodus copied it', 'The similarity is only superficial', 'a', 'Psalm 86:15 — "But thou, O Lord, art a God full of compassion, and gracious, longsuffering, and plenteous in mercy and truth." = Ex 34:6. This is the most quoted verse in the OT by the OT. David appeals to God''s own self-description: You SAID this is who you are — act accordingly. Prayer grounded in revelation.'),
('Psalms', 86, 'adults', 6, 'What does David''s self-designation as "thy servant" (used six times in Psalm 86) reveal about his understanding of kingship?', 'The sixfold "thy servant" (abdekha, vv.2,4,16) portrays David not as sovereign king but as God''s servant-vassal; royal identity is defined by service, not by rule; the king is the LORD''s slave before he is Israel''s sovereign, inverting human power structures and anticipating the Servant of YHWH in Isaiah 42-53', 'David uses the term merely as a politeness formula', 'Servant refers to his role as military commander', 'The repetition is accidental', 'a', 'Psalm 86 — abdekha (thy servant) in vv.2,4,16 (twice),17. David the king calls himself God''s servant/slave. This inversion (king = slave) is the biblical pattern: the greatest serve. Phil 2:7 — Christ "took upon him the form of a servant." David''s servant-kingship prefigures Christ''s servant-lordship.'),
('Psalms', 86, 'adults', 7, 'How does "thou hast delivered my soul from the lowest hell (sheol tachtiyah)" (Psalm 86:13) contribute to OT afterlife theology?', 'Sheol tachtiyah (lowest sheol/deepest underworld) suggests degrees within the afterlife realm — David claims deliverance from the deepest level; whether metaphorical (deepest danger) or literal (afterlife rescue), the language implies that God''s mercy reaches into death''s deepest domain, anticipating Christ''s descent (Eph 4:9, 1 Pet 3:19)', 'Sheol simply means grave with no afterlife implications', 'The phrase is hyperbolic for illness', 'Lowest hell is a geographic location on earth', 'a', 'Psalm 86:13 — sheol tachtiyah (lowest sheol). The superlative suggests depth beyond ordinary sheol. Eph 4:9 — Christ "descended first into the lower parts of the earth." 1 Pet 3:19 — Christ "preached unto the spirits in prison." God''s saving reach extends to the deepest conceivable domain. No depth is beyond divine mercy.'),
('Psalms', 86, 'adults', 8, 'What does "the son of thine handmaid" (Psalm 86:16) reveal about David''s theology of inherited faith?', 'David identifies himself not just as God''s servant but as the child of a believing mother — his faith is inherited as well as personal; the phrase claims generational covenant standing: I belong to You because my mother belonged to You; this theology of transmitted faith anticipates Paul''s commendation of Timothy''s grandmother''s faith (2 Tim 1:5)', 'The phrase is simply biographical information', 'Handmaid refers to a servant in the palace', 'David is emphasising his low social status', 'a', 'Psalm 86:16 — "the son of thine handmaid" (ben-amatekha). Psalm 116:16 uses the same phrase. The claim: I am covenant-born, raised by a woman who served You. 2 Tim 1:5 — "the unfeigned faith that is in thee, which dwelt first in thy grandmother Lois, and thy mother Eunice." Faith transmitted generationally is a biblical category.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 87, 'kids', 1, 'What city does God love more than all the other places in Israel?', 'Zion — the gates of Zion', 'Bethlehem', 'Nazareth', 'Jericho', 'a', 'Psalm 87:2 — "The LORD loveth the gates of Zion more than all the dwellings of Jacob."'),
('Psalms', 87, 'kids', 2, 'What glorious things are spoken about the city of God?', 'Glorious things are spoken of thee, O city of God', 'It has the tallest buildings', 'It has the best food', 'It has the most soldiers', 'a', 'Psalm 87:3 — "Glorious things are spoken of thee, O city of God."'),
('Psalms', 87, 'kids', 3, 'What do the singers and players say about Zion?', 'All my springs (sources of joy) are in thee', 'It has the best music school', 'It has the prettiest flowers', 'It has the most sunshine', 'a', 'Psalm 87:7 — "As well the singers as the players on instruments shall be there: all my springs are in thee."'),
('Psalms', 87, 'teens', 1, 'Which foreign nations does Psalm 87 say will be counted as born in Zion?', 'Rahab (Egypt), Babylon, Philistia, Tyre, and Ethiopia — they will all be called Zion-born', 'Only friendly neighbouring nations', 'Only nations that were never enemies', 'Only nations that speak Hebrew', 'a', 'Psalm 87:4 — "I will make mention of Rahab and Babylon to them that know me: behold Philistia, and Tyre, with Ethiopia; this man was born there."'),
('Psalms', 87, 'teens', 2, 'What remarkable claim does Psalm 87 make about foreigners'' relationship to Zion?', 'Each person from these nations will be registered as having been born in Zion — God counts them as citizens', 'They will be allowed to visit once a year', 'They can trade with Zion but not live there', 'They must pay tribute to be associated with Zion', 'a', 'Psalm 87:5-6 — "And of Zion it shall be said, This and that man was born in her...The LORD shall count, when he writeth up the people, that this man was born there."'),
('Psalms', 87, 'teens', 3, 'What does the Highest Himself do for Zion?', 'He establishes her — the Highest Himself shall establish her', 'He decorates her with gold', 'He surrounds her with a wall of fire', 'He makes her invisible to enemies', 'a', 'Psalm 87:5 — "the Highest himself shall establish her."'),
('Psalms', 87, 'teens', 4, 'Why is Psalm 87 remarkable in its inclusion of foreign nations?', 'It envisions Israel''s worst historical enemies (Egypt, Babylon, Philistia) being counted as native-born citizens of Zion — a radical vision of universal belonging in God''s city', 'It merely lists trade partners', 'It describes military alliances', 'It records the nations Israel conquered', 'a', 'Psalm 87:4-6 lists Rahab (Egypt — Israel''s enslaver), Babylon (Israel''s destroyer), Philistia (perpetual enemy), Tyre, Ethiopia — all counted as Zion-born. This is one of the OT''s most radical universalist texts.'),
('Psalms', 87, 'teens', 5, 'What does "all my springs are in thee" (Psalm 87:7) mean?', 'Zion is the source of all joy and spiritual refreshment — all the singer''s life-giving fountains originate in God''s city', 'Zion has the best natural springs for drinking water', 'It refers to the rainy season in Jerusalem', 'The springs are underground caves', 'a', 'Psalm 87:7 — "All my springs (mayanotai) are in thee." Springs = sources of life-giving water. The singer''s deepest joy and vitality flow from Zion/God''s presence.'),
('Psalms', 87, 'adults', 1, 'How does Psalm 87''s vision of enemies being "born in Zion" represent a radical theological breakthrough?', 'By registering Egypt (enslaver), Babylon (destroyer), and Philistia (perpetual foe) as native-born citizens of Zion, the psalm envisions enemies becoming brothers — not through conquest or conversion but through divine birth-registration; God Himself counts them as Zion-born, making inclusion a sovereign divine act rather than a human achievement', 'The psalm merely describes immigrants gaining citizenship', 'It records conquered peoples being forced into Zion', 'The foreign names are metaphorical for Israelite tribes', 'a', 'Psalm 87:4-6 — God''s register includes Israel''s worst enemies AS NATIVE-BORN. This is not assimilation or conquest but divine adoption. Eph 2:19 — "ye are no more strangers and foreigners, but fellowcitizens with the saints." Gal 3:28 — "neither Jew nor Greek...for ye are all one in Christ." Psalm 87 is the OT seed of NT universalism.'),
('Psalms', 87, 'adults', 2, 'What is the Christological significance of the concept of being "born in Zion" (Psalm 87:5-6)?', 'Being "born" in Zion — divine birth-registration rather than natural birth — anticipates the new birth theology of John 3; Jesus tells Nicodemus he must be "born again/from above" to enter the kingdom; Psalm 87 already envisions a birth that transcends natural nationality, registered by God''s own hand', 'Being born in Zion is literal physical birth', 'It has no NT connection', 'The birth language is about genealogy records', 'a', 'Psalm 87:5-6 — "This and that man was born in her...The LORD shall count, when he writeth up the people, that this man was born there." John 3:3 — "Except a man be born again, he cannot see the kingdom of God." Both envision a supernatural birth that redefines identity: not natural birthplace but divine registration determines belonging.'),
('Psalms', 87, 'adults', 3, 'How does the use of "Rahab" for Egypt (Psalm 87:4) connect to the chaos-sea mythology used elsewhere in the Psalter?', 'Rahab (sea monster/chaos) is a poetic name for Egypt, connecting Israel''s historical enemy to the cosmic chaos God defeated at creation/exodus; by listing Rahab-Egypt among those born in Zion, the psalm envisions even cosmic chaos being redeemed and incorporated into God''s city — enemies transformed into citizens', 'Rahab refers to the prostitute from Jericho', 'It is a random geographic name', 'Rahab and Egypt are unrelated', 'a', 'Rahab: Ps 89:10 — "Thou hast broken Rahab in pieces." Isa 51:9 — "Art thou not it that hath cut Rahab?" Rahab = Egypt-as-chaos-monster. Psalm 87 envisions even chaos-Egypt reborn as Zion''s citizen. This is cosmic reconciliation: the enemy is not destroyed but transformed.'),
('Psalms', 87, 'adults', 4, 'What does the divine birth-register (Psalm 87:6) anticipate in Revelation?', 'God personally writing people''s names as Zion-born anticipates the Lamb''s Book of Life (Rev 21:27) — in both texts, divine registration determines belonging; the census is conducted not by human bureaucrats but by God Himself, making citizenship a matter of sovereign grace', 'The register is a normal census document', 'Revelation does not use registry imagery', 'The connection is too tenuous', 'a', 'Psalm 87:6 — "The LORD shall count, when he writeth up the people." Rev 21:27 — "they which are written in the Lamb''s book of life." Phil 4:3 — "whose names are in the book of life." The divine register: belonging to God''s city is determined by God''s sovereign writing, not human qualification.'),
('Psalms', 87, 'adults', 5, 'How does Psalm 87''s brevity (7 verses) and enigmatic style contribute to its theological impact?', 'The psalm''s compression forces maximum theological weight onto minimal words — each verse is a theological bomb: God loves Zion (v.2), glorious things spoken (v.3), enemies counted as citizens (v.4-6), all springs in Zion (v.7); the enigmatic style creates an open text that invites ongoing meditation rather than closing interpretation', 'The brevity suggests it is a fragment of a longer psalm', 'Short psalms are less important than long ones', 'The style is unclear due to poor transmission', 'a', 'At seven verses, Psalm 87 is among the shortest psalms yet contains one of the OT''s most revolutionary visions. Its compression creates poetic density: every word matters. The enigmatic Hebrew of v.4 ("I will make mention...this one was born there") has generated centuries of interpretation precisely because of its compressed suggestiveness.'),
('Psalms', 87, 'adults', 6, 'What does "all my springs are in thee" (Psalm 87:7) contribute to the Psalter''s theology of Zion?', 'It declares Zion as the source of all life — springs (mayanot) are the origin of rivers and fertility; by locating all springs in Zion, the psalm identifies God''s city as the source from which all blessing, joy, and life flow outward; this connects to Ezekiel 47''s river flowing from the temple and Revelation 22''s river of life', 'Springs refer to literal water sources in Jerusalem', 'The verse describes musical performances', 'All springs means all seasons', 'a', 'Psalm 87:7 — "all my springs (mayanotai) are in thee." Ezek 47:1 — water flowing from the temple. Joel 3:18 — "a fountain shall come forth of the house of the LORD." Rev 22:1 — "a pure river of water of life...proceeding out of the throne." Zion-as-source-of-all-springs makes the city of God the wellspring of cosmic life.'),
('Psalms', 87, 'adults', 7, 'How does Psalm 87 relate to Paul''s concept of the "Jerusalem which is above" (Galatians 4:26)?', 'Psalm 87''s Zion transcends geography — when enemies from every direction are counted as born there, Zion becomes a theological reality rather than a mere city; Paul''s "Jerusalem above" develops this: the true Zion is not the physical city but the spiritual community where all who are born of God belong, regardless of ethnicity', 'Paul never references Jerusalem theology', 'The earthly and heavenly Jerusalem are identical', 'Psalm 87 is purely about physical Jerusalem', 'a', 'Psalm 87 begins the trajectory: Zion includes Egyptians, Babylonians, Philistines (beyond geographic/ethnic limitation). Gal 4:26 — "Jerusalem which is above is free, which is the mother of us all." Heb 12:22 — "ye are come unto mount Sion, and unto the city of the living God, the heavenly Jerusalem." The psalm''s inclusive Zion is the OT seed of the heavenly city concept.'),
('Psalms', 87, 'adults', 8, 'What is the significance of Psalm 87 appearing between the lament-darkness of Psalm 88 and the covenant crisis of Psalm 89 in Book III?', 'Psalm 87''s radiant universalism — enemies becoming citizens, all springs in Zion — is sandwiched between the Psalter''s darkest psalm (88, ending in darkness) and its greatest covenant crisis (89); this placement ensures that the vision of universal belonging is not forgotten even when faith is darkest; hope persists within despair', 'The placement is accidental', 'Psalm 87 is unrelated to its neighbours', 'It should have been placed in Book I', 'a', 'The sequence: 87 (universal hope) → 88 (utter darkness) → 89 (covenant collapse). The brightest vision precedes the darkest psalm. This is deliberate: before plunging into Psalm 88''s unprecedented despair, the editor places a vision of cosmic reconciliation — ensuring the reader carries hope into darkness.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 88, 'kids', 1, 'How did the writer of Psalm 88 feel?', 'Very sad — his soul was full of troubles and his life drew near to the grave', 'Very happy and thankful', 'Excited about a holiday', 'Calm and peaceful', 'a', 'Psalm 88:3 — "For my soul is full of troubles: and my life draweth nigh unto the grave."'),
('Psalms', 88, 'kids', 2, 'What did the writer cry out to God every day?', 'He stretched out his hands to God and cried day and night', 'He sang happy songs every morning', 'He played music on his harp', 'He danced before the altar', 'a', 'Psalm 88:9 — "LORD, I have called daily upon thee, I have stretched out my hands unto thee."'),
('Psalms', 88, 'kids', 3, 'What is the very last word of Psalm 88?', 'Darkness — it is the only psalm that ends without any hope or praise', 'Hallelujah', 'Amen', 'Praise', 'a', 'Psalm 88:18 — "...mine acquaintance into darkness." The psalm ends with the word "darkness" (machshakh) — uniquely among the psalms.'),
('Psalms', 88, 'teens', 1, 'What makes Psalm 88 unique among all 150 psalms?', 'It is the only psalm that ends without any word of hope, praise, or resolution — it begins and ends in darkness', 'It is the longest psalm', 'It is the only psalm by a woman', 'It is the only psalm about animals', 'a', 'Psalm 88 is the darkest psalm — no resolution, no praise, no hope at the end. Its final word is "darkness." Every other lament psalm turns to hope; Psalm 88 does not.'),
('Psalms', 88, 'teens', 2, 'What does the psalmist say about the dead in Psalm 88:10-12?', 'The dead cannot praise God — wonders are not shown to the dead, and God''s faithfulness is not declared in destruction', 'The dead are happy in God''s presence', 'The dead can still pray to God', 'The dead are sleeping peacefully', 'a', 'Psalm 88:10-12 — "Wilt thou shew wonders to the dead?...Shall thy lovingkindness be declared in the grave? or thy faithfulness in destruction?"'),
('Psalms', 88, 'teens', 3, 'What does the psalmist accuse God of doing in Psalm 88:14?', 'Casting off his soul and hiding His face from him', 'Blessing him too much', 'Sending him to a foreign land', 'Giving him too many responsibilities', 'a', 'Psalm 88:14 — "LORD, why castest thou off my soul? why hidest thou thy face from me?"'),
('Psalms', 88, 'teens', 4, 'Who does the psalmist say God has removed from him?', 'Lover, friend, and acquaintance — all put into darkness', 'His wealth and possessions', 'His ability to sing', 'His memories of better times', 'a', 'Psalm 88:18 — "Lover and friend hast thou put far from me, and mine acquaintance into darkness."'),
('Psalms', 88, 'teens', 5, 'What has the psalmist suffered from his youth according to Psalm 88:15?', 'God''s terrors — he is afflicted and ready to die, suffering God''s terrors and being distracted', 'Poverty and hunger', 'Attacks from wild animals', 'Exile in a foreign country', 'a', 'Psalm 88:15 — "I am afflicted and ready to die from my youth up: while I suffer thy terrors I am distracted."'),
('Psalms', 88, 'adults', 1, 'Why is Psalm 88''s unresolved darkness theologically necessary in the Psalter?', 'It validates the experience of unredeemed suffering — some darkness does not lift in this life; by including a psalm with no resolution, the Psalter refuses to falsify reality; not every lament ends in praise, and the canon honours this truth rather than forcing premature resolution', 'It was included by mistake and should end with praise', 'It proves the psalmist lacked faith', 'The darkness is metaphorical and not genuinely distressing', 'a', 'Psalm 88 is the Psalter''s most honest moment: darkness without dawn. Its canonical inclusion validates the experience of those whose suffering finds no earthly resolution. It prevents the Psalter from becoming a collection of guaranteed happy endings. Some crosses have no visible resurrection — yet the prayer continues.'),
('Psalms', 88, 'adults', 2, 'How does the psalmist''s description of God''s wrath (Psalm 88:7,16 — "thy wrath lieth hard upon me...thy fierce wrath goeth over me") connect to Christ''s passion?', 'The psalmist experiences God''s wrath not as punishment for personal sin but as seemingly gratuitous divine affliction — this innocent-sufferer-under-divine-wrath experience prefigures Christ on the cross, where God''s wrath against sin was borne by the sinless one; Psalm 88 is the closest OT parallel to the cry of dereliction (Mark 15:34)', 'The psalm has no Christological dimension', 'The wrath is punishment for the psalmist''s sins', 'Christ never experienced divine wrath', 'a', 'Psalm 88:7 — "Thy wrath lieth hard upon me." Psalm 88:14 — "why hidest thou thy face from me?" Mark 15:34 — "My God, my God, why hast thou forsaken me?" Both experience divine absence/wrath without explanatory cause. Christ fulfills Psalm 88: the innocent sufferer under divine wrath par excellence. 2 Cor 5:21 — "he hath made him to be sin for us, who knew no sin."'),
('Psalms', 88, 'adults', 3, 'What does the series of rhetorical questions about the dead (Psalm 88:10-12) reveal about OT death theology?', 'The questions reflect the OT''s honest uncertainty about post-mortem existence — the dead are in silence, darkness, forgetfulness; praise, lovingkindness, and wonders are absent in sheol; this is not atheistic denial but anguished honesty about death''s apparent finality, which makes resurrection hope (when it emerges in texts like Dan 12:2) all the more revolutionary', 'The questions prove there is no afterlife in OT theology', 'They are rhetorical with no real theological content', 'The dead praise God in sheol according to other psalms', 'a', 'Psalm 88:10-12 — five rhetorical questions expecting "no": no wonders, no praise, no lovingkindness, no faithfulness, no knowledge in the grave. This represents the OT''s bleakest afterlife view. Its canonical inclusion creates the theological problem that only resurrection can solve (1 Cor 15:55 — "O death, where is thy sting?").'),
('Psalms', 88, 'adults', 4, 'What is the significance of the psalm''s opening address — "O LORD God of my salvation" (Psalm 88:1) — in a psalm that ends in total darkness?', 'The opening address creates maximum theological tension: the psalmist calls God "my salvation" yet experiences nothing but darkness; faith persists in addressing the God of salvation while receiving only wrath and abandonment; the address itself IS the faith — prayer to the saving God from within unsaved circumstances', 'The opening is formulaic and contradicts the psalm''s content', 'It proves the psalmist is delusional about God''s character', 'The address was added later to soften the psalm', 'a', 'Psalm 88:1 — "O LORD God of my salvation (yeshuati)." The psalm''s faith is in the address: calling God "my salvation" from the pit. The prayer itself — directed to the right God with the right character — IS the act of faith. Even when experience contradicts theology, the address persists. This is the deepest form of faith.'),
('Psalms', 88, 'adults', 5, 'How does Psalm 88 function within Book III''s theological arc?', 'Book III moves from individual theodicy (Ps 73) through national laments to Psalm 88''s personal abyss — the darkest point before Psalm 89''s covenant crisis; Psalm 88 represents the nadir: if Psalm 73 resolved individual theodicy, Psalm 88 presents the case where resolution does NOT come; together they bracket the full range of faith experience', 'Psalm 88 has no connection to Book III''s themes', 'It was originally in Book V', 'Book III has no arc', 'a', 'Book III arc: 73 (theodicy resolved) → 74-83 (national crisis) → 84-87 (glimpses of hope) → 88 (total darkness) → 89 (covenant collapse). Psalm 88 is the theological nadir: personal suffering without resolution, preparing for the institutional crisis of Psalm 89.'),
('Psalms', 88, 'adults', 6, 'What does the loss of all human relationships (Psalm 88:8,18 — "thou hast put away mine acquaintance...lover and friend into darkness") add to the psalm''s portrayal of suffering?', 'It describes suffering as total isolation — not only is God absent (v.14) but all human companionship is stripped away; the psalmist is alone with darkness; this compound abandonment (divine + human) is the essence of hell: complete relational deprivation; only Christ on the cross fully experiences this double abandonment', 'The relational loss is a minor inconvenience', 'The psalmist is choosing isolation', 'Friends are unimportant in biblical theology', 'a', 'Psalm 88:8 — "Thou hast put away mine acquaintance far from me." V.18 — "Lover and friend...into darkness." Divine absence (v.14) + human isolation (vv.8,18) = total relational void. Gethsemane: disciples slept (Matt 26:40). Cross: "My God, why hast thou forsaken me?" (Matt 27:46). Christ experienced both dimensions of Psalm 88''s isolation.'),
('Psalms', 88, 'adults', 7, 'What pastoral function does Psalm 88 serve for believers experiencing depression or unresolved suffering?', 'It canonises the experience of persistent darkness — by placing this psalm in Scripture, the canon validates that unresolved suffering is a legitimate faith experience, not evidence of spiritual failure; the psalmist prays without receiving answer, grieves without receiving comfort, and remains in faith without receiving relief — this IS faith, not faith''s absence', 'Psalm 88 should not be read by depressed people', 'It proves that depressed people lack faith', 'The psalm has no pastoral application', 'a', 'Psalm 88''s pastoral genius: it gives words to those who have no words. It validates the experience of praying without answer (v.1,9,13), crying without comfort (v.1), believing without seeing (v.1''s "God of my salvation"). The psalm does not prescribe a solution but provides company in the dark. Presence, not prescription, is its gift.'),
('Psalms', 88, 'adults', 8, 'How does the dual attribution "A Song or Psalm for the sons of Korah...Maschil of Heman the Ezrahite" affect interpretation?', 'The Korah attribution links Psalm 88 to the singers whose ancestor was swallowed alive by the earth (Num 16:31-32) — descendants of one who went down to sheol alive are uniquely qualified to write about the pit; Heman the Ezrahite was a temple musician (1 Chr 6:33), making this the prayer of a worship leader plunged into darkness — expertise in praise does not immunise against despair', 'The dual attribution is a scribal error', 'Heman and Korah are the same person', 'The attribution has no interpretive significance', 'a', 'Korah: Num 16:31-32 — the earth swallowed Korah alive. His descendants sing from the perspective of those whose ancestor experienced sheol. Heman: 1 Chr 6:33, 1 Kings 4:31 — wise man and temple musician. The irony: the wisest man and the temple''s lead singer writes the darkest psalm. Wisdom and worship do not prevent darkness.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 89, 'kids', 1, 'What two things does the psalmist sing about in Psalm 89?', 'The mercies of the LORD and His faithfulness', 'The stars and the moon', 'The rivers and the mountains', 'The animals and the birds', 'a', 'Psalm 89:1 — "I will sing of the mercies of the LORD for ever: with my mouth will I make known thy faithfulness to all generations."'),
('Psalms', 89, 'kids', 2, 'What did God promise to David about his throne?', 'His throne would be established forever, like the sun and moon', 'His throne would last for ten years', 'His throne would be shared with his brothers', 'His throne would move to a new city', 'a', 'Psalm 89:36-37 — "His seed shall endure for ever, and his throne as the sun before me. It shall be established for ever as the moon."'),
('Psalms', 89, 'kids', 3, 'What sad question does the psalmist ask at the end?', 'Lord, where are thy former lovingkindnesses, which thou swarest unto David?', 'When will we have a new temple?', 'Why is the sky blue?', 'How many fish are in the sea?', 'a', 'Psalm 89:49 — "Lord, where are thy former lovingkindnesses, which thou swarest unto David in thy truth?"'),
('Psalms', 89, 'teens', 1, 'What covenant promise to David does Psalm 89 extensively describe?', 'That David''s seed and throne would endure forever — God would not break His covenant or alter what He had spoken', 'That David would never lose a battle', 'That David''s temple would never be destroyed', 'That David''s sons would all be prophets', 'a', 'Psalm 89:3-4,34-36 — "I have made a covenant with my chosen, I have sworn unto David my servant, Thy seed will I establish for ever, and build up thy throne to all generations."'),
('Psalms', 89, 'teens', 2, 'What does the psalmist accuse God of doing to the Davidic covenant?', 'Casting off, abhorring, and being wroth with His anointed — making void the covenant and profaning the crown', 'Strengthening and renewing it', 'Expanding it to all nations', 'Replacing it with a better one', 'a', 'Psalm 89:38-39 — "But thou hast cast off and abhorred, thou hast been wroth with thine anointed. Thou hast made void the covenant of thy servant: thou hast profaned his crown by casting it to the ground."'),
('Psalms', 89, 'teens', 3, 'What powerful thing does God do to the sea in Psalm 89:9?', 'He rules the raging of the sea — when its waves arise, He stills them', 'He dries up the sea completely', 'He fills the sea with new creatures', 'He changes the sea''s colour', 'a', 'Psalm 89:9 — "Thou rulest the raging of the sea: when the waves thereof arise, thou stillest them."'),
('Psalms', 89, 'teens', 4, 'What does the psalmist call God in Psalm 89:26?', 'My father, my God, and the rock of my salvation', 'My teacher and counsellor', 'My general and commander', 'My friend and companion', 'a', 'Psalm 89:26 — "He shall cry unto me, Thou art my father, my God, and the rock of my salvation."'),
('Psalms', 89, 'teens', 5, 'How does Book III of the Psalter (Psalms 73-89) end?', 'With Psalm 89''s anguished question about whether God has abandoned His covenant with David — and a doxology closing the book', 'With a joyful celebration', 'With a call to build a new temple', 'With a prophecy of a new king', 'a', 'Psalm 89:49-51 ends with unanswered questions about the Davidic covenant, followed by the doxology "Blessed be the LORD for evermore" (v.52) closing Book III.'),
('Psalms', 89, 'adults', 1, 'How does Psalm 89''s structure — hymn of praise (vv.1-18), covenant recital (vv.19-37), lament (vv.38-51) — create its theological crisis?', 'The structure deliberately builds up the covenant''s certainty before shattering it with present reality: the more firmly the covenant is established (vv.1-37), the more devastating its apparent failure (vv.38-51); this structural strategy forces the reader to hold both truths — God''s promise IS eternal AND it appears broken — creating the book''s defining crisis', 'The three sections are from different psalms combined', 'The lament undermines the praise section', 'The structure has no theological function', 'a', 'Praise (vv.1-18): 18 verses establishing God''s faithfulness. Covenant (vv.19-37): 19 verses detailing specific promises. Lament (vv.38-51): 14 verses describing their apparent failure. The ratio (37 verses of promise vs 14 of crisis) itself argues: the weight of evidence favours faithfulness even when present circumstances scream failure.'),
('Psalms', 89, 'adults', 2, 'How does Psalm 89''s crisis of the Davidic covenant function as the climax and conclusion of Book III?', 'Book III (Psalms 73-89) moves from individual theodicy through national laments to the ultimate crisis: God''s covenant with David appears broken; this is worse than temple destruction (Ps 74) or national defeat (Ps 79) because the Davidic covenant was God''s unconditional promise — its failure questions God''s very trustworthiness, making Psalm 89 the Psalter''s deepest theological crisis', 'Psalm 89 is a minor conclusion with limited impact', 'Book III could end with any psalm', 'The Davidic covenant crisis is less serious than the temple destruction', 'a', 'Temple destruction (Ps 74) is devastating but the temple could be rebuilt. National defeat (Ps 79) is terrible but the nation could recover. But the Davidic covenant was explicitly UNCONDITIONAL (2 Sam 7:15-16): "my mercy shall not depart." If this fails, God''s word itself fails. Psalm 89 is therefore the ultimate theological crisis: not just historical but hermeneutical.'),
('Psalms', 89, 'adults', 3, 'What does the cosmic hymn section (Psalm 89:5-14) contribute to the covenant argument?', 'By establishing God''s sovereignty over creation, the sea, Rahab, heaven, and earth BEFORE reciting the Davidic covenant, the psalm grounds the covenant in cosmic reliability — the God whose word governs the cosmos is the God whose word governs David''s throne; if creation is stable, the covenant should be stable', 'The cosmic section is unrelated to the covenant', 'It is borrowed from another psalm', 'The cosmic language is purely decorative', 'a', 'Psalm 89:5-14 — heavens praise God, sea obeys, Rahab crushed, heaven and earth are God''s. The logic: the God who controls the cosmos controls history. If His word governs creation (reliable), His word governs David''s throne (should be equally reliable). The cosmic hymn raises the stakes: covenant failure would undermine cosmic reliability.'),
('Psalms', 89, 'adults', 4, 'How does the oath "Once have I sworn by my holiness that I will not lie unto David" (Psalm 89:35) intensify the crisis?', 'God swore by His own holiness — the most unbreakable oath possible, since God''s holiness is His essential nature; the apparent failure of this oath does not merely question God''s reliability but His very nature; if God can lie after swearing by His holiness, holiness itself is compromised', 'The oath is standard diplomatic language', 'God''s holiness is not at stake', 'The oath was conditional despite its wording', 'a', 'Psalm 89:35 — "Once have I sworn by my holiness that I will not lie unto David." Heb 6:13 — "when God made promise to Abraham, because he could swear by no greater, he sware by himself." God staked His own nature on this promise. Its apparent failure is therefore a crisis of divine identity, not merely divine policy.'),
('Psalms', 89, 'adults', 5, 'How does "thou hast profaned his crown by casting it to the ground" (Psalm 89:39) function as a theological accusation?', 'The psalmist directly accuses God of desecrating what God Himself consecrated — the crown (nezer, related to Nazirite consecration) was holy because God set it apart; by casting it down, God has violated His own consecration; this is the boldest accusation in the Psalter: God has profaned His own sacred act', 'The crown was profaned by enemies, not by God', 'The psalmist is exaggerating his complaint', 'Crown refers to a literal piece of jewelry', 'a', 'Psalm 89:39 — challal (profane/defile) + nezer (crown/consecration). God consecrated the Davidic crown (v.20, anointing) and now defiles it. The accusation: You have desecrated Your own holy work. This is not mere complaint but theological prosecution — the psalmist puts God on trial for violating His own holiness.'),
('Psalms', 89, 'adults', 6, 'What is the theological function of Psalm 89''s closing doxology (v.52 — "Blessed be the LORD for evermore. Amen, and Amen")?', 'The doxology is an editorial addition closing Book III, not the psalmist''s own resolution — it blesses God DESPITE the unresolved crisis; this creates a deliberate tension: the book ends with both unanswered complaint AND blessed acknowledgment; faith praises God even when the crisis remains open', 'The doxology resolves the crisis by affirming God''s goodness', 'It is a scribal formula with no theological meaning', 'It contradicts the lament that precedes it', 'a', 'Psalm 89:52 — The doxology closes Book III (each of the Psalter''s five books ends with a doxology). It does NOT answer the lament''s questions. The juxtaposition: v.51 (reproach of God''s anointed) + v.52 (blessed be the LORD) = faith persisting in praise without receiving answers. This IS the resolution: praise that outlasts understanding.'),
('Psalms', 89, 'adults', 7, 'How does the Davidic covenant crisis of Psalm 89 find its resolution in the New Testament?', 'The apparent failure of the Davidic covenant (no king on the throne, crown profaned) is resolved in Christ''s resurrection and enthronement — the Davidic throne was not abandoned but was being transformed from political to cosmic; Luke 1:32 — "the Lord God shall give unto him the throne of his father David"; Acts 2:30-31 — David''s descendant raised to sit on his throne', 'The NT ignores the Davidic covenant', 'The covenant was permanently cancelled', 'The resolution is purely spiritual with no Davidic connection', 'a', 'Psalm 89''s crisis: the Davidic throne appears abolished. NT resolution: Luke 1:32 — "the throne of his father David." Acts 2:30-31 — "David...foreseeing this spake of the resurrection of Christ." The covenant was not broken but was being fulfilled in a way no one anticipated: through death, resurrection, and cosmic enthronement. The crown cast to the ground (89:39) = Christ''s humiliation; the eternal throne (89:36) = Christ''s exaltation.'),
('Psalms', 89, 'adults', 8, 'What is the canonical significance of Book III ending with unanswered questions and Book IV (Psalm 90) opening with Moses?', 'Book III ends with the Davidic covenant in ruins; Book IV opens with "A Prayer of Moses" — the canonical editors reach BEHIND David to Moses, the pre-monarchical leader, suggesting that when the Davidic covenant appears to fail, Israel must return to the deeper covenant with the God who preceded David; the answer to the monarchy''s collapse is the God who was sufficient before the monarchy existed', 'The transition from David to Moses is accidental', 'Book IV ignores Book III''s crisis', 'Moses and David are theologically equivalent', 'a', 'Book III ends: Davidic covenant in crisis (Ps 89). Book IV opens: "A Prayer of Moses the man of God" (Ps 90). The canonical move: when the monarchy fails, return to the God who was Lord before the monarchy. Ps 90:1 — "Lord, thou hast been our dwelling place in all generations." God was sufficient before David and remains sufficient after David''s throne appears fallen.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 90, 'kids', 1, 'Who wrote Psalm 90?', 'Moses — the man of God', 'David', 'Solomon', 'Asaph', 'a', 'Psalm 90 heading — "A Prayer of Moses the man of God." This is the only psalm attributed to Moses.'),
('Psalms', 90, 'kids', 2, 'How long is a thousand years to God according to Psalm 90?', 'Like yesterday when it is past — like a watch in the night', 'A very long time even for God', 'Exactly one thousand years', 'Like a whole month', 'a', 'Psalm 90:4 — "For a thousand years in thy sight are but as yesterday when it is past, and as a watch in the night."'),
('Psalms', 90, 'kids', 3, 'What does Moses ask God to teach us to do?', 'Number our days so that we may apply our hearts unto wisdom', 'Count the stars at night', 'Build strong cities', 'Run faster than our enemies', 'a', 'Psalm 90:12 — "So teach us to number our days, that we may apply our hearts unto wisdom."'),
('Psalms', 90, 'teens', 1, 'What does Moses declare about God in Psalm 90:1-2?', 'God has been Israel''s dwelling place in all generations — before the mountains were brought forth, from everlasting to everlasting, He is God', 'God was created at the same time as the mountains', 'God only appeared when Moses was born', 'God chose to exist when creation began', 'a', 'Psalm 90:1-2 — "Lord, thou hast been our dwelling place in all generations. Before the mountains were brought forth...from everlasting to everlasting, thou art God."'),
('Psalms', 90, 'teens', 2, 'How does Moses describe human life in Psalm 90:5-6?', 'Like grass that grows up in the morning and is cut down and withers by evening', 'Like a mighty oak tree that never falls', 'Like a river that flows forever', 'Like a diamond that never breaks', 'a', 'Psalm 90:5-6 — "Thou carriest them away as with a flood...In the morning it flourisheth, and groweth up; in the evening it is cut down, and withereth."'),
('Psalms', 90, 'teens', 3, 'How many years does Moses say a human life typically lasts?', 'Seventy years, or eighty if by strength — yet they are soon cut off and we fly away', 'One hundred and fifty years', 'Fifty years at most', 'Three hundred years', 'a', 'Psalm 90:10 — "The days of our years are threescore years and ten; and if by reason of strength they be fourscore years, yet is their strength labour and sorrow; for it is soon cut off, and we fly away."'),
('Psalms', 90, 'teens', 4, 'What does Moses ask God to do in the morning?', 'Satisfy us early with thy mercy, that we may rejoice and be glad all our days', 'Wake us up before sunrise', 'Send manna like in the wilderness', 'Show us where to find water', 'a', 'Psalm 90:14 — "O satisfy us early with thy mercy; that we may rejoice and be glad all our days."'),
('Psalms', 90, 'teens', 5, 'What does Moses ask God to establish at the end of Psalm 90?', 'The work of our hands — establish thou it', 'A new covenant with Israel', 'A kingdom that lasts forever', 'A temple in the wilderness', 'a', 'Psalm 90:17 — "And let the beauty of the LORD our God be upon us: and establish thou the work of our hands upon us; yea, the work of our hands establish thou it."'),
('Psalms', 90, 'adults', 1, 'What is the theological significance of Psalm 90 being attributed to Moses and opening Book IV?', 'After Book III''s Davidic covenant crisis (Ps 89), Book IV reaches behind the monarchy to Moses — the pre-Davidic leader; this canonical move declares that Israel''s foundation is not the monarchy but the God who was "our dwelling place in all generations" before David ever existed; when institutional structures fail, the eternal God remains', 'The Moses attribution is unreliable and irrelevant', 'Book IV has no connection to Book III', 'Moses is mentioned merely for historical interest', 'a', 'Psalm 90:1 — "Lord, thou hast been our dwelling place in all generations." The response to Psalm 89''s crisis: the Davidic throne may appear fallen, but God Himself — who preceded David, Abraham, creation — remains the dwelling place. The canonical architecture: crisis (Book III) → return to foundations (Book IV).'),
('Psalms', 90, 'adults', 2, 'How does "a thousand years in thy sight are but as yesterday" (Psalm 90:4) function philosophically and how does Peter use it?', 'It establishes divine timelessness — God''s relationship to time is categorically different from humanity''s; this is not merely quantitative (God lives longer) but qualitative (time itself is God''s creation, perceived differently); Peter uses this verse (2 Pet 3:8) to explain the apparent delay of Christ''s return: divine timing operates on a fundamentally different scale', 'The verse is poetic exaggeration', 'Peter misapplies the verse', 'God experiences time exactly as humans do', 'a', 'Psalm 90:4 — 2 Pet 3:8 — "one day is with the Lord as a thousand years, and a thousand years as one day." Peter applies Moses'' psalm to the parousia delay: what seems delayed to us is not delayed to God. Divine timelessness reframes eschatological expectation.'),
('Psalms', 90, 'adults', 3, 'What is the theological relationship between divine wrath (Psalm 90:7-11) and human mortality?', 'Moses connects death not merely to biology but to divine wrath against sin — "we are consumed by thine anger" (v.7); mortality is theological, not merely natural; human finitude is a consequence of God''s righteous response to sin, connecting this psalm to Genesis 3''s mortality sentence and Rom 6:23 ("the wages of sin is death")', 'Death is purely natural with no theological dimension', 'Divine wrath is metaphorical', 'The psalm disconnects death from sin', 'a', 'Psalm 90:7-9 — "We are consumed by thine anger...all our days are passed away in thy wrath." Gen 2:17 — "thou shalt surely die." Gen 3:19 — "unto dust shalt thou return." Rom 6:23 — "the wages of sin is death." Moses theologises mortality: death is not mere biology but divine judgment. This makes resurrection (overcoming death) necessarily an act of divine grace.'),
('Psalms', 90, 'adults', 4, 'How does "teach us to number our days" (Psalm 90:12) function as a wisdom instruction within a lament context?', 'The request transforms lament (mortality is terrible) into wisdom (mortality can teach): awareness of finitude produces not despair but wisdom (chokmah); the limited time available makes every day precious and demands purposeful living; this is the psalm''s practical turn — acknowledging brevity leads to applied wisdom, not nihilism', 'Numbering days is a mathematical exercise', 'The request is for literal calculation of remaining lifespan', 'Wisdom is unrelated to mortality awareness', 'a', 'Psalm 90:12 — "So teach us to number our days, that we may apply our hearts unto wisdom (chokmah)." The logic: because life is brief (vv.3-10) → we need wisdom to use it well (v.12) → therefore satisfy us with mercy (v.14) → so we can rejoice (v.14b). Mortality awareness → wisdom → joy. This is the psalm''s existential prescription.'),
('Psalms', 90, 'adults', 5, 'What does the request "satisfy us early with thy mercy" (Psalm 90:14) reveal about the psalm''s resolution?', 'After extensive reflection on wrath and mortality (vv.3-11), the resolution is not escape from finitude but mercy WITHIN finitude — the psalmist does not ask for immortality but for God''s mercy to fill the limited days available; this is grace applied to mortality: not removing death but transforming the quality of mortal life', 'The request is for physical comfort', 'Early means early in the morning only', 'The resolution is escape from mortality', 'a', 'Psalm 90:14 — "satisfy us early (baboqer, in the morning) with thy mercy (chesed)." The resolution: not immortality but chesed-saturated mortality. Not more years but more mercy within the years given. This is mature faith: accepting human limits while requesting divine quality within those limits.'),
('Psalms', 90, 'adults', 6, 'How does the contrast between divine eternity (vv.1-2) and human brevity (vv.3-10) establish the psalm''s anthropology?', 'The contrast creates a chasm between the everlasting God and grass-like humanity — this is not meant to humiliate but to properly locate human beings: we are NOT God; our significance comes not from our duration but from our relationship to the Eternal One; human worth is derived, not inherent, relational, not autonomous', 'The contrast merely states obvious facts', 'It proves humanity is worthless', 'The contrast is pessimistic', 'a', 'Psalm 90: God = everlasting (vv.1-2). Humanity = grass (vv.5-6), seventy years (v.10). The anthropological point: human significance is derivative, not intrinsic. We matter because the Eternal God made us and dwells with us (v.1), not because we endure. This relational anthropology prevents both pride (we are not God) and despair (God is with us).'),
('Psalms', 90, 'adults', 7, 'What is the significance of the closing petition "establish thou the work of our hands" (Psalm 90:17) in light of the psalm''s mortality theme?', 'After establishing that human life is brief and grass-like, the petition asks God to give permanence to human effort — without divine establishment, all work perishes with the worker; only God can make mortal work immortal; this redeems human labour from absurdity by grounding its significance in divine purpose', 'The request is for professional success', 'It contradicts the earlier mortality theme', 'The work of hands refers only to temple construction', 'a', 'Psalm 90:17 — "establish (konneh) thou the work of our hands." The paradox: human life is grass (v.5-6), yet human work can be established (konneh = made firm/permanent). How? Only if God establishes it. 1 Cor 15:58 — "your labour is not in vain in the Lord." Divine establishment rescues human work from mortality''s futility.'),
('Psalms', 90, 'adults', 8, 'How does Psalm 90 bridge the Old and New Testament understandings of mortality and hope?', 'Moses acknowledges mortality as divine judgment on sin (v.7-9), human life''s brevity (v.10), and requests mercy within finitude (v.14) — the OT honest assessment of death without resurrection hope; the NT completes this: Christ''s resurrection answers the psalm''s implicit question (can mortal work endure?); 1 Cor 15:54 — "Death is swallowed up in victory" fulfils what Psalm 90 could only yearn for', 'The psalm has no NT connections', 'The NT supersedes the psalm entirely', 'Moses already had full resurrection theology', 'a', 'Psalm 90 honestly faces mortality without resurrection hope. The NT answers: 2 Tim 1:10 — Christ "hath abolished death." 1 Cor 15:54 — "Death is swallowed up in victory." What Moses prayed for — mercy within mortal limits — Christ provides: victory over mortality itself. Psalm 90 is the question; the resurrection is the answer.');
